    [Fact]
    public void CliVerify_FindsCounterexampleForUnconstrainedAmountPostcondition()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, new byte[]
            {
                (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x01,
                (byte)NeoVm.OpCode.RET,
            });
            WriteManifest(manifestPath, methodOffset: 0);
            WriteSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "a SAT counterexample means the formal gate must fail");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["violated"]!.GetValue<int>().Should().Be(1);
            root["summary"]!["proved"]!.GetValue<int>().Should().Be(0);

            var result = root["results"]!.AsArray().Single()!;
            result["id"]!.GetValue<string>().Should().Be("amount_non_negative");
            result["method"]!.GetValue<string>().Should().Be("transfer");
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["assumptions"]!.AsArray().Should().BeEmpty();
            result["counterexample"].Should().NotBeNull();
            var amount = BigInteger.Parse(result["counterexample"]!["arg_amount"]!.GetValue<string>());
            amount.Should().BeLessThan(BigInteger.Zero);
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_RejectsReportOutputPathThatOverwritesInput()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "contract.bin");
            string manifestPath = Path.Combine(dir, "contract.manifest.json");
            string specPath = Path.Combine(dir, "contract.neo-sym.spec.json");

            File.WriteAllBytes(scriptPath, new[] { (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET });
            WriteMethodManifest(
                manifestPath,
                "NoOverwriteContract",
                "check",
                methodOffset: 0,
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "returns_true",
                      "method": "check",
                      "ensures": [
                        { "return": true, "op": "==", "value": true }
                      ]
                    }
                  ]
                }
                """);
            string originalManifest = File.ReadAllText(manifestPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", manifestPath);

            exit.Should().Be(2, "verify report output must never overwrite an input artifact");
            File.ReadAllText(manifestPath).Should().Be(originalManifest);
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

