    [Fact]
    public void CliVerify_RejectsReportOutputPathThatOverwritesDependencyProofArtifact()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "contract.bin");
            string manifestPath = Path.Combine(dir, "contract.manifest.json");
            string specPath = Path.Combine(dir, "contract.neo-sym.spec.json");
            string dependencyNefPath = Path.Combine(dir, "dependency.nef");
            string dependencyManifestPath = Path.Combine(dir, "dependency.manifest.json");

            File.WriteAllBytes(scriptPath, new[] { (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET });
            WriteMethodManifest(
                manifestPath,
                "NoArtifactOverwriteContract",
                "check",
                methodOffset: 0,
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "returns_true",
                      "method": "check",
                      "ensures": [
                        { "return": true, "op": "==", "value": true }
                      ]
                    }
                  ]
                }
                """);
            byte[] originalDependencyNef = BuildNef("neo-sym-test", "", Array.Empty<MethodToken>(), ReturnBool(true));
            File.WriteAllBytes(dependencyNefPath, originalDependencyNef);
            WriteMethodManifest(
                dependencyManifestPath,
                "Dependency",
                "safe",
                methodOffset: 0,
                returnType: "Boolean");

            int exit = InvokeCli(
                "verify", scriptPath,
