                "--dependency-proof-artifact", $"{HashDescriptor(Enumerable.Repeat((byte)0x11, 20).ToArray())}={dependencyNefPath},{dependencyManifestPath}",
                "--format", "json",
                "--out", dependencyNefPath);

            exit.Should().Be(2, "verification report output must never overwrite dependency proof artifact inputs");
            File.ReadAllBytes(dependencyNefPath).Should().Equal(originalDependencyNef);
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
