    [Fact]
    public void CliVerify_ForbidFaultsRejectsRequiresInfeasibleUnderAbiConstraints()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "no-fault-vacuous-requires.bin");
            string manifestPath = Path.Combine(dir, "no-fault-vacuous-requires.manifest.json");
            string specPath = Path.Combine(dir, "no-fault-vacuous-requires.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, new byte[]
            {
                (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x01,
                (byte)NeoVm.OpCode.RET,
            });
            WriteMethodManifest(
                manifestPath,
                "InputContract",
                "check",
                methodOffset: 0,
                parametersJson: """[{ "name": "key", "type": "ByteString" }]""");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "byte_string_negative_size_no_fault",
                      "description": "Fault-freedom proofs must not pass when requires contradict ABI path constraints.",
                      "method": "check",
                      "requires": [
                        { "arg": "key", "metric": "size", "op": "<", "value": 0 }
                      ],
                      "forbid_faults": true,
                      "ensures": []
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "fault-freedom over an empty ABI input domain is a vacuous proof");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("requires");
            result["reason"]!.GetValue<string>().Should().Contain("infeasible");
            result["reason"]!.GetValue<string>().Should().Contain("ABI");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_CustomSpecMarksRepeatedStorageReadOffsetIncomplete()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "repeated-storage-read-offset.bin");
            string manifestPath = Path.Combine(dir, "repeated-storage-read-offset.manifest.json");
            string specPath = Path.Combine(dir, "repeated-storage-read-offset.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] script = Concat(
                Pushdata1("a"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.CALL, (byte)0x08 },
                Pushdata1("b"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.CALL, (byte)0x03 },
                new[] { (byte)NeoVm.OpCode.RET },
                Syscall("System.Storage.Local.Get"),
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, script);
            ScriptDecoder.Decode(script).Instructions.Single(i => i.Offset == 3).Target.Should().Be(11);
            ScriptDecoder.Decode(script).Instructions.Single(i => i.Offset == 8).Target.Should().Be(11);
            WriteMethodManifest(
                manifestPath,
                "RepeatedStorageReadContract",
                "readTwice",
                methodOffset: 0,
                parametersJson: "[]",
                returnType: "Void");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "repeated_storage_read_offset",
                      "description": "Offset-only storage_read specs cannot select between repeated reads of one opcode.",
                      "method": "readTwice",
                      "ensures": [
                        { "storage_read": 11, "metric": "size", "op": ">=", "value": 0 }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "reusing one Storage.Get offset for distinct reads makes offset-only storage_read specs ambiguous");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("storage_read");
            result["reason"]!.GetValue<string>().Should().Contain("0x000B");
            result["reason"]!.GetValue<string>().Should().Contain("more than once");
            result["reason"]!.GetValue<string>().Should().Contain("ambiguous");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_CustomSpecByteStringRequiresHonorsVmEqualPathCondition()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "byte-string-requires-vm-equal.bin");
            string manifestPath = Path.Combine(dir, "byte-string-requires-vm-equal.manifest.json");
            string specPath = Path.Combine(dir, "byte-string-requires-vm-equal.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x01 },
                new[] { (byte)NeoVm.OpCode.LDARG0 },
                Pushdata1("x"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.EQUAL, (byte)NeoVm.OpCode.NOT, (byte)NeoVm.OpCode.ASSERT },
                ReturnBool(false)));
            WriteMethodManifest(
                manifestPath,
                "ByteStringGateContract",
                "check",
                methodOffset: 0,
                parametersJson: """[{ "name": "key", "type": "ByteString" }]""",
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "byte_string_requires_excluded_by_vm_equal",
                      "description": "Exact byte-string requires must be comparable with VM EQUAL path conditions.",
                      "method": "check",
                      "requires": [
                        { "arg": "key", "op": "==", "value": "0x78" }
                      ],
                      "ensures": [
                        { "return": true, "op": "==", "value": true }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "the only successful HALT path has asserted key != 0x78, so the exact-byte requires excludes it");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("no successful HALT path");
            result["reason"]!.GetValue<string>().Should().Contain("requires");
            result["failed_condition"].Should().BeNull();
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_ForbidFaultsRejectsReturnScopedRequiresOnFaultedPath()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "return-requires-abort.bin");
            string manifestPath = Path.Combine(dir, "return-requires-abort.manifest.json");
            string specPath = Path.Combine(dir, "return-requires-abort.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, new byte[]
            {
                (byte)NeoVm.OpCode.PUSH0,
                (byte)NeoVm.OpCode.ABORT,
            });
            WriteMethodManifest(
                manifestPath,
                "AbortContract",
                "check",
                methodOffset: 0,
                parametersJson: "[]",
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "return_scoped_fault_freedom",
                      "description": "Faulted paths do not have a valid method return value for return-scoped requires.",
                      "method": "check",
                      "requires": [
                        { "return": true, "op": "==", "value": true }
                      ],
                      "forbid_faults": true,
                      "ensures": []
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "a faulted path has no successful return value to satisfy or exclude return-scoped requires");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("return-scoped requires");
            result["reason"]!.GetValue<string>().Should().Contain("faulted path");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_MarksCustomSpecIncompleteForDuplicateAbiParameterNames()
