            File.WriteAllBytes(scriptPath, new byte[]
            {
                (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x02,
                (byte)NeoVm.OpCode.LDARG1,
                (byte)NeoVm.OpCode.RET,
            });
            WriteMethodManifest(
                manifestPath,
                "DuplicateArgsContract",
                "choose",
                methodOffset: 0,
                parametersJson: """
                    [
                      { "name": "x", "type": "Integer" },
