                    """,
                returnType: "Integer");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "duplicate_x_not_sound",
                      "description": "Duplicate ABI parameter names make name-based specs ambiguous.",
                      "method": "choose",
                      "requires": [
                        { "arg": "x", "op": "==", "value": 5 }
