    [Fact]
    public void CliVerify_ReturnPostconditionIgnoresRuntimeTypeMismatchOnRequiresInfeasiblePath()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "integer-return-excluded-bad-type.bin");
            string manifestPath = Path.Combine(dir, "integer-return-excluded-bad-type.manifest.json");
            string specPath = Path.Combine(dir, "integer-return-excluded-bad-type.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] rejectedReturn = Pushdata1("bad"u8.ToArray());
            byte[] script = Concat(
                new byte[]
                {
                    (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x01,
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.PUSH0,
                    (byte)NeoVm.OpCode.GE,
                    (byte)NeoVm.OpCode.JMPIF, (byte)0x00,
                },
                rejectedReturn,
                new[] { (byte)NeoVm.OpCode.RET },
                new[] { (byte)NeoVm.OpCode.LDARG0, (byte)NeoVm.OpCode.RET });
            const int jmpIfOffset = 6;
            int acceptedReturnOffset = 8 + rejectedReturn.Length + 1;
            script[7] = checked((byte)(acceptedReturnOffset - jmpIfOffset));
            ScriptDecoder.Decode(script).Instructions.Single(i => i.Offset == jmpIfOffset)
                .Target.Should().Be(acceptedReturnOffset);
            File.WriteAllBytes(scriptPath, script);
            WriteMethodManifest(
                manifestPath,
                "EchoContract",
                "echoNonNegative",
                methodOffset: 0,
                parametersJson: """[{ "name": "amount", "type": "Integer" }]""",
                returnType: "Integer");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "return_requires_filters_bad_runtime_type",
                      "description": "Return postconditions should evaluate only successful paths feasible under requires.",
                      "method": "echoNonNegative",
                      "requires": [
                        { "arg": "amount", "op": ">=", "value": 0 }
                      ],
                      "ensures": [
                        { "return": true, "op": "==", "value_arg": "amount" }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, File.Exists(reportPath)
                ? File.ReadAllText(reportPath)
                : "the ByteString-returning HALT path is infeasible under requires");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["reason"]!.GetValue<string>().Should().Contain("all successful HALT paths");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

