            File.WriteAllBytes(nefPath, nefBytes);
            WriteMethodManifest(
                manifestPath,
                "IdentityContract",
                "currentHash",
                methodOffset: 0,
                returnType: "Hash160");
            string contractHash = "0x" + ContractIdentity.ComputeContractHashHex(
                NefFile.Parse(nefBytes, verifyChecksum: true),
                ContractManifest.FromFile(manifestPath),
                ContractIdentity.ParseUInt160LittleEndianHex(deploySender));
            File.WriteAllText(specPath, $$"""
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "executing_hash_matches_contract_identity",
                      "description": "NEF verification must bind Runtime.GetExecutingScriptHash to the deployed Neo N3 contract hash.",
                      "method": "currentHash",
                      "ensures": [
                        { "return": true, "op": "==", "value": "{{contractHash}}" }
                      ]
                    }
