    [Fact]
    public void CliVerify_AllowUnprovedRecordsGatePolicyInReport()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-allow-unproved.bin");
            string manifestPath = Path.Combine(dir, "transfer-allow-unproved.manifest.json");
            string specPath = Path.Combine(dir, "transfer-allow-unproved.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, new byte[]
            {
                (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x01,
                (byte)NeoVm.OpCode.RET,
            });
            WriteManifest(manifestPath, methodOffset: 0);
            WriteSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--allow-unproved",
                "--allow-assumption-backed-proofs",
                "--format", "json",
                "--out", reportPath);

            // Review fix (#8): `--allow-unproved` records the gate policy and tolerates
            // Unknown/Incomplete coverage, but a Violated result is a counterexample-backed
            // proven-UNSAFE path that the gate must ALWAYS reject (exit 3). The allow-unproved
            // policy is still recorded in the report; it just never silences a proven violation.
            exit.Should().Be(3, "--allow-unproved records the gate policy but never silences a proven violation");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["violated"]!.GetValue<int>().Should().Be(1);
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["passed"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["policies"]!["fail_on_unproved"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["policies"]!["unproved_allowed"]!.GetValue<bool>().Should().BeTrue();
            root["gate_evaluation"]!["unproved"]!.GetValue<bool>().Should().BeTrue();
            root["gate_evaluation"]!["violations"]!.AsArray().Should().NotBeEmpty(
                "a proven violation fails the gate even under --allow-unproved");

            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("violated");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

