    [Fact]
    public void VerificationMarkdown_RendersUnprovedResultsBeforeProvedResults()
    {
        var report = new VerificationReport(
            new VerificationMeta(StatesExplored: 2, StepsExecuted: 2),
            new VerificationSummary(
                Total: 2,
                Proved: 1,
                Violated: 1,
                Unknown: 0,
                Incomplete: 0),
            System.Collections.Immutable.ImmutableArray.Create(
                new VerificationPropertyResult(
                    Id: "aaa.proved",
                    Method: "ok",
                    Description: null,
                    Status: VerificationStatus.Proved,
                    CheckedPaths: 1,
                    IgnoredFaultedPaths: 0,
                    StoppedPaths: 0,
                    ObligationsChecked: 1,
                    Reason: "proved",
                    FailedCondition: null,
                    Counterexample: null),
                new VerificationPropertyResult(
                    Id: "zzz.violated",
                    Method: "bad",
                    Description: null,
                    Status: VerificationStatus.Violated,
                    CheckedPaths: 1,
                    IgnoredFaultedPaths: 0,
                    StoppedPaths: 0,
                    ObligationsChecked: 1,
                    Reason: "violated",
                    FailedCondition: "bad condition",
                    Counterexample: null)));

        string markdown = VerificationReportRenderer.ToMarkdown(report);

        markdown.IndexOf("### `zzz.violated`", StringComparison.Ordinal)
            .Should().BeLessThan(markdown.IndexOf("### `aaa.proved`", StringComparison.Ordinal),
                "default markdown reports should surface failing proof obligations before proved noise");
        markdown.Should().Contain("- **Violated:** 1");
        markdown.Should().Contain("- **Status:** `violated`");
        markdown.Should().Contain("- **Failed condition:** `bad condition`");
    }

    [Fact]
    public void VerificationMarkdown_RendersSourceProfilePerProperty()
    {
        var report = new VerificationReport(
            new VerificationMeta(),
            new VerificationSummary(
                Total: 2,
                Proved: 2,
                Violated: 0,
                Unknown: 0,
                Incomplete: 0),
            System.Collections.Immutable.ImmutableArray.Create(
                new VerificationPropertyResult(
                    Id: "custom.balance",
                    Method: "balanceOf",
                    Description: null,
                    Status: VerificationStatus.Proved,
                    CheckedPaths: 1,
                    IgnoredFaultedPaths: 0,
                    StoppedPaths: 0,
                    ObligationsChecked: 1,
                    Reason: "custom spec proved",
                    FailedCondition: null,
                    Counterexample: null,
                    SourceProfile: "custom-spec"),
                new VerificationPropertyResult(
                    Id: "profile.transfer",
                    Method: "transfer",
                    Description: null,
                    Status: VerificationStatus.Proved,
                    CheckedPaths: 1,
                    IgnoredFaultedPaths: 0,
                    StoppedPaths: 0,
                    ObligationsChecked: 1,
                    Reason: "profile proof proved",
                    FailedCondition: null,
                    Counterexample: null,
                    SourceProfile: "neo-n3-security")));

        string markdown = VerificationReportRenderer.ToMarkdown(report);

        string customBlock = PropertyBlock(markdown, "custom.balance");
        customBlock.Should().Contain("- **Source profile:** `custom-spec`");
        string profileBlock = PropertyBlock(markdown, "profile.transfer");
        profileBlock.Should().Contain("- **Source profile:** `neo-n3-security`");

        static string PropertyBlock(string markdown, string id)
        {
            string heading = $"### `{id}`";
            int start = markdown.IndexOf(heading, StringComparison.Ordinal);
            start.Should().BeGreaterThanOrEqualTo(0, $"markdown should contain a property block for {id}");
            int next = markdown.IndexOf("\n### `", start + heading.Length, StringComparison.Ordinal);
            return next < 0 ? markdown[start..] : markdown[start..next];
        }
    }

