    [Fact]
    public void VerificationReport_SeparatesAssumptionBackedProofsFromUnqualifiedProofs()
    {
        var results = ImmutableArray.Create(
            new VerificationPropertyResult(
                Id: "unqualified",
                Method: "ok",
                Description: null,
                Status: VerificationStatus.Proved,
                CheckedPaths: 1,
                IgnoredFaultedPaths: 0,
                StoppedPaths: 0,
                ObligationsChecked: 1,
                Reason: "proved without environment assumptions",
                FailedCondition: null,
                Counterexample: null),
            new VerificationPropertyResult(
                Id: "qualified",
                Method: "transfer",
                Description: null,
                Status: VerificationStatus.Proved,
                CheckedPaths: 1,
                IgnoredFaultedPaths: 0,
                StoppedPaths: 0,
                ObligationsChecked: 1,
                Reason: "proved under explicit storage invariant",
                FailedCondition: null,
                Counterexample: null,
                Assumptions: ImmutableArray.Create(new VerificationAssumption(
                    "storage_model",
                    "storage values obey the declared model",
                    "test"))));
        var report = new VerificationReport(
            new VerificationMeta(),
            VerificationSummary.FromResults(results),
            results);

        var root = JsonNode.Parse(VerificationReportRenderer.ToJson(report))!;
        root["summary"]!["proved"]!.GetValue<int>().Should().Be(2);
        root["summary"]!["proved_without_assumptions"]!.GetValue<int>().Should().Be(1);
        root["summary"]!["proved_with_assumptions"]!.GetValue<int>().Should().Be(1);
        root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeTrue();
        root["summary"]!["all_proved_without_assumptions"]!.GetValue<bool>().Should().BeFalse();

        var qualified = root["results"]!.AsArray()
            .Single(result => result!["id"]!.GetValue<string>() == "qualified")!;
        qualified["status"]!.GetValue<string>().Should().Be("proved_with_assumptions");
        qualified["base_status"]!.GetValue<string>().Should().Be("proved");
        qualified["proved_under_assumptions"]!.GetValue<bool>().Should().BeTrue();

        var unqualified = root["results"]!.AsArray()
            .Single(result => result!["id"]!.GetValue<string>() == "unqualified")!;
        unqualified["status"]!.GetValue<string>().Should().Be("proved");
        unqualified["proved_under_assumptions"]!.GetValue<bool>().Should().BeFalse();

        string markdown = VerificationReportRenderer.ToMarkdown(report);
        markdown.Should().Contain("Proved without assumptions:** 1");
        markdown.Should().Contain("Proved with assumptions:** 1");
        markdown.Should().Contain("Status:** `proved_with_assumptions`");
    }

