    [Fact]
    public void CliVerify_MarksCustomSpecIncompleteWhenRequiresAreInfeasible()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-infeasible-requires.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer-infeasible-requires.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, new byte[]
            {
                (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x01,
                (byte)NeoVm.OpCode.PUSH1,
                (byte)NeoVm.OpCode.RET,
            });
            WriteManifest(manifestPath, methodOffset: 0);
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "infeasible_requires_do_not_prove",
                      "description": "Contradictory requires must not prove postconditions.",
                      "method": "transfer",
                      "requires": [
                        { "arg": "amount", "op": ">=", "value": 0 },
                        { "arg": "amount", "op": "<", "value": 0 }
                      ],
                      "ensures": [
                        { "return": true, "op": "==", "value": true }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "infeasible requires are a specification coverage problem, not a proof");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("requires");
            result["reason"]!.GetValue<string>().Should().Contain("infeasible");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

