                          { "name": "to", "type": "Hash160" },
                          { "name": "amount", "type": "Integer" }
                        ]
                      }
                    ]
                    """,
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "transfer_event_amount_matches_arg",
                      "description": "Wrong Runtime.Notify event payload fields must fail custom postconditions.",
                      "method": "transfer",
                      "ensures": [
                        { "notification_arg": "Transfer", "index": 2, "op": "==", "value_arg": "amount" }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, File.Exists(reportPath) ? File.ReadAllText(reportPath) : "an unconstrained amount can differ from the wrong event payload");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["failed_condition"]!.GetValue<string>().Should().Contain("notification_arg(Transfer, 2) == arg(amount)");
            result["counterexample"]!["arg_amount"].Should().NotBeNull();
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

