            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x01 },
                new[] { (byte)NeoVm.OpCode.LDARG0 },
                new[] { (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Runtime.Notify"),
                new[] { (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "EventContract",
                "emitDynamic",
                methodOffset: 0,
                parametersJson: """[{ "name": "eventName", "type": "ByteString" }]""",
                eventsJson: """[{ "name": "Ping", "parameters": [] }]""");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "ping_event_absent",
                      "description": "Dynamic Runtime.Notify names cannot be counted as definitely absent.",
                      "method": "emitDynamic",
                      "ensures": [
                        { "notification": "Ping", "metric": "count", "op": "==", "value": 0 }
                      ]
                    }
                  ]
                }
