    [Fact]
    public void CliVerify_NeoN3SecurityProfileFlagsConcreteInvalidBlsDeserializeAsVmFault()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "cryptolib-bls-invalid-concrete.bin");
            string manifestPath = Path.Combine(dir, "cryptolib-bls-invalid-concrete.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, Concat(
                new[]
                {
                    (byte)NeoVm.OpCode.INITSLOT,
                    (byte)0x00,
                    (byte)0x01,
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.JMPIF,
                    (byte)0x04,
                    (byte)NeoVm.OpCode.PUSHT,
                    (byte)NeoVm.OpCode.RET,
                },
                Pushdata1(CryptoLibHashBytes()),
                Pushdata1("bls12381Deserialize"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                Pushdata1(Enumerable.Repeat((byte)0x42, 47).ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.RET }));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(CryptoLibHashBytes())}}", "methods": ["bls12381Deserialize"] }]""",
                parametersJson: """[{ "name": "takeFaultPath", "type": "Boolean" }]""",
                returnType: "Boolean");

            int exit = InvokeCli(
                "verify",
                scriptPath,
                "--manifest",
                manifestPath,
                "--profile",
                "neo-n3-security",
                "--format",
                "json",
                "--out",
                reportPath);

            exit.Should().Be(3, "a concrete invalid BLS native input is a reachable VM fault, not an unknown external return");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var vmFaultFree = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.bridge")!;
            vmFaultFree["status"]!.GetValue<string>().Should().Be("violated");
            vmFaultFree["reason"]!.GetValue<string>().Should().Contain("CryptoLib.bls12381Deserialize");
            vmFaultFree["reason"]!.GetValue<string>().Should().Contain("48, 96, or 576");
