            var vmFaultFree = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.mulGeneratorG1")!;
            vmFaultFree["status"]!.GetValue<string>().Should().Be("violated");
