    [Fact]
    public void CliVerify_NeoN3SecurityProfileFlagsConcreteInvalidBlsMulScalarAsVmFault()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "cryptolib-bls-mul-invalid-concrete-scalar.bin");
            string manifestPath = Path.Combine(dir, "cryptolib-bls-mul-invalid-concrete-scalar.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");
            byte[] invalidScalar = Enumerable.Repeat((byte)0xff, 32).ToArray();

            File.WriteAllBytes(scriptPath, Concat(
                new[]
                {
                    (byte)NeoVm.OpCode.INITSLOT,
                    (byte)0x01,
                    (byte)0x01,
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.JMPIF,
                    (byte)0x04,
                    (byte)NeoVm.OpCode.PUSHT,
                    (byte)NeoVm.OpCode.RET,
                },
                Pushdata1(CryptoLibHashBytes()),
                Pushdata1("bls12381Deserialize"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                Pushdata1(Convert.FromHexString(BlsG1GeneratorHex)),
                new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.STLOC0 },
                Pushdata1(CryptoLibHashBytes()),
                Pushdata1("bls12381Mul"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.PUSHF },
                Pushdata1(invalidScalar),
                new[] { (byte)NeoVm.OpCode.LDLOC0 },
                new[] { (byte)NeoVm.OpCode.PUSH3, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.RET }));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(CryptoLibHashBytes())}}", "methods": ["bls12381Deserialize", "bls12381Mul"] }]""",
                parametersJson: """[{ "name": "takeFaultPath", "type": "Boolean" }]""",
                returnType: "Boolean");

            int exit = InvokeCli(
                "verify",
                scriptPath,
                "--manifest",
                manifestPath,
                "--profile",
                "neo-n3-security",
                "--format",
                "json",
                "--out",
                reportPath);

            exit.Should().Be(3, "a concrete invalid BLS scalar is a reachable VM fault, not an unknown external return");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var vmFaultFree = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.bridge")!;
            vmFaultFree["status"]!.GetValue<string>().Should().Be("violated");
            vmFaultFree["reason"]!.GetValue<string>().Should().Contain("CryptoLib.bls12381Mul");
            vmFaultFree["reason"]!.GetValue<string>().Should().Contain("valid BLS12-381 scalar");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

