    [Fact]
    public void CliVerify_CustomSpecAllowsSignatureCheckRequiresForAuthorizedProofScope()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "constant-signature-requires.bin");
            string manifestPath = Path.Combine(dir, "constant-signature-requires.manifest.json");
            string specPath = Path.Combine(dir, "constant-signature-requires.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] pubkey = Convert.FromHexString("036B17D1F2E12C4247F8BCE6E563A440F277037D812DEB33A0F4A13945D898C296");
            string pubkeyHex = "0x" + Convert.ToHexString(pubkey).ToLowerInvariant();
            byte[] signature = Enumerable.Repeat((byte)0x42, 64).ToArray();
            File.WriteAllBytes(scriptPath, Concat(
                Pushdata1(pubkey),
                Pushdata1(signature),
                Syscall("System.Crypto.CheckSig"),
                new[] { (byte)NeoVm.OpCode.ASSERT },
                ReturnBool(true)));
            WriteMethodManifest(
                manifestPath,
                "OwnerContract",
                "verifyConstantOwner",
                methodOffset: 0,
                returnType: "Boolean");
            File.WriteAllText(specPath, $$"""
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "constant_owner_signature_scoped_return",
