                      "method": "verifyConstantOwner",
                      "requires": [
                        { "signature_check": "{{pubkeyHex}}", "metric": "enforced_count", "op": ">=", "value": 1 }
                      ],
                      "ensures": [
                        { "return": true, "op": "==", "value": true }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, "signature_check requires should narrow proof obligations to signature-authorized paths");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["reason"]!.GetValue<string>().Should().Contain("under requires");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

