                new[] { (byte)NeoVm.OpCode.LDARG0, (byte)NeoVm.OpCode.LDARG1 },
                Syscall("System.Crypto.CheckSig"),
                new[] { (byte)NeoVm.OpCode.DROP, (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "OwnerContract",
                "verifyOwner",
                methodOffset: 0,
                parametersJson: """
                    [
                      { "name": "pubkey", "type": "PublicKey" },
                      { "name": "signature", "type": "Signature" }
                    ]
