                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "owner_signature_enforced",
                      "description": "Calling CheckSig without asserting the result must not count as authorization.",
                      "method": "verifyOwner",
                      "ensures": [
                        { "signature_check": "pubkey", "metric": "enforced_count", "op": ">=", "value": 1 }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
