        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "callback-wrong-arg.bin");
            string manifestPath = Path.Combine(dir, "callback-wrong-arg.manifest.json");
            string specPath = Path.Combine(dir, "callback-wrong-arg.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x04 },
                new[] { (byte)NeoVm.OpCode.LDARG1 },
                Pushdata1("onNEP17Payment"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH15 },
                new[]
                {
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.PUSH0,
                    (byte)NeoVm.OpCode.LDARG3,
                    (byte)NeoVm.OpCode.PUSH3,
                    (byte)NeoVm.OpCode.PACK,
                },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.DROP, (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "CallbackContract",
                "transfer",
                methodOffset: 0,
                parametersJson: """
                    [
                      { "name": "from", "type": "Hash160" },
                      { "name": "to", "type": "Hash160" },
                      { "name": "amount", "type": "Integer" },
                      { "name": "data", "type": "ByteString" }
                    ]
                    """,
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "callback_amount_matches",
                      "description": "Wrong external call arguments must fail custom postconditions.",
                      "method": "transfer",
                      "require_external_call_completeness": false,
                      "ensures": [
                        { "external_call_arg": "onNEP17Payment", "index": 1, "op": "==", "value_arg": "amount" }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, File.Exists(reportPath) ? File.ReadAllText(reportPath) : "an unconstrained amount can differ from the wrong callback payload");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["failed_condition"]!.GetValue<string>().Should().Contain("external_call_arg(onNEP17Payment, 1) == arg(amount)");
            result["counterexample"]!["arg_amount"].Should().NotBeNull();
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_CustomSpecProvesExternalCallAfterNotification()
    {
