                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x04 },
                Nep17TransferNotification(),
                Nep17PaymentCallbackDropReturn(),
                new[] { (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "CallbackContract",
                "transfer",
                methodOffset: 0,
                parametersJson: """
                    [
                      { "name": "from", "type": "Hash160" },
                      { "name": "to", "type": "Hash160" },
                      { "name": "amount", "type": "Integer" },
                      { "name": "data", "type": "ByteString" }
                    ]
                    """,
                eventsJson: """
                    [
                      {
                        "name": "Transfer",
                        "parameters": [
                          { "name": "from", "type": "Hash160" },
                          { "name": "to", "type": "Hash160" },
                          { "name": "amount", "type": "Integer" }
                        ]
                      }
                    ]
                    """,
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "callback_after_transfer_event",
                      "description": "Custom specs can prove callback ordering relative to emitted events.",
                      "method": "transfer",
                      "require_external_call_completeness": false,
                      "ensures": [
                        { "external_call_after_notification": "onNEP17Payment", "notification_before": "Transfer", "op": "==", "value": true }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
