    [Fact]
    public void CliVerify_CustomSpecScopesExternalCallOrderingToCurrentContractNotificationEmitter()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "native-transfer-before-callback-self-transfer-after.bin");
            string manifestPath = Path.Combine(dir, "native-transfer-before-callback-self-transfer-after.manifest.json");
            string specPath = Path.Combine(dir, "native-transfer-before-callback-self-transfer-after.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");
            byte[] nativeFrom = Enumerable.Range(0, 20).Select(i => (byte)(0x21 + i)).ToArray();
            byte[] nativeTo = Enumerable.Range(0, 20).Select(i => (byte)(0x61 + i)).ToArray();

            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x04 },
                GasTransferNativeCall(nativeFrom, nativeTo, new[] { (byte)NeoVm.OpCode.PUSH1 }),
                new[] { (byte)NeoVm.OpCode.ASSERT },
                Nep17PaymentCallbackDropReturn(),
                Nep17TransferNotification(),
                new[] { (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "CallbackContract",
                "transfer",
                methodOffset: 0,
                parametersJson: """
                    [
                      { "name": "from", "type": "Hash160" },
                      { "name": "to", "type": "Hash160" },
                      { "name": "amount", "type": "Integer" },
                      { "name": "data", "type": "ByteString" }
                    ]
                    """,
                eventsJson: """
                    [
                      {
                        "name": "Transfer",
                        "parameters": [
                          { "name": "from", "type": "Hash160" },
                          { "name": "to", "type": "Hash160" },
                          { "name": "amount", "type": "Integer" }
                        ]
                      }
                    ]
                    """,
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "callback_after_current_transfer_event",
                      "description": "Native token Transfer events must not satisfy ordering requirements for the current contract Transfer event.",
                      "method": "transfer",
                      "require_external_call_completeness": false,
                      "ensures": [
                        {
                          "external_call_after_notification": "onNEP17Payment",
                          "notification_before": "Transfer",
                          "notification_emitter": "current",
                          "op": "==",
                          "value": true
                        }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, File.Exists(reportPath) ? File.ReadAllText(reportPath) : "native GAS Transfer must not prove callback-after-current-Transfer ordering");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["failed_condition"]!.GetValue<string>().Should().Contain("external_call_after_notification(onNEP17Payment, Transfer@current) == true");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

