    [Fact]
    public void CliVerify_CustomSpecMarksExternalCallCountIncompleteForDynamicMethodSelector()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "dynamic-external-selector.bin");
            string manifestPath = Path.Combine(dir, "dynamic-external-selector.manifest.json");
            string specPath = Path.Combine(dir, "dynamic-external-selector.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] target = Enumerable.Repeat((byte)0x52, 20).ToArray();
            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x01 },
                Pushdata1(target),
                new[] { (byte)NeoVm.OpCode.LDARG0 },
                new[]
                {
                    (byte)NeoVm.OpCode.PUSH1,
                    (byte)NeoVm.OpCode.PUSH0,
                    (byte)NeoVm.OpCode.PACK,
                },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.DROP, (byte)NeoVm.OpCode.RET }));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(target)}}", "methods": ["balanceOf"] }]""",
                parametersJson: """[{ "name": "methodName", "type": "ByteString" }]""");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "balance_call_absent",
                      "description": "Dynamic Contract.Call selectors cannot be counted as definitely absent.",
                      "method": "bridge",
                      "require_external_call_completeness": false,
                      "ensures": [
                        { "external_call": "balanceOf", "metric": "count", "op": "==", "value": 0 }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "a symbolic Contract.Call selector may equal balanceOf, so absence cannot be proved");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("external_call");
            result["reason"]!.GetValue<string>().Should().Contain("dynamic");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

