    [Fact]
    public void CliVerify_NeoN3SecurityProfileMarksAnyAbiParameterCoverageIncomplete()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "profile-any-abi-undercoverage.bin");
            string manifestPath = Path.Combine(dir, "profile-any-abi-undercoverage.manifest.json");
            string specPath = Path.Combine(dir, "profile-any-abi-undercoverage.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, new[]
            {
                (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x01,
                (byte)NeoVm.OpCode.PUSHT,
                (byte)NeoVm.OpCode.RET,
            });
            WriteMethodManifest(
                manifestPath,
                "AnyContract",
                "check",
                methodOffset: 0,
                parametersJson: """[{ "name": "data", "type": "Any" }]""",
                returnType: "Boolean");
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "the security profile must not over-prove methods whose ABI entry state is not exhaustively modeled");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["incomplete"]!.GetValue<int>().Should().BeGreaterThan(0);
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.coverage.check")!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("Any");
            result["reason"]!.GetValue<string>().Should().Contain("non-exhaustive");
            root["results"]!.AsArray()
                .Where(r => r!["method"]!.GetValue<string>() == "check"
                    && r!["id"]!.GetValue<string>() != "security.coverage.check")
                .Should().BeEmpty("profile coverage-incomplete methods must not emit independently proved descendant obligations");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

