                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "standard transfer data:Any is explored with representative shapes but is not an exhaustive full-domain proof");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["meta"]!["coverage_incomplete"]!.GetValue<bool>().Should().BeTrue();
            root["meta"]!["coverage_reason"]!.GetValue<string>().Should().Contain("data:Any");

            var coverage = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.coverage.transfer")!;
            coverage["status"]!.GetValue<string>().Should().Be("incomplete");
            coverage["reason"]!.GetValue<string>().Should().Contain("data:Any");
            coverage["reason"]!.GetValue<string>().Should().Contain("non-exhaustive");

            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.sender_authorized.transfer")!["status"]!
                .GetValue<string>().Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.balance_delta.transfer")!["status"]!
                .GetValue<string>().Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.transfer_event.transfer")!["status"]!
                .GetValue<string>().Should().Be("proved");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
