            string manifestPath = Path.Combine(dir, "nep17-transfer-overload-any-coverage.manifest.json");
            string specPath = Path.Combine(dir, "nep17-transfer-overload-any-coverage.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] transferBody =
            {
                (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x04,
                (byte)NeoVm.OpCode.PUSH0,
                (byte)NeoVm.OpCode.RET,
            };
            byte[] standardScript = CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset);
            int overloadOffset = standardScript.Length;
            byte[] overloadBody =
            {
                (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x01,
                (byte)NeoVm.OpCode.PUSHT,
                (byte)NeoVm.OpCode.RET,
            };
            File.WriteAllBytes(scriptPath, Concat(standardScript, overloadBody));
            File.WriteAllText(manifestPath, $$"""
                {
                  "name": "Nep17OverloadContract",
                  "groups": [],
                  "features": {},
                  "supportedstandards": ["NEP-17"],
                  "abi": {
                    "methods": [
                      {
                        "name": "symbol",
                        "parameters": [],
                        "returntype": "String",
                        "offset": {{symbolOffset}},
                        "safe": true
                      },
                      {
                        "name": "decimals",
                        "parameters": [],
                        "returntype": "Integer",
                        "offset": {{decimalsOffset}},
                        "safe": true
                      },
                      {
                        "name": "totalSupply",
                        "parameters": [],
                        "returntype": "Integer",
                        "offset": {{totalSupplyOffset}},
                        "safe": true
                      },
                      {
                        "name": "balanceOf",
                        "parameters": [
                          { "name": "account", "type": "Hash160" }
                        ],
                        "returntype": "Integer",
                        "offset": {{balanceOfOffset}},
                        "safe": true
                      },
                      {
                        "name": "transfer",
                        "parameters": [
                          { "name": "from", "type": "Hash160" },
                          { "name": "to", "type": "Hash160" },
                          { "name": "amount", "type": "Integer" },
                          { "name": "data", "type": "Any" }
                        ],
                        "returntype": "Boolean",
                        "offset": 0,
                        "safe": false
                      },
                      {
                        "name": "transfer",
                        "parameters": [
                          { "name": "data", "type": "Any" }
                        ],
                        "returntype": "Boolean",
                        "offset": {{overloadOffset}},
                        "safe": false
                      }
                    ],
                    "events": [
                      {
                        "name": "Transfer",
                        "parameters": [
                          { "name": "from", "type": "Hash160" },
                          { "name": "to", "type": "Hash160" },
                          { "name": "amount", "type": "Integer" }
                        ]
                      }
                    ]
                  },
                  "permissions": [],
                  "trusts": []
                }
                """);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "non-standard transfer overloads must not inherit the standard NEP-17 data:Any coverage exception");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == $"security.coverage.transfer@{overloadOffset}")!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["method_offset"]!.GetValue<int>().Should().Be(overloadOffset);
            result["reason"]!.GetValue<string>().Should().Contain("data:Any");
            result["reason"]!.GetValue<string>().Should().Contain("non-exhaustive");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

