            (byte)NeoVm.OpCode.PUSHF,
            (byte)NeoVm.OpCode.RET,
        };

        var report = FormalVerifier.Verify(
            ScriptDecoder.Decode(script),
            ContractManifest.FromJson("""
                {
                  "name": "AmbiguousContract",
                  "groups": [],
                  "features": {},
                  "supportedstandards": [],
                  "abi": {
                    "methods": [
                      {
                        "name": "transfer",
                        "parameters": [],
                        "returntype": "Boolean",
                        "offset": 0,
                        "safe": false
                      },
                      {
                        "name": "transfer",
                        "parameters": [{ "name": "amount", "type": "Integer" }],
                        "returntype": "Boolean",
                        "offset": 2,
                        "safe": false
                      }
                    ],
                    "events": []
                  },
                  "permissions": [],
                  "trusts": []
                }
                """),
            VerificationSpec.FromJson(JsonNode.Parse("""
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "transfer_returns_true",
                      "method": "transfer",
                      "ensures": [{ "return": true, "op": "==", "value": true }]
