    [Fact]
    public void CliVerify_ForbidFaultsFindsReachableAssertFailure()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-assert.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer-no-fault.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, AmountNonNegativeAssertScript());
            WriteManifest(manifestPath, methodOffset: 0);
            WriteForbidFaultsSpec(specPath, requireNonNegative: false);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "forbid_faults must reject any satisfiable input path that reaches VM FAULT");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["violated"]!.GetValue<int>().Should().Be(1);

            var result = root["results"]!.AsArray().Single()!;
            result["id"]!.GetValue<string>().Should().Be("amount_no_fault");
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["failed_condition"]!.GetValue<string>().Should().Be("no fault under requires");
            result["reason"]!.GetValue<string>().Should().Contain("ASSERT failed");
            result["ignored_faulted_paths"]!.GetValue<int>().Should().Be(0);
            var amount = BigInteger.Parse(result["counterexample"]!["arg_amount"]!.GetValue<string>());
            amount.Should().BeLessThan(BigInteger.Zero);
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_ForbidFaultsHonorsRequires()
    {
