                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, "fault paths excluded by the declared precondition should not violate fault-freedom");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
