            result["ignored_faulted_paths"]!.GetValue<int>().Should().Be(0);
            result["obligations_checked"]!.GetValue<int>().Should().Be(1);
            result["reason"]!.GetValue<string>().Should().Contain("fault obligations");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

