    [Fact]
    public void Engine_RecordsArithmeticResultForSymbolicAddOverflowProof()
    {
        var engine = new SymbolicEngine(ScriptDecoder.Decode(SymbolicAddOverflowScript()));
        var entry = engine.CreateMethodEntryState(0, new[]
        {
            new ContractParameterDefinition("amount", "Integer"),
        });

        var result = engine.Run(entry);

        result.FinalStates.Should().ContainSingle();
        var op = result.FinalStates.Single().Telemetry.ArithmeticOps.Should().ContainSingle().Which;
        op.Operation.Should().Be("ADD");
        op.OverflowPossible.Should().BeTrue();
        op.Result.Should().NotBeNull();
        op.Result!.Expression.FreeSymbols().Should().Contain("arg_amount");
    }

