            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x01 },
                new[]
                {
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.CONVERT,
                    SymbolicEngine.StackItemTypeCodes.Integer,
                    (byte)NeoVm.OpCode.RET,
                }));
            WriteMethodManifest(
                manifestPath,
                "BytesContract",
                "toInteger",
                methodOffset: 0,
                parametersJson: """[{ "name": "value", "type": "ByteString" }]""",
                returnType: "Integer");
            WriteByteStringToIntegerNoFaultSpec(specPath, requireNeoVmIntegerBytes: false);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "NeoVM faults when ByteString-to-Integer conversion receives more than 32 bytes");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("CONVERT Integer");
            result["reason"]!.GetValue<string>().Should().Contain("32 bytes");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

