    [Fact]
    public void CliVerify_CustomSpecIgnoresAmbiguousStoragePutOnRequiresInfeasiblePath()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "storage-put-infeasible-ambiguous-path.bin");
            string manifestPath = Path.Combine(dir, "storage-put-infeasible-ambiguous-path.manifest.json");
            string specPath = Path.Combine(dir, "storage-put-infeasible-ambiguous-path.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] dispatchPrefix =
            {
                (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x02,
                (byte)NeoVm.OpCode.LDARG0,
                (byte)NeoVm.OpCode.JMPIF, 0x00,
                (byte)NeoVm.OpCode.LDARG1,
                (byte)NeoVm.OpCode.CALL, 0x00,
                (byte)NeoVm.OpCode.LDARG1,
                (byte)NeoVm.OpCode.CALL, 0x00,
                (byte)NeoVm.OpCode.RET,
                (byte)NeoVm.OpCode.LDARG1,
                (byte)NeoVm.OpCode.CALL, 0x00,
                (byte)NeoVm.OpCode.RET,
            };
            byte[] key = Pushdata1("amount"u8.ToArray());
            byte[] storeSubroutine = Concat(
                key,
                new[] { (byte)NeoVm.OpCode.SWAP },
                Syscall("System.Storage.Local.Put"),
                new[] { (byte)NeoVm.OpCode.RET });

            const int jmpIfOffset = 4;
            const int falseCall1Offset = 7;
            const int falseCall2Offset = 10;
            const int trueBranchOffset = 13;
            const int trueCallOffset = 14;
            int storeSubroutineOffset = dispatchPrefix.Length;
            dispatchPrefix[5] = checked((byte)(trueBranchOffset - jmpIfOffset));
            dispatchPrefix[8] = checked((byte)(storeSubroutineOffset - falseCall1Offset));
            dispatchPrefix[11] = checked((byte)(storeSubroutineOffset - falseCall2Offset));
            dispatchPrefix[15] = checked((byte)(storeSubroutineOffset - trueCallOffset));

            int storagePutOffset = storeSubroutineOffset + key.Length + 1;
            byte[] script = Concat(dispatchPrefix, storeSubroutine);
            ScriptDecoder.Decode(script).Instructions.Single(i => i.Offset == jmpIfOffset).Target.Should().Be(trueBranchOffset);
            ScriptDecoder.Decode(script).Instructions.Single(i => i.Offset == falseCall1Offset).Target.Should().Be(storeSubroutineOffset);
            ScriptDecoder.Decode(script).Instructions.Single(i => i.Offset == falseCall2Offset).Target.Should().Be(storeSubroutineOffset);
            ScriptDecoder.Decode(script).Instructions.Single(i => i.Offset == trueCallOffset).Target.Should().Be(storeSubroutineOffset);
            ScriptDecoder.Decode(script).Instructions
                .Single(i => i.Offset == storagePutOffset)
                .OpCode.Should().Be(NeoVm.OpCode.SYSCALL);
            File.WriteAllBytes(scriptPath, script);
            WriteMethodManifest(
                manifestPath,
                "StorageWriteContract",
                "store",
                methodOffset: 0,
                parametersJson: """[{ "name": "flag", "type": "Boolean" }, { "name": "amount", "type": "Integer" }]""");
            File.WriteAllText(specPath, $$"""
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "storage_put_requires_filters_ambiguous_path",
                      "description": "Requires should filter paths before path-local Storage.Put ambiguity is evaluated.",
                      "method": "store",
                      "requires": [
                        { "arg": "flag", "op": "==", "value": true },
                        { "arg": "amount", "op": ">=", "value": 0 }
                      ],
                      "ensures": [
                        { "storage_put": {{storagePutOffset}}, "op": ">=", "value": 0 }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, File.Exists(reportPath)
                ? File.ReadAllText(reportPath)
                : "requires excludes the path that executes the referenced Storage.Put offset twice");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["reason"]!.GetValue<string>().Should().Contain("all successful HALT paths");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

