    [Fact]
    public void FormalVerifier_ForbidFaultsFindsSymbolicCheckWitnessLength()
    {
        byte[] script = Concat(
            new[]
            {
                (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x01,
                (byte)NeoVm.OpCode.LDARG0,
            },
            Syscall("System.Runtime.CheckWitness"),
            new[] { (byte)NeoVm.OpCode.RET });

        var report = FormalVerifier.Verify(
            ScriptDecoder.Decode(script),
            ContractManifest.FromJson("""
                {
                  "name": "WitnessContract",
                  "groups": [],
                  "features": {},
                  "supportedstandards": [],
                  "abi": {
                    "methods": [
                      {
                        "name": "check",
                        "parameters": [{ "name": "witness", "type": "ByteString" }],
                        "returntype": "Boolean",
                        "offset": 0,
                        "safe": false
                      }
                    ],
                    "events": []
                  },
                  "permissions": [],
                  "trusts": []
                }
                """),
            VerificationSpec.FromJson(JsonNode.Parse("""
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "check_witness_symbolic_length",
                      "method": "check",
                      "forbid_faults": true,
                      "ensures": []
                    }
                  ]
                }
                """)!),
            ExecutionOptions.Default,
            new FixedSmtBackend(SmtOutcome.Sat));

        var result = report.Results.Single();
        result.Status.Should().Be(VerificationStatus.Violated);
        result.Reason.Should().Contain("CheckWitness");
        result.Reason.Should().Contain("20 or 33 bytes");
    }

