    [Fact]
    public void CliVerify_MarksSmtConcretizedProofIncomplete()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "symbolic-pick.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, new byte[]
            {
                (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x01,
                (byte)NeoVm.OpCode.PUSH1,
                (byte)NeoVm.OpCode.PUSH2,
                (byte)NeoVm.OpCode.LDARG0,
                (byte)NeoVm.OpCode.PICK,
                (byte)NeoVm.OpCode.RET,
            });
            WriteManifest(manifestPath, methodOffset: 0);
            WriteSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "SMT concretization explores one feasible value and must not be treated as a complete proof");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["incomplete"]!.GetValue<int>().Should().Be(1);
            root["summary"]!["violated"]!.GetValue<int>().Should().Be(0);

            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("SMT concretized symbolic runtime operand");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

