    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ProvesCommonRuntimeEnvironmentSyscalls()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "runtime-environment.nef");
            string manifestPath = Path.Combine(dir, "runtime-environment.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";

            File.WriteAllBytes(scriptPath, BuildNef("dotnet", "", Array.Empty<MethodToken>(), Concat(
                Syscall("System.Runtime.Platform"),
                Pushdata1("NEO"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.EQUAL, (byte)NeoVm.OpCode.ASSERT },
                Syscall("System.Runtime.GetTrigger"),
                new[] { (byte)NeoVm.OpCode.PUSHINT8, (byte)0x40, (byte)NeoVm.OpCode.NUMEQUAL, (byte)NeoVm.OpCode.ASSERT },
                Syscall("System.Runtime.GasLeft"),
                new[] { (byte)NeoVm.OpCode.DROP },
                Syscall("System.Runtime.GetInvocationCounter"),
                new[] { (byte)NeoVm.OpCode.DROP },
                Syscall("System.Runtime.GetNetwork"),
                new[] { (byte)NeoVm.OpCode.DROP },
                Syscall("System.Runtime.GetAddressVersion"),
                new[] { (byte)NeoVm.OpCode.DROP },
                Syscall("System.Runtime.GetTime"),
                new[] { (byte)NeoVm.OpCode.DROP },
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                Syscall("System.Runtime.BurnGas"),
                new[] { (byte)NeoVm.OpCode.RET })));
            WriteMethodManifest(manifestPath, "RuntimeContract", "inspect", methodOffset: 0);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--deploy-sender-hash", deploySender,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, "pure Runtime environment syscalls should not make the VM-surface proof incomplete");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["violated"]!.GetValue<int>().Should().Be(0);
            root["summary"]!["unknown"]!.GetValue<int>().Should().Be(0);
            root["summary"]!["incomplete"]!.GetValue<int>().Should().Be(0);

            var vmSurface = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_surface.inspect")!;
            vmSurface["status"]!.GetValue<string>().Should().Be("proved");
            vmSurface["reason"]!.GetValue<string>().Should().NotContain("unknown syscall");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

