    [Fact]
    public void CliVerify_DoesNotProveRuntimeGetRandomStableAcrossRepeatedHelperCalls()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "runtime-random-helper-repeat.bin");
            string manifestPath = Path.Combine(dir, "runtime-random-helper-repeat.manifest.json");
            string specPath = Path.Combine(dir, "runtime-random-helper-repeat.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, RuntimeGetRandomTwiceThroughSameHelperScript());
            WriteMethodManifest(
                manifestPath,
                "RuntimeContract",
                "randomsEqual",
                methodOffset: 0,
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "runtime_random_not_stable_across_calls",
                      "description": "Repeated Runtime.GetRandom calls from the same helper offset must not be modeled as stable.",
                      "method": "randomsEqual",
                      "ensures": [
                        { "return": true, "op": "==", "value": true }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "Runtime.GetRandom returns a fresh value on each call, even when the same helper offset is invoked repeatedly");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be(
                "violated",
                result["reason"]!.GetValue<string>());
            result["reason"]!.GetValue<string>().Should().Contain("$return == true");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

