            byte[] getContract = ContractManagementGetContractNativeCall(receiver);
            byte[] presentBranch = Concat(
                new[] { (byte)NeoVm.OpCode.DROP },
                ContractManagementIsContractNativeCall(receiver),
                new[]
                {
                    (byte)NeoVm.OpCode.ASSERT,
                    (byte)NeoVm.OpCode.PUSHT,
                    (byte)NeoVm.OpCode.RET,
                });
            byte branchOffset = checked((byte)(2 + presentBranch.Length));
            File.WriteAllBytes(scriptPath, Concat(
                getContract,
                new[]
                {
                    (byte)NeoVm.OpCode.DUP,
                    (byte)NeoVm.OpCode.ISNULL,
                    (byte)NeoVm.OpCode.JMPIF,
                    branchOffset,
                },
                presentBranch,
                new[]
                {
                    (byte)NeoVm.OpCode.DROP,
                    (byte)NeoVm.OpCode.PUSHT,
                    (byte)NeoVm.OpCode.RET,
                }));
            WriteMethodManifest(
                manifestPath,
