                "getContractImpliesIsContract");

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, "ContractManagement.getContract(target) returning non-null proves target is a contract on the same path");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("proved");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

