    [Theory]
    [InlineData("GASToken", "balanceOf", 1, "GAS.balanceOf")]
    [InlineData("LedgerContract", "getBlock", 1, "Ledger.getBlock")]
    [InlineData("PolicyContract", "getFeePerByte", 0, "Policy.getFeePerByte")]
    public void CliVerify_ForbidFaultsFindsModeledNativeCalltMissingReturnValueShape(
        string nativeContract,
        string nativeMethod,
        int parameterCount,
        string operation)
    {
        string dir = CreateTempDirectory();
        try
        {
            string safeName = $"{nativeContract}-{nativeMethod}".ToLowerInvariant();
            string methodName = $"{char.ToLowerInvariant(nativeMethod[0])}{nativeMethod[1..]}MustDeclareReturnValue";
            string nefPath = Path.Combine(dir, $"{safeName}-callt-no-return.nef");
            string manifestPath = Path.Combine(dir, $"{safeName}-callt-no-return.manifest.json");
            string specPath = Path.Combine(dir, $"{safeName}-callt-no-return.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");
            byte[] targetHash = nativeContract switch
            {
                "GASToken" => GasTokenHashBytes(),
                "LedgerContract" => LedgerContractHashBytes(),
                "PolicyContract" => PolicyContractHashBytes(),
                _ => throw new ArgumentOutOfRangeException(nameof(nativeContract)),
            };

            File.WriteAllBytes(
                nefPath,
                BuildNef(
                    "neo-sym-test",
                    "",
                    new[] { new MethodToken(targetHash, nativeMethod, ParametersCount: checked((ushort)parameterCount), HasReturnValue: false, CallFlags: 0x01) },
                    Concat(
                        NativeCalltArguments(nativeContract, nativeMethod),
                        new[]
                        {
                            (byte)NeoVm.OpCode.CALLT,
                            (byte)0x00,
                            (byte)0x00,
                            (byte)NeoVm.OpCode.PUSHT,
                            (byte)NeoVm.OpCode.RET,
                        })));
            WriteMethodManifest(
                manifestPath,
                "NativeCalltShapeContract",
                methodName,
                methodOffset: 0,
                returnType: "Boolean");
            WriteNoFaultSpec(
                specPath,
                $"native_callt_{safeName}_return_shape",
                methodName);

            int exit = InvokeCli(
                "verify", nefPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "CALLT MethodToken metadata must declare return values for modeled native methods");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("CALLT MethodToken");
            result["reason"]!.GetValue<string>().Should().Contain(operation);
            result["reason"]!.GetValue<string>().Should().Contain("declares no return value");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

