    [Fact]
    public void CliVerify_CustomSpecProvesGasTransferNativeTransferNotificationPayload()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "gas-transfer-notification-payload.bin");
            string manifestPath = Path.Combine(dir, "gas-transfer-notification-payload.manifest.json");
            string specPath = Path.Combine(dir, "gas-transfer-notification-payload.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");
            byte[] from = Enumerable.Range(0, 20).Select(i => (byte)(0x21 + i)).ToArray();
            byte[] to = Enumerable.Range(0, 20).Select(i => (byte)(0x61 + i)).ToArray();
            string fromHex = "0x" + Convert.ToHexString(from).ToLowerInvariant();
            string toHex = "0x" + Convert.ToHexString(to).ToLowerInvariant();

            File.WriteAllBytes(scriptPath, Concat(
                GasTransferNativeCall(from, to, new[] { (byte)NeoVm.OpCode.PUSH1 }),
                new[] { (byte)NeoVm.OpCode.ASSERT, (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "GasBridgeContract",
                "pay",
                methodOffset: 0,
                returnType: "Boolean");
            File.WriteAllText(specPath, $$"""
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "gas_transfer_native_transfer_event_payload",
                      "description": "Native GAS.transfer success emits a proof-visible NEP-17 Transfer payload.",
                      "method": "pay",
                      "require_external_call_completeness": false,
                      "ensures": [
                        { "notification": "Transfer", "metric": "count", "op": "==", "value": 1 },
                        { "notification_arg": "Transfer", "index": 0, "op": "==", "value": "{{fromHex}}" },
                        { "notification_arg": "Transfer", "index": 1, "op": "==", "value": "{{toHex}}" },
                        { "notification_arg": "Transfer", "index": 2, "op": "==", "value": 1 }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, File.Exists(reportPath) ? File.ReadAllText(reportPath) : "successful native GAS.transfer should emit a proof-visible Transfer(from,to,amount) notification");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["reason"]!.GetValue<string>().Should().Contain("ensures");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

