    [Fact]
    public void CliVerify_CustomSpecCanFilterTransferNotificationByCurrentContractEmitter()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "gas-transfer-and-self-transfer-event.bin");
            string manifestPath = Path.Combine(dir, "gas-transfer-and-self-transfer-event.manifest.json");
            string specPath = Path.Combine(dir, "gas-transfer-and-self-transfer-event.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");
            byte[] from = Enumerable.Range(0, 20).Select(i => (byte)(0x21 + i)).ToArray();
            byte[] to = Enumerable.Range(0, 20).Select(i => (byte)(0x61 + i)).ToArray();

            File.WriteAllBytes(scriptPath, Concat(
                GasTransferNativeCall(from, to, new[] { (byte)NeoVm.OpCode.PUSH1 }),
                new[] { (byte)NeoVm.OpCode.ASSERT },
                Pushdata1("Transfer"u8.ToArray()),
                new[]
                {
                    (byte)NeoVm.OpCode.PUSH2,
                },
                Pushdata1(to),
                Pushdata1(from),
                new[]
                {
                    (byte)NeoVm.OpCode.PUSH3,
                    (byte)NeoVm.OpCode.PACK,
                },
                Syscall("System.Runtime.Notify"),
                new[] { (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "GasBridgeContract",
                "pay",
                methodOffset: 0,
                eventsJson: """
                    [
                      {
                        "name": "Transfer",
                        "parameters": [
                          { "name": "from", "type": "Hash160" },
                          { "name": "to", "type": "Hash160" },
                          { "name": "amount", "type": "Integer" }
                        ]
                      }
                    ]
                    """,
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "self_transfer_event_amount_ignores_native_transfer_event",
                      "description": "Custom specs can scope notification payload checks to the current contract emitter.",
                      "method": "pay",
                      "require_external_call_completeness": false,
                      "ensures": [
                        { "notification_arg": "Transfer", "notification_emitter": "current", "index": 2, "op": "==", "value": 2 }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, File.Exists(reportPath) ? File.ReadAllText(reportPath) : "notification_emitter=current should select the user contract Transfer event, not the native GAS Transfer event");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("proved");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

