                new[] { (byte)NeoVm.OpCode.DROP, (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "GasBridgeContract",
                "pay",
                methodOffset: 0,
                returnType: "Boolean");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "gas_transfer_has_no_storage_mutation",
                      "description": "Native token balance mutations are visible to storage side-effect policies.",
                      "method": "pay",
                      "forbid_storage_mutation": true,
                      "require_external_call_completeness": false,
                      "ensures": []
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "native GAS.transfer mutates native token balances and must violate read-only storage policies");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("GAS.transfer");
            result["failed_condition"]!.GetValue<string>().Should().Contain("native storage mutation");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

