            string specPath = Path.Combine(dir, "bytes-pickitem-fault-only-success.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, ByteStringPickItemThenTrueScript());
            WriteMethodManifest(
                manifestPath,
                "ByteStringContract",
                "readThenTrue",
                methodOffset: 0,
                parametersJson: """
