                .Single(r => r!["id"]!.GetValue<string>() == "security.access_control.mint")!;
            result["id"]!.GetValue<string>().Should().Be("security.access_control.mint");
            result["method"]!.GetValue<string>().Should().Be("mint");
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("Storage.Put");
            result["failed_condition"]!.GetValue<string>().Should().Contain("auth before sensitive state mutation");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

