    [Fact]
    public void CliVerify_NeoN3SecurityProfile_FailsSensitiveStorageWriteAfterUnboundCryptoLibSignature()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "mint-unbound-cryptolib-signature.bin");
            string manifestPath = Path.Combine(dir, "mint-unbound-cryptolib-signature.manifest.json");
            string specPath = Path.Combine(dir, "mint-unbound-cryptolib-signature.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");
            byte[] adminPublicKey = Convert.FromHexString(
                "036B17D1F2E12C4247F8BCE6E563A440F277037D812DEB33A0F4A13945D898C296");

            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x02 },
                Pushdata1(CryptoLibHashBytes()),
                Pushdata1("verifyWithECDsa"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.PUSHINT8, (byte)23 },
                new[] { (byte)NeoVm.OpCode.LDARG1 },
                Pushdata1(adminPublicKey),
                new[] { (byte)NeoVm.OpCode.LDARG0 },
                new[] { (byte)NeoVm.OpCode.PUSH4, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.ASSERT },
                Syscall("System.Storage.GetContext"),
                Pushdata1("supply"u8.ToArray()),
                Pushdata1(new byte[] { 1 }),
                Syscall("System.Storage.Put"),
                new[] { (byte)NeoVm.OpCode.RET }));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(CryptoLibHashBytes())}}", "methods": ["verifyWithECDsa"] }]""",
                parametersJson: """
                    [
                      { "name": "message", "type": "ByteString" },
                      { "name": "signature", "type": "Signature" }
                    ]
                    """);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify",
                scriptPath,
                "--manifest",
                manifestPath,
                "--spec",
                specPath,
                "--format",
                "json",
                "--out",
                reportPath);

            exit.Should().Be(3, "a signature over an arbitrary message must not authorize unrelated storage mutation");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.access_control.bridge")!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("signature");
            result["reason"]!.GetValue<string>().Should().Contain("Storage.Put");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

