                "036B17D1F2E12C4247F8BCE6E563A440F277037D812DEB33A0F4A13945D898C296");

            WriteNefScript(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x02 },
                Pushdata1(CryptoLibHashBytes()),
                Pushdata1("verifyWithECDsa"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.PUSHINT8, (byte)23 },
                new[] { (byte)NeoVm.OpCode.LDARG1 },
                Pushdata1(adminPublicKey),
                new[] { (byte)NeoVm.OpCode.LDARG0 },
                new[] { (byte)NeoVm.OpCode.PUSH4, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.ASSERT },
                Syscall("System.Storage.GetContext"),
                Pushdata1("supply"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.LDARG0 },
                new[] { (byte)NeoVm.OpCode.DUP, (byte)NeoVm.OpCode.SIZE },
                PushInt32(65535),
                new[] { (byte)NeoVm.OpCode.LE, (byte)NeoVm.OpCode.ASSERT },
                Syscall("System.Storage.Put"),
                new[] { (byte)NeoVm.OpCode.RET }));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(CryptoLibHashBytes())}}", "methods": ["verifyWithECDsa"] }]""",
                parametersJson: """
                    [
                      { "name": "message", "type": "ByteString" },
                      { "name": "signature", "type": "Signature" }
                    ]
                    """);
