                "--deploy-sender-hash",
                ProofDeploySenderHash,
                "--format",
                "json",
                "--out",
                reportPath);

            exit.Should().Be(0, "a CryptoLib signature can authorize a mutation when the signed message is operation-bound");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.access_control.bridge")!;
            result["status"]!.GetValue<string>().Should().Be("proved");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

