                Syscall("System.Storage.GetContext"),
                new[] { (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.PUSH2 },
                Syscall("System.Storage.Put"),
                new[] { (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "MintContract",
                "mint",
                methodOffset: 0,
                parametersJson: """
                    [
                      { "name": "accountA", "type": "Hash160" },
                      { "name": "accountB", "type": "Hash160" }
                    ]
                    """);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "each sensitive operation needs authorization related to that operation, not just the first write");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.access_control.mint")!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("unrelated");
            result["failed_condition"]!.GetValue<string>().Should().Contain("authorized principal related to sensitive operation");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

