            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0, (byte)2 },
                new[] { (byte)NeoVm.OpCode.LDARG0 },
                new[] { (byte)NeoVm.OpCode.LDARG1 },
                Syscall("System.Crypto.CheckMultisig"),
                new[] { (byte)NeoVm.OpCode.ASSERT },
                Syscall("System.Storage.GetContext"),
                Pushdata1("supply"u8.ToArray()),
                Pushdata1(new byte[] { 1 }),
                Syscall("System.Storage.Put"),
                new[] { (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "MintContract",
                "mint",
                methodOffset: 0,
                parametersJson: """
                    [
                      { "name": "pubkeys", "type": "Array" },
                      { "name": "signatures", "type": "Array" }
                    ]
                    """);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "caller-provided CheckMultisig public-key arrays require non-exhaustive method-entry coverage");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["incomplete"]!.GetValue<int>().Should().BeGreaterThan(0);
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.coverage.mint")!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("Array");
            result["reason"]!.GetValue<string>().Should().Contain("non-exhaustive");
            root["results"]!.AsArray()
                .Where(r => r!["method"]!.GetValue<string>() == "mint"
