    [Fact]
    public void CliVerify_NeoN3SecurityProfile_FailsSensitiveStorageWriteAfterCallerProvidedCheckSig()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "mint-arg-sig.bin");
            string manifestPath = Path.Combine(dir, "mint-arg-sig.manifest.json");
            string specPath = Path.Combine(dir, "mint-arg-sig.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0, (byte)2 },
                new[] { (byte)NeoVm.OpCode.LDARG0 },
                new[] { (byte)NeoVm.OpCode.LDARG1 },
                Syscall("System.Crypto.CheckSig"),
                new[] { (byte)NeoVm.OpCode.ASSERT },
                Syscall("System.Storage.GetContext"),
                Pushdata1("supply"u8.ToArray()),
                Pushdata1(new byte[] { 1 }),
                Syscall("System.Storage.Put"),
                new[] { (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(
                manifestPath,
                "MintContract",
                "mint",
                methodOffset: 0,
                parametersJson: """
                    [
                      { "name": "pubkey", "type": "PublicKey" },
                      { "name": "signature", "type": "Signature" }
                    ]
                    """);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "a caller-provided signature key is not a proof-grade authorization for an unrelated storage mutation");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.access_control.mint")!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("unrelated");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

