            File.WriteAllBytes(scriptPath, new[]
            {
                (byte)NeoVm.OpCode.LDARG0,
                (byte)NeoVm.OpCode.RET,
            });
            WriteMethodManifest(manifestPath, "FaultContract", "alwaysFault", methodOffset: 0);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "an all-faulted entrypoint must not make the profile look fully proved");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.entrypoint_reaches_halt.alwaysFault")!;
