                    .Single(r => r!["id"]!.GetValue<string>() == id)!;
                profileResult["status"]!.GetValue<string>().Should().Be(
                    "incomplete",
                    "success-path profile obligations must not be proved when the entrypoint has no successful HALT path");
                profileResult["checked_paths"]!.GetValue<int>().Should().Be(0);
                profileResult["reason"]!.GetValue<string>().Should().Contain("no successful HALT paths");
            }
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
