            string specPath = Path.Combine(dir, "excluded-dynamic-loadscript.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x02 },
                new[]
                {
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.JMPIF, (byte)0x0E,
                    (byte)NeoVm.OpCode.LDARG1,
                    (byte)NeoVm.OpCode.PUSH0,
                    (byte)NeoVm.OpCode.PUSH0,
                    (byte)NeoVm.OpCode.PACK,
                },
                Syscall("System.Runtime.LoadScript"),
                new[]
                {
                    (byte)NeoVm.OpCode.DROP,
                    (byte)NeoVm.OpCode.PUSH0,
                    (byte)NeoVm.OpCode.RET,
                    (byte)NeoVm.OpCode.PUSH1,
                    (byte)NeoVm.OpCode.RET,
                }));
            WriteMethodManifest(
                manifestPath,
                "LoadScriptContract",
                "selected",
                methodOffset: 0,
                parametersJson: """
                    [
                      { "name": "flag", "type": "Boolean" },
                      { "name": "payload", "type": "ByteString" }
                    ]
                    """,
                returnType: "Integer");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "selected_return_value",
                      "description": "Requires-scoped proofs must ignore Runtime.LoadScript on infeasible paths.",
                      "method": "selected",
                      "requires": [
                        { "arg": "flag", "op": "==", "value": true }
                      ],
                      "ensures": [
                        { "return": true, "op": "==", "value": 1 }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, File.Exists(reportPath) ? File.ReadAllText(reportPath) : "verify report was not written");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["reason"]!.GetValue<string>().Should().Contain("ensures");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

