    [Fact]
    public void CliVerify_NeoN3SecurityProfile_FailsUncheckedModeledNativeReturn()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "stdlib-strlen-unchecked-return.bin");
            string manifestPath = Path.Combine(dir, "stdlib-strlen-unchecked-return.manifest.json");
            string specPath = Path.Combine(dir, "stdlib-strlen-unchecked-return.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");
            byte[] owner = Enumerable.Range(0, 20).Select(i => (byte)(0x40 + i)).ToArray();

            File.WriteAllBytes(scriptPath, Concat(
                Pushdata1(owner),
                Syscall("System.Runtime.CheckWitness"),
                new[] { (byte)NeoVm.OpCode.ASSERT },
                Pushdata1(StdLibHashBytes()),
                Pushdata1("strLen"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH5 },
                Pushdata1("alice"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.DROP, (byte)NeoVm.OpCode.RET }));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(StdLibHashBytes())}}", "methods": ["strLen"] }]""");
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "modeled native Contract.Call returns are still non-void external returns");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.external_returns.bridge")!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("strLen");
            result["reason"]!.GetValue<string>().Should().Contain("not checked");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

