    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ChecksManifestPermissionOnExplicitRejectionPath()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "stdlib-strlen-permission-before-reject.bin");
            string manifestPath = Path.Combine(dir, "stdlib-strlen-permission-before-reject.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] rejectingCall = Concat(
                Pushdata1(StdLibHashBytes()),
                Pushdata1("strLen"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH5 },
                Pushdata1("alice"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Contract.Call"),
                new[]
                {
                    (byte)NeoVm.OpCode.DUP,
                    (byte)NeoVm.OpCode.PUSH0,
                    (byte)NeoVm.OpCode.GE,
                    (byte)NeoVm.OpCode.ASSERT,
                    (byte)NeoVm.OpCode.DROP,
                    (byte)NeoVm.OpCode.PUSHF,
                    (byte)NeoVm.OpCode.ASSERT,
                });
            byte branchOffset = checked((byte)(2 + rejectingCall.Length));
            File.WriteAllBytes(scriptPath, Concat(
                new[]
                {
                    (byte)NeoVm.OpCode.INITSLOT,
                    (byte)0x00,
                    (byte)0x01,
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.JMPIF,
                    branchOffset,
                },
                rejectingCall,
                new[]
                {
                    (byte)NeoVm.OpCode.PUSHT,
                    (byte)NeoVm.OpCode.RET,
                }));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: "[]",
                parametersJson: """[{ "name": "flag", "type": "Boolean" }]""",
                returnType: "Boolean");

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "manifest permissions are enforced when the external call executes, even if the path rejects later");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.manifest_call_permissions.bridge")!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("StdLib.strLen");
            result["reason"]!.GetValue<string>().Should().Contain("not covered by manifest.permissions");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

