                },
                Pushdata1(StdLibHashBytes()),
                Pushdata1("strLen"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                Pushdata1(Convert.FromHexString("FF")),
                new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.RET }));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(StdLibHashBytes())}}", "methods": ["strLen"] }]""",
                parametersJson: """[{ "name": "takeFaultPath", "type": "Boolean" }]""",
                returnType: "Boolean");

            int exit = InvokeCli(
                "verify",
                scriptPath,
                "--manifest",
                manifestPath,
                "--profile",
                "neo-n3-security",
                "--format",
                "json",
                "--out",
                reportPath);

            exit.Should().Be(3, "a concrete invalid StdLib UTF-8 string input is a reachable VM fault");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var vmFaultFree = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.bridge")!;
            vmFaultFree["status"]!.GetValue<string>().Should().Be("violated");
            vmFaultFree["reason"]!.GetValue<string>().Should().Contain("StdLib.strLen");
            vmFaultFree["reason"]!.GetValue<string>().Should().Contain("strict UTF-8");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

