    [Fact]
    public void CliVerify_NeoN3SecurityProfile_FailsExternalReturnFalseBranchThatStillSucceeds()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "external-return-false-still-succeeds.bin");
            string manifestPath = Path.Combine(dir, "external-return-false-still-succeeds.manifest.json");
            string specPath = Path.Combine(dir, "external-return-false-still-succeeds.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");
            byte[] owner = Enumerable.Range(0, 20).Select(i => (byte)(0x48 + i)).ToArray();
            byte[] target = Enumerable.Range(0, 20).Select(i => (byte)(0x88 + i)).ToArray();

            File.WriteAllBytes(scriptPath, Concat(
                Pushdata1(owner),
                Syscall("System.Runtime.CheckWitness"),
                new[] { (byte)NeoVm.OpCode.ASSERT },
                Pushdata1(target),
                Pushdata1("settle"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH15 },
                new[] { (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Contract.Call"),
                new[] { (byte)NeoVm.OpCode.JMPIF, (byte)0x04 },
                new[] { (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET },
                new[] { (byte)NeoVm.OpCode.PUSHT, (byte)NeoVm.OpCode.RET }));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(target)}}", "methods": ["settle"] }]""",
                returnType: "Boolean");
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "checking an external return must prove the false branch cannot still report success");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.external_returns.bridge")!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("false");
            result["reason"]!.GetValue<string>().Should().Contain("success");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

