    [Fact]
    public void CliVerify_ForbidFaultsFindsConcreteRuntimeLoadScriptFault()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "loadscript-custom-forbid-faults.bin");
            string manifestPath = Path.Combine(dir, "loadscript-custom-forbid-faults.manifest.json");
            string specPath = Path.Combine(dir, "loadscript-custom-forbid-faults.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, Concat(
                Pushdata1(new byte[] { (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.ASSERT }),
                new byte[] { (byte)NeoVm.OpCode.PUSH0 },
                new byte[] { (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.PACK },
                Syscall("System.Runtime.LoadScript"),
                new byte[] { (byte)NeoVm.OpCode.DROP, (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(manifestPath, "LoadScriptContract", "run", methodOffset: 0, safe: false);
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "loadscript_no_fault",
                      "description": "Runtime.LoadScript execution must not be hidden by the outer path.",
                      "method": "run",
                      "forbid_faults": true,
                      "ensures": []
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "concrete Runtime.LoadScript payloads are executed for custom fault-freedom proofs");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("fault");
            result["reason"]!.GetValue<string>().Should().Contain("ASSERT");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

