    [Fact]
    public void CliVerify_NeoN3SecurityProfile_FailsNep17AlwaysFalseTransferAsNonFunctional()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-false-profile.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] transferBody = Concat(
                new byte[] { (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x04 },
                new[] { (byte)NeoVm.OpCode.PUSH0 },
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset,
                totalSupplyBody: new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.RET }));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "a contract declaring NEP-17 must have at least one feasible true-return transfer path");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["violated"]!.GetValue<int>().Should().Be(2);
            root["summary"]!["unknown"]!.GetValue<int>().Should().Be(0);
            root["summary"]!["incomplete"]!.GetValue<int>().Should().BeGreaterThanOrEqualTo(2);

            var successFeasible = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.transfer_success_feasible.transfer")!;
            successFeasible["status"]!.GetValue<string>().Should().Be("violated");
            successFeasible["reason"]!.GetValue<string>().Should().Contain("no feasible non-self true-return transfer path");
            var selfTransfer = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.self_transfer_success.transfer")!;
            selfTransfer["status"]!.GetValue<string>().Should().Be("violated");
            selfTransfer["reason"]!.GetValue<string>().Should().Contain("valid self-transfer can return false");
            var coverage = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.coverage.transfer")!;
            coverage["status"]!.GetValue<string>().Should().Be("incomplete");
            coverage["reason"]!.GetValue<string>().Should().Contain("data:Any");
            var amountNonNegative = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.amount_non_negative.transfer")!;
            amountNonNegative["status"]!.GetValue<string>().Should().Be("incomplete");
            amountNonNegative["reason"]!.GetValue<string>().Should().Contain("no successful HALT path");
            amountNonNegative["reason"]!.GetValue<string>().Should().Contain("requires");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

