    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ProvesEmptyNep24RoyaltyInfoBehavior()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "royalty-nft.bin");
            string manifestPath = Path.Combine(dir, "royalty.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";

            File.WriteAllBytes(scriptPath, CompleteNep11ScriptWithExtraMethod(
                Nep11TransferBodyWithCallback(callbackBeforeTransferEvent: false, correctCallbackPayload: true),
                RoyaltyInfoEmptyArrayBody(),
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset,
                out int ownerOfOffset,
                out int tokensOfOffset,
                out int royaltyInfoOffset));
            WriteCompleteNep24Nep11Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset,
                ownerOfOffset,
                tokensOfOffset,
                royaltyInfoOffset,
                permissionsJson: """[{ "contract": "*", "methods": ["onNEP11Payment"] }]""");

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--deploy-sender-hash", deploySender,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "declaring the NEP-11 base NFT standard still surfaces unrelated NEP-11 transfer security obligations");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeFalse();
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep24.abi.*")!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["reason"]!.GetValue<string>().Should().Contain("base NFT ABI");
            var behavior = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep24.behavior.royaltyInfo")!;
            behavior["status"]!.GetValue<string>().Should().Be("proved");
            behavior["reason"]!.GetValue<string>().Should().Contain("royaltyInfo");
            behavior["reason"]!.GetValue<string>().Should().Contain("royalty entry");
            var salePrice = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep24.behavior.sale_price.royaltyInfo")!;
            salePrice["status"]!.GetValue<string>().Should().Be("proved");
            salePrice["reason"]!.GetValue<string>().Should().Contain("salePrice");
            root["results"]!.AsArray()
                .Should().NotContain(r => r!["id"]!.GetValue<string>() == "security.nep24.behavior.royalty_policy");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

