            File.WriteAllBytes(scriptPath, Concat(
                new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x03 },
                Pushdata1("received"u8.ToArray()),
                Pushdata1("1"u8.ToArray()),
                Syscall("System.Storage.Local.Put"),
                new[] { (byte)NeoVm.OpCode.RET }));
            File.WriteAllText(manifestPath, """
                {
                  "name": "ReceiverContract",
                  "groups": [],
                  "features": {},
                  "supportedstandards": ["NEP-27"],
                  "abi": {
                    "methods": [
                      {
                        "name": "onNEP17Payment",
                        "parameters": [
                          { "name": "from", "type": "Hash160" },
                          { "name": "amount", "type": "Integer" },
                          { "name": "data", "type": "Any" }
                        ],
                        "returntype": "Void",
                        "offset": 0,
                        "safe": false
                      }
                    ],
                    "events": []
                  },
                  "permissions": [],
                  "trusts": []
                }
                """);

            int exit = InvokeCli(
                "verify",
                scriptPath,
                "--manifest",
                manifestPath,
                "--profile",
                "neo-n3-security",
                "--format",
                "json",
                "--out",
                reportPath);

            exit.Should().Be(3, "passive receiver behavior excludes callback storage mutations");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var behavior = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep27.behavior.onNEP17Payment")!;
            behavior["status"]!.GetValue<string>().Should().Be("violated");
            behavior["reason"]!.GetValue<string>().Should().Contain("Storage.Put");
            behavior["failed_condition"]!.GetValue<string>().Should().Contain("no Storage.Put or Storage.Delete");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

