            byte[] transferBody = Concat(
                Nep17BalanceDeltaStorageMutation(),
                Nep17TransferNotification(),
                new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset,
                symbolBody: Concat(Pushdata1("BAD SYMBOL"u8.ToArray()), new[] { (byte)NeoVm.OpCode.RET })));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
