    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ProvesNep17CallbackAfterTransferWithPayload()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-callback-ok.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] transferBody = Concat(
                Nep17BalanceDeltaStorageMutation(),
                Nep17TransferNotification(),
                Nep17PaymentCallback(correctPayload: true, checkReturn: false),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--allow-unproved",
                "--allow-assumption-backed-proofs",
                "--format", "json",
                "--out", reportPath);

            // Review fix (#8): this fixture isolates the NEP-17 callback proof. The overall gate now
            // fails (exit 3) because the fixture also carries counterexample-backed violations
            // (negative totalSupply, non-conforming transfer return stack) that --allow-unproved no
            // longer silences; the callback obligation itself is still proved.
            exit.Should().Be(3, "the callback obligation proves, but the fixture's other violations fail the gate even under --allow-unproved");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.callback_order_payload.transfer")!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["reason"]!.GetValue<string>().Should().Contain("onNEP17Payment");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

