            callResult["status"]!.GetValue<string>().Should().Be("proved");
            callResult["reason"]!.GetValue<string>().Should().Contain("covered by manifest.permissions");
            AssertExternalReceiverSurfaceIncomplete(root, "onNEP17Payment");
