                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset,
                totalSupplyBody: new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.RET }));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset,
                permissionsJson: """[{ "contract": "*", "methods": ["onNEP17Payment"] }]""");

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "onNEP17Payment is a Void standard callback, but the receiver contract implementation is still external proof surface");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeFalse();

            var externalReturns = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.external_returns.transfer")!;
            externalReturns["status"]!.GetValue<string>().Should().Be("incomplete");
            externalReturns["reason"]!.GetValue<string>().Should().Contain("receiver callback");
            externalReturns["reason"]!.GetValue<string>().Should().Contain("target contract existence and ABI");

            var vmSurface = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_surface.transfer")!;
            vmSurface["status"]!.GetValue<string>().Should().Be("incomplete");
            vmSurface["reason"]!.GetValue<string>().Should().Contain("onNEP17Payment");
            vmSurface["reason"]!.GetValue<string>().Should().Contain("target contract existence and ABI are not modeled");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ClosesNep17VoidCallbackExternalSurfaceWithDependencyProofSummary()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-callback-void.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string summaryPath = Path.Combine(dir, "transfer.dependencies.neo-sym.proof.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] receiver = Enumerable.Repeat((byte)0x42, 20).ToArray();
            byte[] transferBody = Concat(
                Nep17BalanceDeltaStorageMutation(),
                Nep17TransferNotification(),
                AssertArgumentEqualsBytes(NeoVm.OpCode.LDARG1, receiver),
                Nep17PaymentCallback(correctPayload: true, checkReturn: false),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset,
                totalSupplyBody: new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.RET }));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(receiver)}}", "methods": ["onNEP17Payment"] }]""");
            File.WriteAllText(summaryPath, $$"""
                {
                  "version": 3,
                  "contracts": [
                    {
                      "hash": "{{HashDescriptor(receiver)}}",
                      "proof": {{DependencyProofMetadataJson(HashDescriptor(receiver))}},
                      "methods": [
                        {
                          "name": "onNEP17Payment",
                          "parameter_count": 3,
                          "parameters": [
                            { "name": "from", "type": "Hash160" },
                            { "name": "amount", "type": "Integer" },
                            { "name": "data", "type": "Any" }
                          ],
                          "return_type": "Void",
                          "initial_call_flags": 15,
                          "initial_runtime_trigger": 64,
                          "fault_free": true
                        }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--dependency-proof-summary", summaryPath,
                "--trust-dependency-proof-summaries",
                "--allow-unbound-dependency-proof-summaries",
                "--format", "json",
                "--out", reportPath);

            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            string diagnostics = string.Join(
                " | ",
                root["results"]!.AsArray()
                    .Where(r => r!["status"]!.GetValue<string>() != "proved")
                    .Select(r => $"{r!["id"]!.GetValue<string>()}: {r["status"]!.GetValue<string>()}: {r["reason"]!.GetValue<string>()}"));
            exit.Should().Be(3, $"raw-script NEP profile still has unrelated identity, coverage, or assumption gates; receiver callback surface must nevertheless be closed. {diagnostics}");
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeFalse();

            foreach (string id in new[]
            {
                "security.external_returns.transfer",
                "security.manifest_call_permissions.transfer",
                "security.vm_surface.transfer",
                "security.vm_fault_free.transfer",
            })
            {
                var result = root["results"]!.AsArray()
                    .Single(r => r!["id"]!.GetValue<string>() == id)!;
                result["status"]!.GetValue<string>().Should().NotBe("incomplete");
                result["reason"]!.GetValue<string>().Should().NotContain("target contract existence");
                result["reason"]!.GetValue<string>().Should().NotContain("target contract proof surface");
            }
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

