            string scriptPath = Path.Combine(dir, "transfer-mutates-total-supply.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] transferBody = Concat(
                Nep17BalanceDeltaStorageMutation(),
                Syscall("System.Storage.GetContext"),
                Pushdata1("totalSupply"u8.ToArray()),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                Syscall("System.Storage.Put"),
                Nep17TransferNotification(),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "a normal NEP-17 transfer must not mint or burn by mutating totalSupply storage");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.total_supply_unchanged.transfer")!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("totalSupply()");
            result["failed_condition"]!.GetValue<string>().Should().Contain("does not mutate totalSupply()");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ProvesNep17TransferLeftSlicedAccountKeysDoNotAliasTotalSupply()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-left-sliced-balance-keys.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] transferBody = Concat(
                Nep17LeftSlicedBalanceDeltaStorageMutation(),
                Nep17TransferNotification(),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset);
            WriteSecurityProfileSpec(specPath);

            _ = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--allow-unproved",
                "--format", "json",
                "--out", reportPath);

            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.total_supply_unchanged.transfer")!;
            result["status"]!.GetValue<string>().Should().Be(
                "proved",
                "LEFT(from, 20) and LEFT(to, 20) are fixed-length account keys and cannot alias the concrete totalSupply key");
            result["reason"]!.GetValue<string>().Should().NotContain("may alias totalSupply");

            var balanceDelta = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.balance_delta.transfer")!;
            balanceDelta["status"]!.GetValue<string>().Should().Be(
                "proved",
                "LEFT(from, 20) and LEFT(to, 20) are full Hash160 account keys for NEP-17 balance updates");

            var balanceOfStorage = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.balanceof_storage_consistency.balanceOf")!;
            balanceOfStorage["status"]!.GetValue<string>().Should().Be(
                "proved",
                "balanceOf(account) and transfer should normalize the same full Hash160 account storage template");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

