    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ProvesNep17TransferWhenFromArgumentWitnessIsAsserted()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-from-witness.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] transferBody = Concat(
                Nep17BalanceDeltaStorageMutation(),
                Nep17TransferNotification(),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "core NEP-17 transfer obligations prove, but receiver callback coverage is incomplete");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            AssertReceiverCallbackIncomplete(root, "security.nep17.callback_order_payload.transfer", "onNEP17Payment");
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.sender_authorized.transfer")!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["checked_paths"]!.GetValue<int>().Should().BeGreaterThan(1,
                "Any callback data is explored across representative StackItem shapes");
            result["ignored_faulted_paths"]!.GetValue<int>().Should().BeGreaterThan(0,
                "the profile treats explicit rejection paths separately from successful proofs");

            var zeroResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.zero_address.transfer")!;
            zeroResult["status"]!.GetValue<string>().Should().Be("proved");
            zeroResult["obligations_checked"]!.GetValue<int>().Should().BeGreaterThanOrEqualTo(2);

            var eventResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.transfer_event.transfer")!;
            eventResult["status"]!.GetValue<string>().Should().Be("proved");
            eventResult["obligations_checked"]!.GetValue<int>().Should().BeGreaterThanOrEqualTo(1);

            var balanceDeltaResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.balance_delta.transfer")!;
            balanceDeltaResult["status"]!.GetValue<string>().Should().Be("proved");
            balanceDeltaResult["obligations_checked"]!.GetValue<int>().Should().BeGreaterThanOrEqualTo(1);

            var insufficientBalanceResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.insufficient_balance_false.transfer")!;
            insufficientBalanceResult["status"]!.GetValue<string>().Should().Be("proved");
            insufficientBalanceResult["obligations_checked"]!.GetValue<int>().Should().BeGreaterThanOrEqualTo(1);

            var totalSupplyResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.total_supply_unchanged.transfer")!;
            totalSupplyResult["status"]!.GetValue<string>().Should().Be("proved");
            totalSupplyResult["obligations_checked"]!.GetValue<int>().Should().BeGreaterThanOrEqualTo(2);

            var abiResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep17.abi.*")!;
            abiResult["status"]!.GetValue<string>().Should().Be("proved");

            var accessResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.access_control.transfer")!;
            accessResult["status"]!.GetValue<string>().Should().Be("proved");

            var vmFaultFreeResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.transfer")!;
            vmFaultFreeResult["status"]!.GetValue<string>().Should().Be("proved_with_assumptions");
            vmFaultFreeResult["base_status"]!.GetValue<string>().Should().Be("proved");
            vmFaultFreeResult["proved_under_assumptions"]!.GetValue<bool>().Should().BeTrue();
            vmFaultFreeResult["reason"]!.GetValue<string>().Should().Contain("NEP token storage integer encoding invariant");
            var assumptions = vmFaultFreeResult["assumptions"]!.AsArray();
            assumptions.Should().ContainSingle();
            assumptions[0]!["id"]!.GetValue<string>().Should().Be("nep_token_storage_integer_encoding");
            assumptions[0]!["description"]!.GetValue<string>().Should()
                .Contain("Storage.Get values used as NEP token integers");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_NeoN3SecurityProfileDoesNotUseTokenIntegerInvariantForAuxiliaryTransferStorage()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-auxiliary-storage-integer.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] transferBody = Concat(
                Nep17BalanceDeltaStorageMutation(),
                Syscall("System.Storage.GetContext"),
                Pushdata1("pausedUntil"u8.ToArray()),
                Syscall("System.Storage.Get"),
                new[] { (byte)NeoVm.OpCode.CONVERT, SymbolicEngine.StackItemTypeCodes.Integer, (byte)NeoVm.OpCode.DROP },
                Nep17TransferNotification(),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--allow-assumption-backed-proofs",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "the NEP token storage integer invariant is limited to token balance/supply storage, not arbitrary auxiliary keys");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.transfer")!;
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("CONVERT Integer");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_RequireUnqualifiedProofsFailsOnAssumptionBackedProfileProof()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-from-witness-unqualified.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] transferBody = Concat(
                Nep17BalanceDeltaStorageMutation(),
                Nep17TransferNotification(),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--allow-unproved",
                "--require-unqualified-proofs",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "proof-grade CI can reject results that only prove under explicit assumptions");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["proved_with_assumptions"]!.GetValue<int>().Should().BeGreaterThan(0);
            root["summary"]!["all_proved_without_assumptions"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["passed"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["unproved"]!.GetValue<bool>().Should().BeTrue(
                "this fixture still has an incomplete receiver-callback obligation, but --allow-unproved should suppress that gate violation");
            root["gate_evaluation"]!["assumption_backed_proofs"]!.GetValue<int>().Should().BeGreaterThan(0);
            root["gate_evaluation"]!["policies"]!["require_unqualified_proofs"]!.GetValue<bool>().Should().BeTrue();
            root["gate_evaluation"]!["policies"]!["unproved_allowed"]!.GetValue<bool>().Should().BeTrue();
            root["gate_evaluation"]!["violations"]!.AsArray()
                .Select(v => v!.GetValue<string>())
                .Should().Contain(v => v.Contains("unqualified proofs required", StringComparison.Ordinal));

            var vmFaultFreeResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.transfer")!;
            vmFaultFreeResult["status"]!.GetValue<string>().Should().Be("proved_with_assumptions");
            vmFaultFreeResult["proved_under_assumptions"]!.GetValue<bool>().Should().BeTrue();
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

