    [Fact]
    public void CliVerify_AllowsAssumptionBackedProfileProofWhenExplicitlyPermitted()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "transfer-from-witness-qualified-allowed.bin");
            string manifestPath = Path.Combine(dir, "transfer.manifest.json");
            string specPath = Path.Combine(dir, "transfer.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] transferBody = Concat(
                Nep17BalanceDeltaStorageMutation(),
                Nep17TransferNotification(),
                new[] { (byte)NeoVm.OpCode.PUSH1 },
                new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(scriptPath, CompleteNep17Script(
                transferBody,
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset));
            WriteCompleteNep17Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset);
            WriteSecurityProfileSpec(specPath);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--allow-unproved",
                "--allow-assumption-backed-proofs",
                "--format", "json",
                "--out", reportPath);

            // Review fix (#8): the assumption-backed proof is still produced and the
            // allow-unproved / unqualified-proof policies are recorded, but this fixture also has a
            // counterexample-backed Violated result (NEP-17 totalSupply can be negative; transfer
            // return stack is non-conforming). A Violated result fails the gate (exit 3) even under
            // --allow-unproved, so the gate no longer passes on a contract with a proven violation.
            exit.Should().Be(3, "a proven violation fails the gate even with --allow-unproved and assumption-backed proofs permitted");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["proved_with_assumptions"]!.GetValue<int>().Should().BeGreaterThan(0);
            root["gate_evaluation"]!["passed"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["policies"]!["require_unqualified_proofs"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["policies"]!["unproved_allowed"]!.GetValue<bool>().Should().BeTrue();
            root["gate_evaluation"]!["violations"]!.AsArray().Should().NotBeEmpty(
                "a proven violation fails the gate even under --allow-unproved");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

