                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.owner_authorized.transfer")!;
            authResult["status"]!.GetValue<string>().Should().Be("proved");

            var invalidTokenResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.invalid_token_false.transfer")!;
            invalidTokenResult["status"]!.GetValue<string>().Should().Be("proved");

            var eventResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.transfer_event.transfer")!;
            eventResult["status"]!.GetValue<string>().Should().Be("proved");

            var ownerUpdateResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.owner_update.transfer")!;
            ownerUpdateResult["status"]!.GetValue<string>().Should().Be("proved");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

