            string manifestPath = Path.Combine(dir, "nft-mint.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, CompleteNep11ScriptWithExtraMethod(
                Nep11TransferBody(ownerWitness: true, correctEventPayload: true),
                Nep11MintSupplyOwnerMutation(emitTransferEvent: true),
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset,
                out int ownerOfOffset,
                out int tokensOfOffset,
                out int mintOffset,
                totalSupplyBody: TotalSupplyStorageRead()));
            WriteCompleteNep11ManifestWithMint(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset,
                ownerOfOffset,
                tokensOfOffset,
                mintOffset);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "the NEP-11 mint lifecycle proof is valid, while transfer callback coverage remains incomplete");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_event.mint")!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["method_offset"]!.GetValue<int>().Should().Be(mintOffset);
            result["reason"]!.GetValue<string>().Should().Contain("every successful NEP-11 mint path");

            var zeroAddressResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_zero_address.mint")!;
            zeroAddressResult["status"]!.GetValue<string>().Should().Be("proved", zeroAddressResult["reason"]!.GetValue<string>());
            zeroAddressResult["method_offset"]!.GetValue<int>().Should().Be(mintOffset);

            var balanceResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_balance.mint")!;
            balanceResult["status"]!.GetValue<string>().Should().Be("proved", balanceResult["reason"]!.GetValue<string>());
            balanceResult["method_offset"]!.GetValue<int>().Should().Be(mintOffset);

            var ownerStorageResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_owner_storage.mint")!;
            ownerStorageResult["status"]!.GetValue<string>().Should().Be("proved", ownerStorageResult["reason"]!.GetValue<string>());
            ownerStorageResult["method_offset"]!.GetValue<int>().Should().Be(mintOffset);

            var failureNoStateChangeResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_failure_no_state_change.mint")!;
            failureNoStateChangeResult["status"]!.GetValue<string>().Should().Be("proved", failureNoStateChangeResult["reason"]!.GetValue<string>());
            failureNoStateChangeResult["method_offset"]!.GetValue<int>().Should().Be(mintOffset);
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

