    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ProvesNep11BurnLifecycleTransferEvent()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "nft-burn-transfer-event.bin");
            string manifestPath = Path.Combine(dir, "nft-burn.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, CompleteNep11ScriptWithExtraMethod(
                Nep11TransferBody(ownerWitness: true, correctEventPayload: true),
                Nep11BurnSupplyOwnerMutation(emitTransferEvent: true),
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset,
                out int ownerOfOffset,
                out int tokensOfOffset,
                out int burnOffset,
                totalSupplyBody: TotalSupplyStorageRead()));
            WriteCompleteNep11ManifestWithBurn(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset,
                ownerOfOffset,
                tokensOfOffset,
                burnOffset);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "the NEP-11 burn lifecycle proof is valid, while transfer callback coverage remains incomplete");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_event.burn")!;
            result["status"]!.GetValue<string>().Should().Be("proved", result["reason"]!.GetValue<string>());
            result["method_offset"]!.GetValue<int>().Should().Be(burnOffset);
            result["reason"]!.GetValue<string>().Should().Contain("every successful NEP-11 burn path");

            var zeroAddressResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_zero_address.burn")!;
            zeroAddressResult["status"]!.GetValue<string>().Should().Be("proved", zeroAddressResult["reason"]!.GetValue<string>());
            zeroAddressResult["method_offset"]!.GetValue<int>().Should().Be(burnOffset);

            var balanceResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_balance.burn")!;
            balanceResult["status"]!.GetValue<string>().Should().Be("proved", balanceResult["reason"]!.GetValue<string>());
            balanceResult["method_offset"]!.GetValue<int>().Should().Be(burnOffset);

            var ownerStorageResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_owner_storage.burn")!;
            ownerStorageResult["status"]!.GetValue<string>().Should().Be("proved", ownerStorageResult["reason"]!.GetValue<string>());
            ownerStorageResult["method_offset"]!.GetValue<int>().Should().Be(burnOffset);

            var failureNoStateChangeResult = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.lifecycle_failure_no_state_change.burn")!;
            failureNoStateChangeResult["status"]!.GetValue<string>().Should().Be("proved", failureNoStateChangeResult["reason"]!.GetValue<string>());
            failureNoStateChangeResult["method_offset"]!.GetValue<int>().Should().Be(burnOffset);
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

