    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ProvesDivisibleNep11TransferShapeButMarksExternalSurfaceIncomplete()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "divisible-nft-transfer.bin");
            string manifestPath = Path.Combine(dir, "divisible-nft.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, CompleteDivisibleNep11Script(
                Nep11DivisibleTransferBody(guardAmount: true, updateBalances: true, assertNonSelf: true),
                out int symbolOffset,
                out int decimalsOffset,
                out int totalSupplyOffset,
                out int balanceOfOffset,
                out int ownerOfOffset,
                out int tokensOfOffset));
            WriteCompleteDivisibleNep11Manifest(
                manifestPath,
                transferOffset: 0,
                symbolOffset,
                decimalsOffset,
                totalSupplyOffset,
                balanceOfOffset,
                ownerOfOffset,
                tokensOfOffset,
                permissionsJson: """[{ "contract": "*", "methods": ["onNEP11Payment"] }]""");

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "valid divisible NEP-11 transfer obligations prove, but receiver callback callee semantics remain external surface");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeFalse();

            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.abi.*")!["status"]!.GetValue<string>()
                .Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.iterator_returns.*")!["status"]!.GetValue<string>()
                .Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.sender_authorized.transfer")!["status"]!.GetValue<string>()
                .Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.amount_non_negative.transfer")!["status"]!.GetValue<string>()
                .Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.balance_delta.transfer")!["status"]!.GetValue<string>()
                .Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.insufficient_balance_false.transfer")!["status"]!.GetValue<string>()
                .Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.ownerof_index.transfer")!["status"]!.GetValue<string>()
                .Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.transfer_event.transfer")!["status"]!.GetValue<string>()
                .Should().Be("proved");
            root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.nep11.callback_order_payload.transfer")!["status"]!.GetValue<string>()
                .Should().Be("proved");
            AssertExternalReceiverSurfaceIncomplete(root, "onNEP11Payment");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

