            File.WriteAllBytes(scriptPath, new[] { (byte)NeoVm.OpCode.RET });
            WriteManifestWithGrants(
                manifestPath,
                permissionsJson: """[{ "contract": "*", "methods": "*" }]""",
                trustsJson: "[]",
                groupsJson: "[]");

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "proof-grade profile must reject manifest permissions that grant arbitrary calls");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["violated"]!.GetValue<int>().Should().Be(1);

            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.manifest_permissions.*")!;
            result["method"]!.GetValue<string>().Should().Be("*");
            result["status"]!.GetValue<string>().Should().Be("violated");
            result["reason"]!.GetValue<string>().Should().Contain("contract=\"*\" methods=\"*\"");
            result["failed_condition"]!.GetValue<string>().Should().Contain("no fully-wildcard contract permission");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

