    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ProvesExplicitManifestGrants()
    {
        string dir = CreateTempDirectory();
        try
        {
            string nefPath = Path.Combine(dir, "balance.nef");
            string manifestPath = Path.Combine(dir, "balance.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";
            byte[] nefBytes = BuildNef("dotnet", "", Array.Empty<MethodToken>(), new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(nefPath, nefBytes);
            var manifestForHash = new ContractManifest { Name = "GrantContract" };
            byte[] contractHash = Convert.FromHexString(ContractIdentity.ComputeContractHashHex(
                NefFile.Parse(nefBytes, verifyChecksum: true),
                manifestForHash,
                ContractIdentity.ParseUInt160LittleEndianHex(deploySender)));
            var group = CreateManifestGroupSignature(contractHash);

            WriteManifestWithGrants(
                manifestPath,
                permissionsJson: """[{ "contract": "0x1111111111111111111111111111111111111111", "methods": ["balanceOf"] }]""",
                trustsJson: """["0x2222222222222222222222222222222222222222"]""",
                groupsJson: $$"""[{ "pubkey": "{{group.PublicKeyHex}}", "signature": "{{group.SignatureBase64}}" }]""");

            int exit = InvokeCli(
                "verify", nefPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--deploy-sender-hash", deploySender,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0);
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeTrue();

            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.manifest_permissions.*")!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["reason"]!.GetValue<string>().Should().Contain("narrow and pinned");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

