                "--out", reportPath);

            exit.Should().Be(3, "manifest permissions authorize a call but do not prove target contract existence, ABI, or callee fault freedom");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeFalse();
            var permission = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.manifest_call_permissions.bridge")!;
            permission["status"]!.GetValue<string>().Should().Be("proved");
            permission["obligations_checked"]!.GetValue<int>().Should().Be(2, "manifest permissions are checked for every reachable external call, not just successful HALT paths");
            permission["reason"]!.GetValue<string>().Should().Contain("reachable external contract call");
            permission["reason"]!.GetValue<string>().Should().Contain("covered by manifest.permissions");
            var surface = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_surface.bridge")!;
            surface["status"]!.GetValue<string>().Should().Be("incomplete");
            surface["reason"]!.GetValue<string>().Should().Contain("external Contract.Call");
            surface["reason"]!.GetValue<string>().Should().Contain("target contract existence");
            var faultFreedom = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.bridge")!;
            faultFreedom["status"]!.GetValue<string>().Should().Be("incomplete");
            faultFreedom["reason"]!.GetValue<string>().Should().Contain("target contract existence");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_NeoN3SecurityProfile_ProvesPermittedExternalCallWithDependencyProofSummary()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "bridge.nef");
            string manifestPath = Path.Combine(dir, "bridge.manifest.json");
            string summaryPath = Path.Combine(dir, "bridge.dependencies.neo-sym.proof.json");
            string reportPath = Path.Combine(dir, "verify.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";

            byte[] target = Enumerable.Repeat((byte)0x11, 20).ToArray();
            File.WriteAllBytes(scriptPath, BuildNef("dotnet", "", Array.Empty<MethodToken>(), AuthorizedContractCallScript(target, "balanceOf")));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: """[{ "contract": "0x1111111111111111111111111111111111111111", "methods": ["balanceOf"] }]""");
            File.WriteAllText(summaryPath, $$"""
                {
                  "version": 3,
                  "contracts": [
                    {
                      "hash": "{{HashDescriptor(target)}}",
                      "proof": {{DependencyProofMetadataJson(HashDescriptor(target))}},
                      "methods": [
                        {
                          "name": "balanceOf",
                          "parameter_count": 0,
                          "return_type": "Boolean",
                          "initial_call_flags": 1,
                          "initial_runtime_trigger": 64,
                          "fault_free": true
                        }
                      ]
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--dependency-proof-summary", summaryPath,
                "--trust-dependency-proof-summaries",
                "--allow-unbound-dependency-proof-summaries",
                "--allow-assumption-backed-proofs",
                "--deploy-sender-hash", deploySender,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0, "a matching unbound dependency proof summary can close target semantics only under an explicit offline artifact-trust assumption");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeTrue();
            root["summary"]!["all_proved_without_assumptions"]!.GetValue<bool>().Should().BeFalse();
            root["summary"]!["proved_with_assumptions"]!.GetValue<int>().Should().BeGreaterThan(0);
            root["summary"]!["incomplete"]!.GetValue<int>().Should().Be(0);

            var surface = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_surface.bridge")!;
            surface["status"]!.GetValue<string>().Should().Be("proved_with_assumptions");
            surface["assumptions"]!.AsArray()
                .Should().Contain(a => a!["id"]!.GetValue<string>() == "unbound_dependency_proof_summary");
            surface["reason"]!.GetValue<string>().Should().NotContain("target contract existence");

            var faultFreedom = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.bridge")!;
            faultFreedom["status"]!.GetValue<string>().Should().Be("proved_with_assumptions");
            faultFreedom["assumptions"]!.AsArray()
                .Should().Contain(a => a!["id"]!.GetValue<string>() == "unbound_dependency_proof_summary");
            faultFreedom["reason"]!.GetValue<string>().Should().NotContain("target contract existence");

            var summaryProvenance = root["meta"]!["inputs"]!["dependency_proof_summaries"]!.AsArray().Single()!;
            summaryProvenance["path"]!.GetValue<string>().Should().Be(summaryPath);
            summaryProvenance["sha256"]!.GetValue<string>().Should().HaveLength(64);
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

