    [Fact]
    public void DependencyProofSummaryCoverageRequiresExplicitTrustByDefault()
    {
        byte[] target = Enumerable.Repeat((byte)0x11, 20).ToArray();
        string json = $$"""
            {
              "version": 3,
              "contracts": [
                {
                  "hash": "{{HashDescriptor(target)}}",
                  "proof": {{DependencyProofMetadataJson(HashDescriptor(target))}},
                  "methods": [
                    {
                      "name": "balanceOf",
                      "parameter_count": 0,
                      "return_type": "Boolean",
                      "initial_call_flags": 1,
                      "initial_runtime_trigger": 64,
                      "fault_free": true
                    }
                  ]
                }
              ]
            }
            """;

        var untrusted = DependencyProofSummarySet.FromJson(json);
        var untrustedCoverage = untrusted.CheckExternalCall(
            target,
            "balanceOf",
            parameterCount: 0,
            hasReturnValue: true,
            expectedReturnType: "Boolean",
            callFlags: NeoCallFlags.ReadStates,
            callFlagsDynamic: false,
            runtimeTrigger: NeoTriggerTypes.Application,
            requireExternalSmt: false);

        untrustedCoverage.IsCovered.Should().BeFalse();
        untrustedCoverage.Reason.Should().Contain("not explicitly trusted");

        var trusted = DependencyProofSummarySet.FromJson(json, trustedForExternalCalls: true);
        var trustedCoverage = trusted.CheckExternalCall(
            target,
            "balanceOf",
            parameterCount: 0,
            hasReturnValue: true,
            expectedReturnType: "Boolean",
            callFlags: NeoCallFlags.ReadStates,
            callFlagsDynamic: false,
            runtimeTrigger: NeoTriggerTypes.Application,
            requireExternalSmt: false);

        trustedCoverage.IsCovered.Should().BeTrue();
    }

    [Fact]
    public void DependencyProofSummaryCoverageRejectsVoidReturnForReturnValuedCalltWithoutInferredType()
    {
        byte[] target = Enumerable.Repeat((byte)0x11, 20).ToArray();
        var summary = DependencyProofSummarySet.FromJson($$"""
            {
              "version": 3,
              "contracts": [
                {
                  "hash": "{{HashDescriptor(target)}}",
                  "proof": {{DependencyProofMetadataJson(HashDescriptor(target))}},
                  "methods": [
                    {
                      "name": "balanceOf",
                      "parameter_count": 0,
                      "return_type": "Void",
                      "initial_call_flags": 1,
                      "initial_runtime_trigger": 64,
                      "fault_free": true
                    }
                  ]
                }
              ]
            }
            """, trustedForExternalCalls: true);

        var coverage = summary.CheckExternalCall(
            target,
            "balanceOf",
            parameterCount: 0,
            hasReturnValue: true,
            expectedReturnType: null,
            callFlags: NeoCallFlags.ReadStates,
            callFlagsDynamic: false,
            runtimeTrigger: NeoTriggerTypes.Application,
            requireExternalSmt: false,
            returnValueDeclaredByMethodToken: true);

        coverage.IsCovered.Should().BeFalse(
            "a return-valued CALLT MethodToken must be backed by a dependency ABI method that really returns a stack item");
        coverage.Reason.Should().Contain("CALLT");
        coverage.Reason.Should().Contain("Void");
    }

    [Fact]
    public void DependencyProofSummaryConstructorDefaultsToUntrusted()
    {
        byte[] target = Enumerable.Repeat((byte)0x11, 20).ToArray();
        var parsedTrusted = DependencyProofSummarySet.FromJson($$"""
            {
              "version": 3,
              "contracts": [
                {
                  "hash": "{{HashDescriptor(target)}}",
                  "proof": {{DependencyProofMetadataJson(HashDescriptor(target))}},
                  "methods": [
                    {
                      "name": "balanceOf",
                      "parameter_count": 0,
                      "return_type": "Boolean",
                      "initial_call_flags": 1,
                      "initial_runtime_trigger": 64,
                      "fault_free": true
                    }
                  ]
                }
              ]
            }
            """, trustedForExternalCalls: true);

        var directlyConstructed = new DependencyProofSummarySet(parsedTrusted.Contracts);
        var coverage = directlyConstructed.CheckExternalCall(
            target,
            "balanceOf",
            parameterCount: 0,
            hasReturnValue: true,
            expectedReturnType: "Boolean",
            callFlags: NeoCallFlags.ReadStates,
            callFlagsDynamic: false,
            runtimeTrigger: NeoTriggerTypes.Application,
            requireExternalSmt: false);

        coverage.IsCovered.Should().BeFalse("public library construction must fail closed unless the caller explicitly trusts summaries");
        coverage.Reason.Should().Contain("not explicitly trusted");
    }

