        coverage.IsCovered.Should().BeFalse();
        coverage.Reason.Should().Contain("runtime trigger");
        coverage.Reason.Should().Contain("Verification");
        coverage.Reason.Should().Contain("Application");
    }

    [Fact]
    public void DependencyProofSummaryCoverageRequiresTransitiveDependencyProofSummaryClosure()
    {
        byte[] target = Enumerable.Repeat((byte)0x11, 20).ToArray();
        string missingTransitiveSummaryHash = new('c', 64);
        var summary = DependencyProofSummarySet.FromJson($$"""
            {
              "version": 3,
              "contracts": [
                {
                  "hash": "{{HashDescriptor(target)}}",
                  "proof": {{DependencyProofMetadataJson(HashDescriptor(target), missingTransitiveSummaryHash)}},
                  "methods": [
                    {
                      "name": "balanceOf",
                      "parameter_count": 0,
                      "return_type": "Boolean",
                      "initial_call_flags": 1,
                      "initial_runtime_trigger": 64,
                      "fault_free": true
                    }
                  ]
                }
              ]
            }
            """, trustedForExternalCalls: true);

        var coverage = summary.CheckExternalCall(
            target,
            "balanceOf",
            parameterCount: 0,
            hasReturnValue: true,
            expectedReturnType: "Boolean",
            callFlags: NeoCallFlags.ReadStates,
            callFlagsDynamic: false,
            runtimeTrigger: NeoTriggerTypes.Application,
            requireExternalSmt: false);

        coverage.IsCovered.Should().BeFalse();
        coverage.Reason.Should().Contain("transitive dependency proof summary");
        coverage.Reason.Should().Contain(missingTransitiveSummaryHash);
    }

