            File.WriteAllText(transitivePath, $$"""
                {
                  "version": 3,
                  "contracts": [
                    {
                      "hash": "{{HashDescriptor(transitiveTarget)}}",
                      "proof": {{DependencyProofMetadataJson(HashDescriptor(transitiveTarget))}},
                      "methods": [
                        {
                          "name": "helper",
                          "parameter_count": 0,
                              "return_type": "Boolean",
                              "initial_call_flags": 1,
                              "initial_runtime_trigger": 64,
                              "fault_free": true
                        }
                      ]
                    }
                  ]
                }
                """);
            string transitiveSummaryHash = Sha256File(transitivePath);
            File.WriteAllText(dependencyPath, $$"""
                {
                  "version": 3,
                  "contracts": [
                    {
                      "hash": "{{HashDescriptor(target)}}",
                      "proof": {{DependencyProofMetadataJson(HashDescriptor(target), transitiveSummaryHash)}},
                      "methods": [
                        {
                          "name": "balanceOf",
                          "parameter_count": 0,
                              "return_type": "Boolean",
                              "initial_call_flags": 1,
                              "initial_runtime_trigger": 64,
                              "fault_free": true
                        }
                      ]
                    }
                  ]
                }
