    [Fact]
    public void DependencyProofSummaryCoverageAllowsFixedByteReturnsForByteStringConsumersButRejectsReverse()
    {
        byte[] target = Enumerable.Repeat((byte)0x11, 20).ToArray();
        var summary = DependencyProofSummarySet.FromJson($$"""
            {
              "version": 3,
              "contracts": [
                {
                  "hash": "{{HashDescriptor(target)}}",
                  "proof": {{DependencyProofMetadataJson(HashDescriptor(target))}},
                  "methods": [
                    {
                      "name": "getPublicKey",
                      "parameter_count": 0,
                          "return_type": "PublicKey",
                          "initial_call_flags": 1,
                          "initial_runtime_trigger": 64,
                          "fault_free": true
                    },
                    {
                      "name": "getBytes",
                      "parameter_count": 0,
                          "return_type": "ByteString",
                          "initial_call_flags": 1,
                          "initial_runtime_trigger": 64,
                          "fault_free": true
                    }
                  ]
                }
              ]
            }
            """, trustedForExternalCalls: true);

        var fixedByteAsBytes = summary.CheckExternalCall(
            target,
            "getPublicKey",
            parameterCount: 0,
            hasReturnValue: true,
            expectedReturnType: "ByteString",
            callFlags: NeoCallFlags.ReadStates,
            callFlagsDynamic: false,
            runtimeTrigger: NeoTriggerTypes.Application,
            requireExternalSmt: false);
        var bytesAsFixedByte = summary.CheckExternalCall(
            target,
            "getBytes",
            parameterCount: 0,
            hasReturnValue: true,
            expectedReturnType: "PublicKey",
            callFlags: NeoCallFlags.ReadStates,
            callFlagsDynamic: false,
            runtimeTrigger: NeoTriggerTypes.Application,
            requireExternalSmt: false);

        fixedByteAsBytes.IsCovered.Should().BeTrue("a proof-grade PublicKey return is safe to consume as bytes");
        bytesAsFixedByte.IsCovered.Should().BeFalse("a generic ByteString proof does not prove the ECPoint shape required by PublicKey");
    }

    [Fact]
    public void CliVerify_EmitsDependencyProofSummaryFromVerifiedNefAndConsumerUsesIt()
    {
        string dir = CreateTempDirectory();
        try
        {
            string dependencyNefPath = Path.Combine(dir, "dependency.nef");
            string dependencyManifestPath = Path.Combine(dir, "dependency.manifest.json");
            string dependencyReportPath = Path.Combine(dir, "dependency.verify.json");
            string summaryPath = Path.Combine(dir, "dependency.neo-sym.proof.json");
            string bridgeScriptPath = Path.Combine(dir, "bridge.nef");
            string bridgeManifestPath = Path.Combine(dir, "bridge.manifest.json");
            string bridgeReportPath = Path.Combine(dir, "bridge.verify.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";

            byte[] dependencyNef = BuildNef("neo-sym-test", "", Array.Empty<MethodToken>(), ReturnBool(true));
            File.WriteAllBytes(dependencyNefPath, dependencyNef);
            WriteMethodManifest(
                dependencyManifestPath,
                "DependencyContract",
                "balanceOf",
                methodOffset: 0,
                safe: true,
                returnType: "Boolean");

            var dependencyManifest = ContractManifest.FromFile(dependencyManifestPath);
            string dependencyHash = ContractIdentity.ComputeContractHashHex(
                NefFile.Parse(dependencyNef, verifyChecksum: true),
                dependencyManifest,
                ContractIdentity.ParseUInt160LittleEndianHex(deploySender));
            byte[] dependencyHashBytes = Convert.FromHexString(dependencyHash);

            int dependencyExit = InvokeCli(
                "verify", dependencyNefPath,
                "--manifest", dependencyManifestPath,
                "--profile", "neo-n3-security",
                "--deploy-sender-hash", deploySender,
                "--emit-dependency-proof-summary", summaryPath,
                "--format", "json",
                "--out", dependencyReportPath);

            dependencyExit.Should().Be(0);
            File.Exists(summaryPath).Should().BeTrue();
            var summary = JsonNode.Parse(File.ReadAllText(summaryPath))!;
            summary["version"]!.GetValue<int>().Should().Be(3);
            var contract = summary["contracts"]!.AsArray().Single()!;
            contract["hash"]!.GetValue<string>().Should().Be("0x" + dependencyHash);
            var proof = contract["proof"]!;
            proof["tool"]!.GetValue<string>().Should().Be("Neo.SymbolicExecutor.Verify");
            proof["source_profile"]!.GetValue<string>().Should().Be("neo-n3-security");
            proof["gate_passed"]!.GetValue<bool>().Should().BeTrue();
            proof["require_unqualified_proofs"]!.GetValue<bool>().Should().BeTrue();
            proof["assumption_backed_proofs"]!.GetValue<int>().Should().Be(0);
            proof["program_sha256"]!.GetValue<string>().Should().HaveLength(64);
            proof["manifest_sha256"]!.GetValue<string>().Should().HaveLength(64);
            proof["contract_hash"]!.GetValue<string>().Should().Be("0x" + dependencyHash);
            proof["deploy_sender_hash"]!.GetValue<string>().Should().Be(deploySender);
            proof["nef_checksum_hex"]!.GetValue<string>().Should().StartWith("0x");
            var method = contract["methods"]!.AsArray().Single()!;
            method["name"]!.GetValue<string>().Should().Be("balanceOf");
            method["parameter_count"]!.GetValue<int>().Should().Be(0);
            method["return_type"]!.GetValue<string>().Should().Be("Boolean");
            method["initial_call_flags"]!.GetValue<int>().Should().Be(NeoCallFlags.All);
            method["initial_runtime_trigger"]!.GetValue<int>().Should().Be(NeoTriggerTypes.Application);
            method["fault_free"]!.GetValue<bool>().Should().BeTrue();

            WriteNefScript(bridgeScriptPath, AuthorizedContractCallWithAllFlagsScript(dependencyHashBytes, "balanceOf"));
            WriteExternalCallManifest(
                bridgeManifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(dependencyHashBytes)}}", "methods": ["balanceOf"] }]""");

            int bridgeExit = InvokeCli(
                "verify", bridgeScriptPath,
                "--manifest", bridgeManifestPath,
                "--profile", "neo-n3-security",
                "--dependency-proof-summary", summaryPath,
                "--dependency-proof-artifact", $"{HashDescriptor(dependencyHashBytes)}={dependencyNefPath},{dependencyManifestPath}",
                "--trust-dependency-proof-summaries",
                "--deploy-sender-hash", deploySender,
                "--format", "json",
                "--out", bridgeReportPath);

            bridgeExit.Should().Be(0, "the emitted dependency proof summary should close the bridge contract's external-call proof obligations");
            var bridgeRoot = JsonNode.Parse(File.ReadAllText(bridgeReportPath))!;
            bridgeRoot["summary"]!["all_proved"]!.GetValue<bool>().Should().BeTrue();
            bridgeRoot["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_surface.bridge")!
                ["status"]!.GetValue<string>().Should().Be("proved");
            bridgeRoot["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_fault_free.bridge")!
                ["status"]!.GetValue<string>().Should().Be("proved");
            var artifactProvenanceNode = bridgeRoot["meta"]!["inputs"]!["dependency_proof_artifacts"];
            artifactProvenanceNode.Should().NotBeNull("verified dependency proof artifacts must remain auditable from the report");
            var artifactProvenance = artifactProvenanceNode!.AsArray().Single()!;
            artifactProvenance["contract_hash"]!.GetValue<string>().Should().Be(HashDescriptor(dependencyHashBytes));
            artifactProvenance["program_path"]!.GetValue<string>().Should().Be(dependencyNefPath);
            artifactProvenance["program_sha256"]!.GetValue<string>().Should().Be(Sha256File(dependencyNefPath));
            artifactProvenance["manifest_path"]!.GetValue<string>().Should().Be(dependencyManifestPath);
            artifactProvenance["manifest_sha256"]!.GetValue<string>().Should().Be(Sha256File(dependencyManifestPath));
            var proofPolicy = bridgeRoot["meta"]!["inputs"]!["dependency_proof_policy"];
            proofPolicy.Should().NotBeNull("audit reports must state whether dependency proof summaries were trusted and artifact-bound");
            proofPolicy!["trusted_for_external_calls"]!.GetValue<bool>().Should().BeTrue();
            proofPolicy["artifact_binding_required"]!.GetValue<bool>().Should().BeTrue();
            proofPolicy["unbound_summaries_allowed"]!.GetValue<bool>().Should().BeFalse();
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_RejectsDependencyProofSummaryWhenRuntimeTriggerMismatches()
    {
        string dir = CreateTempDirectory();
        try
        {
            string dependencyNefPath = Path.Combine(dir, "verify-dependency.nef");
            string dependencyManifestPath = Path.Combine(dir, "verify-dependency.manifest.json");
            string dependencyReportPath = Path.Combine(dir, "verify-dependency.verify.json");
            string summaryPath = Path.Combine(dir, "verify-dependency.neo-sym.proof.json");
            string bridgeScriptPath = Path.Combine(dir, "bridge.nef");
            string bridgeManifestPath = Path.Combine(dir, "bridge.manifest.json");
            string bridgeReportPath = Path.Combine(dir, "bridge.verify.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";

            byte[] verifyOnlyScript = Concat(
                Syscall("System.Runtime.GetTrigger"),
                new[] { (byte)NeoVm.OpCode.PUSHINT8, (byte)NeoTriggerTypes.Verification, (byte)NeoVm.OpCode.NUMEQUAL, (byte)NeoVm.OpCode.ASSERT },
                ReturnBool(true));
            byte[] dependencyNef = BuildNef("neo-sym-test", "", Array.Empty<MethodToken>(), verifyOnlyScript);
            File.WriteAllBytes(dependencyNefPath, dependencyNef);
            WriteMethodManifest(
                dependencyManifestPath,
                "VerifyDependencyContract",
                "verify",
                methodOffset: 0,
                safe: true,
                returnType: "Boolean");

            var dependencyManifest = ContractManifest.FromFile(dependencyManifestPath);
            string dependencyHash = ContractIdentity.ComputeContractHashHex(
                NefFile.Parse(dependencyNef, verifyChecksum: true),
                dependencyManifest,
                ContractIdentity.ParseUInt160LittleEndianHex(deploySender));
            byte[] dependencyHashBytes = Convert.FromHexString(dependencyHash);

            int dependencyExit = InvokeCli(
                "verify", dependencyNefPath,
                "--manifest", dependencyManifestPath,
                "--profile", "neo-n3-security",
                "--deploy-sender-hash", deploySender,
                "--emit-dependency-proof-summary", summaryPath,
                "--format", "json",
                "--out", dependencyReportPath);

            dependencyExit.Should().Be(0);
            var emitted = JsonNode.Parse(File.ReadAllText(summaryPath))!;
            emitted["contracts"]!.AsArray().Single()!["methods"]!.AsArray().Single()!["initial_runtime_trigger"]!
                .GetValue<int>().Should().Be(NeoTriggerTypes.Verification);

            WriteNefScript(bridgeScriptPath, AuthorizedContractCallWithAllFlagsScript(dependencyHashBytes, "verify"));
            WriteExternalCallManifest(
                bridgeManifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(dependencyHashBytes)}}", "methods": ["verify"] }]""");

            int bridgeExit = InvokeCli(
                "verify", bridgeScriptPath,
                "--manifest", bridgeManifestPath,
                "--profile", "neo-n3-security",
                "--dependency-proof-summary", summaryPath,
                "--dependency-proof-artifact", $"{HashDescriptor(dependencyHashBytes)}={dependencyNefPath},{dependencyManifestPath}",
                "--trust-dependency-proof-summaries",
                "--deploy-sender-hash", deploySender,
                "--format", "json",
                "--out", bridgeReportPath);

            bridgeExit.Should().Be(3, "a Verification-trigger proof for verify() must not close an Application-trigger external call");
            var bridgeRoot = JsonNode.Parse(File.ReadAllText(bridgeReportPath))!;
            var surface = bridgeRoot["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_surface.bridge")!;
            surface["status"]!.GetValue<string>().Should().Be("incomplete");
            surface["reason"]!.GetValue<string>().Should().Contain("runtime trigger");
            surface["reason"]!.GetValue<string>().Should().Contain("Verification");
            surface["reason"]!.GetValue<string>().Should().Contain("Application");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

