            string dependencyNefPath = Path.Combine(dir, "dependency.nef");
            string dependencyManifestPath = Path.Combine(dir, "dependency.manifest.json");
            string summaryPath = Path.Combine(dir, "dependency.neo-sym.proof.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";

            byte[] dependencyNef = BuildNef("neo-sym-test", "", Array.Empty<MethodToken>(), ReturnBool(true));
            File.WriteAllBytes(dependencyNefPath, dependencyNef);
            WriteMethodManifest(
                dependencyManifestPath,
                "DependencyContract",
                "balanceOf",
                methodOffset: 0,
                safe: true,
                returnType: "Boolean");

            var nef = NefFile.Parse(dependencyNef, verifyChecksum: true);
            var manifest = ContractManifest.FromFile(dependencyManifestPath);
            string contractHash = ContractIdentity.ComputeContractHashHex(
                nef,
                manifest,
                ContractIdentity.ParseUInt160LittleEndianHex(deploySender));
            string contractHashDescriptor = "0x" + contractHash;
            var results = ImmutableArray.Create(
                DependencyProfileResult("security.vm_surface.balanceOf"),
                DependencyProfileResult("security.vm_fault_free.balanceOf"),
                DependencyProfileResult("security.abi_return_type.balanceOf"));
            var report = new VerificationReport(
                new VerificationMeta
                {
                    Inputs = new VerificationInputProvenance(
                        dependencyNefPath,
                        Sha256File(dependencyNefPath),
                        dependencyManifestPath,
                        Sha256File(dependencyManifestPath),
                        SpecPath: null,
                        SpecSha256: null),
                    EngineOptions = VerificationEngineOptions.From(ExecutionOptions.Default),
                    ContractIdentity = new VerificationContractIdentity(
                        Status: "computed",
                        SourceKind: "nef",
                        ManifestName: "DependencyContract",
                        DeploySenderHash: deploySender,
                        NefChecksum: nef.Checksum,
                        NefChecksumHex: $"0x{nef.Checksum:x8}",
                        ContractHash: contractHash,
                        Reason: null),
                },
                VerificationSummary.FromResults(results),
                results,
                new VerificationGateEvaluation(
                    Passed: true,
                    Policies: new VerificationGatePolicy(
                        FailOnUnproved: true,
                        RequireExternalSmt: false,
                        RequireUnqualifiedProofs: true),
                    Unproved: false,
                    ExternalSmtRequiredButMissing: false,
                    Violations: ImmutableArray<string>.Empty,
                    AssumptionBackedProofs: 0));
            var summary = DependencyProofSummarySet.FromVerifiedContract(
                manifest,
                contractHashDescriptor,
                report);
            var root = JsonNode.Parse(summary.ToJson())!;
            root["contracts"]!.AsArray().Single()!["methods"]!.AsArray().Single()!["name"] = "notInManifest";
            File.WriteAllText(summaryPath, root.ToJsonString());

            Action bind = () => DependencyProofSummarySet.FromFiles(
                new[] { summaryPath },
                artifactBindings: new[]
                {
                    new DependencyProofArtifactBinding(
                        contractHashDescriptor,
                        dependencyNefPath,
                        dependencyManifestPath),
                });

            bind.Should().Throw<FormatException>()
                .WithMessage("*notInManifest*bound manifest*");

            static VerificationPropertyResult DependencyProfileResult(string id) => new(
                Id: id,
                Method: "balanceOf",
                Description: null,
                Status: VerificationStatus.Proved,
                CheckedPaths: 1,
                IgnoredFaultedPaths: 0,
                StoppedPaths: 0,
                ObligationsChecked: 1,
                Reason: "proved",
                FailedCondition: null,
                Counterexample: null,
                MethodOffset: 0,
                SourceProfile: "neo-n3-security");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_RejectsDependencyProofSummaryWhenBoundArtifactsComputeDifferentContractHash()
    {
        string dir = CreateTempDirectory();
        try
        {
            string dependencyNefPath = Path.Combine(dir, "dependency.nef");
            string dependencyManifestPath = Path.Combine(dir, "dependency.manifest.json");
            string dependencyReportPath = Path.Combine(dir, "dependency.verify.json");
            string summaryPath = Path.Combine(dir, "dependency.neo-sym.proof.json");
            string bridgeScriptPath = Path.Combine(dir, "bridge.nef");
            string bridgeManifestPath = Path.Combine(dir, "bridge.manifest.json");
            string bridgeReportPath = Path.Combine(dir, "bridge.verify.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";
            const string forgedHash = "0xabababababababababababababababababababab";

            byte[] dependencyNef = BuildNef("neo-sym-test", "", Array.Empty<MethodToken>(), ReturnBool(true));
            File.WriteAllBytes(dependencyNefPath, dependencyNef);
            WriteMethodManifest(
                dependencyManifestPath,
                "DependencyContract",
                "balanceOf",
                methodOffset: 0,
                safe: true,
                returnType: "Boolean");

            int dependencyExit = InvokeCli(
                "verify", dependencyNefPath,
                "--manifest", dependencyManifestPath,
                "--profile", "neo-n3-security",
                "--deploy-sender-hash", deploySender,
                "--emit-dependency-proof-summary", summaryPath,
                "--format", "json",
                "--out", dependencyReportPath);

            dependencyExit.Should().Be(0);
            var summary = JsonNode.Parse(File.ReadAllText(summaryPath))!;
            var contract = summary["contracts"]!.AsArray().Single()!;
            contract["hash"] = forgedHash;
            contract["proof"]!["contract_hash"] = forgedHash;
            File.WriteAllText(summaryPath, summary.ToJsonString());

            byte[] forgedHashBytes = Convert.FromHexString(forgedHash[2..]);
            WriteNefScript(bridgeScriptPath, AuthorizedContractCallWithAllFlagsScript(forgedHashBytes, "balanceOf"));
            WriteExternalCallManifest(
                bridgeManifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(forgedHashBytes)}}", "methods": ["balanceOf"] }]""");

            int bridgeExit = InvokeCli(
                "verify", bridgeScriptPath,
                "--manifest", bridgeManifestPath,
                "--profile", "neo-n3-security",
                "--dependency-proof-summary", summaryPath,
                "--dependency-proof-artifact", $"{forgedHash}={dependencyNefPath},{dependencyManifestPath}",
                "--trust-dependency-proof-summaries",
                "--deploy-sender-hash", deploySender,
                "--format", "json",
                "--out", bridgeReportPath);

            bridgeExit.Should().Be(3, "artifact binding must prove the NEF and manifest compute the claimed Neo N3 contract hash");
            AssertDependencyProofInputFailureReport(
                bridgeReportPath,
                "contract_hash mismatch");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

