    [Fact]
    public void CliVerify_RejectsDependencyProofSummaryEmissionFromCustomSpecSecurityIds()
    {
        string dir = CreateTempDirectory();
        try
        {
            string dependencyNefPath = Path.Combine(dir, "dependency.nef");
            string dependencyManifestPath = Path.Combine(dir, "dependency.manifest.json");
            string dependencySpecPath = Path.Combine(dir, "dependency.neo-sym.spec.json");
            string dependencyReportPath = Path.Combine(dir, "dependency.verify.json");
            string summaryPath = Path.Combine(dir, "dependency.neo-sym.proof.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";

            byte[] dependencyNef = BuildNef("neo-sym-test", "", Array.Empty<MethodToken>(), ReturnBool(true));
            File.WriteAllBytes(dependencyNefPath, dependencyNef);
            WriteMethodManifest(
                dependencyManifestPath,
                "DependencyContract",
                "balanceOf",
                methodOffset: 0,
                safe: true,
                returnType: "Boolean");
            File.WriteAllText(dependencySpecPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "security.vm_surface.balanceOf",
                      "description": "A custom spec must not masquerade as a built-in profile surface proof.",
                      "method": "balanceOf",
                      "ensures": [
                        { "return": true, "op": "==", "value": true }
                      ]
                    },
                    {
                      "id": "security.vm_fault_free.balanceOf",
                      "description": "A custom spec must not masquerade as a built-in profile fault-freedom proof.",
                      "method": "balanceOf",
                      "forbid_faults": true,
                      "ensures": []
                    }
                  ]
                }
                """);

            int dependencyExit = InvokeCli(
                "verify", dependencyNefPath,
                "--manifest", dependencyManifestPath,
                "--spec", dependencySpecPath,
                "--deploy-sender-hash", deploySender,
                "--emit-dependency-proof-summary", summaryPath,
                "--format", "json",
                "--out", dependencyReportPath);

            dependencyExit.Should().Be(1, "dependency proof summaries must be emitted only from built-in neo-n3-security profile results");
            File.Exists(summaryPath).Should().BeFalse();
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

