            DependencyProfileResult("security.abi_return_type.check"));
        string transitiveSummaryHash = new string('c', 64);
        var report = new VerificationReport(
            new VerificationMeta
            {
                Inputs = new VerificationInputProvenance(
                    "bridge.nef",
                    new string('a', 64),
                    "bridge.manifest.json",
                    new string('b', 64),
                    SpecPath: null,
                    SpecSha256: null,
                    DependencyProofSummaries: ImmutableArray.Create(
                        new VerificationDependencyProofSummaryProvenance(
                            "/private/build/callee-summary.json",
                            transitiveSummaryHash)),
                    DependencyProofPolicy: new VerificationDependencyProofPolicy(
                        TrustedForExternalCalls: true,
                        ArtifactBindingRequired: true,
                        UnboundSummariesAllowed: false)),
                EngineOptions = VerificationEngineOptions.From(ExecutionOptions.Default),
                ContractIdentity = new VerificationContractIdentity(
                    Status: "resolved",
                    SourceKind: "nef",
                    ManifestName: "BridgeDependency",
                    DeploySenderHash: "0102030405060708090a0b0c0d0e0f1011121314",
                    NefChecksum: 0,
                    NefChecksumHex: "0x00000000",
                    ContractHash: "1111111111111111111111111111111111111111",
                    Reason: null),
            },
            VerificationSummary.FromResults(results),
            results,
            new VerificationGateEvaluation(
                Passed: true,
                Policies: new VerificationGatePolicy(
                    FailOnUnproved: true,
                    RequireExternalSmt: false,
                    RequireUnqualifiedProofs: true),
                Unproved: false,
                ExternalSmtRequiredButMissing: false,
                Violations: ImmutableArray<string>.Empty,
                AssumptionBackedProofs: 0));

        var summary = DependencyProofSummarySet.FromVerifiedContract(
            manifest,
            "0x1111111111111111111111111111111111111111",
            report);

        var transitive = summary.Contracts.Single().Proof.DependencyProofSummaries
            .Should().ContainSingle().Subject;
        transitive.Sha256.Should().Be(transitiveSummaryHash);
        var json = summary.ToJson();
        json.Should().Contain("dependency_proof_summaries");
        json.Should().Contain(transitiveSummaryHash);
        json.Should().NotContain("/private/build");
        DependencyProofSummarySet.FromJson(json)
            .Contracts.Single().Proof.DependencyProofSummaries.Single().Sha256.Should().Be(transitiveSummaryHash);

        static VerificationPropertyResult DependencyProfileResult(string id) => new(
            Id: id,
            Method: "check",
            Description: null,
            Status: VerificationStatus.Proved,
            CheckedPaths: 1,
            IgnoredFaultedPaths: 0,
            StoppedPaths: 0,
            ObligationsChecked: 1,
            Reason: "proved",
            FailedCondition: null,
            Counterexample: null,
            MethodOffset: 0,
            SourceProfile: "neo-n3-security");
    }

