    [Fact]
    public void CliVerify_ForbidFaultsMarksExternalContractCallWithoutTargetAbiIncomplete()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "bridge-custom-external.bin");
            string manifestPath = Path.Combine(dir, "bridge-custom-external.manifest.json");
            string specPath = Path.Combine(dir, "bridge-custom-external.neo-sym.spec.json");
            string reportPath = Path.Combine(dir, "verify.json");

            byte[] target = Enumerable.Repeat((byte)0x22, 20).ToArray();
            File.WriteAllBytes(scriptPath, ExternalContractCallScript(target, "balanceOf"));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(target)}}", "methods": ["balanceOf"] }]""");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "external_contract_call_no_fault",
                      "description": "Custom fault-freedom proofs need target contract existence and ABI coverage.",
                      "method": "bridge",
                      "forbid_faults": true,
                      "ensures": []
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "manifest permissions do not prove external callee existence, ABI, or implementation semantics");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("external Contract.Call");
            result["reason"]!.GetValue<string>().Should().Contain("target contract");
            result["reason"]!.GetValue<string>().Should().Contain("ABI");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

