                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(target)}}", "methods": ["balanceOf"] }]""");
            File.WriteAllText(specPath, """
                {
                  "version": 1,
                  "properties": [
                    {
                      "id": "callt_no_fault",
                      "description": "CALLT custom proofs need target contract existence and ABI coverage.",
                      "method": "bridge",
                      "forbid_faults": true,
                      "ensures": []
                    }
                  ]
                }
                """);

            int exit = InvokeCli(
                "verify", nefPath,
                "--manifest", manifestPath,
                "--spec", specPath,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "NEF MethodToken metadata names the call but does not prove the external contract's ABI or implementation semantics");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray().Single()!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("CALLT");
            result["reason"]!.GetValue<string>().Should().Contain("target contract");
            result["reason"]!.GetValue<string>().Should().Contain("ABI");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

