            string reportPath = Path.Combine(dir, "verify.json");

            byte[] target = Enumerable.Range(0, 20).Select(i => (byte)(0x20 + i)).ToArray();
            File.WriteAllBytes(
                nefPath,
                BuildNef(
                    "neo-sym-test",
                    "",
                    new[] { new MethodToken(target, "balanceOf", ParametersCount: 1, HasReturnValue: true, CallFlags: 0x01) },
                    AuthorizedCalltScript()));
            WriteExternalCallManifest(
                manifestPath,
                permissionsJson: $$"""[{ "contract": "{{HashDescriptor(target)}}", "methods": ["balanceOf"] }]""");

            int exit = InvokeCli(
                "verify", nefPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "CALLT manifest permissions do not prove target contract existence, ABI, or callee fault freedom");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeFalse();

            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.manifest_call_permissions.bridge")!;
            result["status"]!.GetValue<string>().Should().Be("proved");
            result["obligations_checked"]!.GetValue<int>().Should().Be(2, "manifest permissions are checked for every reachable CALLT external call, not just successful HALT paths");
            result["reason"]!.GetValue<string>().Should().Contain("reachable external contract call");
            var surface = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.vm_surface.bridge")!;
            surface["status"]!.GetValue<string>().Should().Be("incomplete");
            surface["reason"]!.GetValue<string>().Should().Contain("CALLT");
            surface["reason"]!.GetValue<string>().Should().Contain("target contract existence");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

