    [Fact]
    public void CliVerify_ReportIncludesProofProvenance()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "balance.nef");
            string manifestPath = Path.Combine(dir, "balance.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");
            const string deploySender = "0102030405060708090a0b0c0d0e0f1011121314";

            File.WriteAllBytes(scriptPath, BuildNef("dotnet", "", Array.Empty<MethodToken>(), new[] { (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(manifestPath, "BalanceContract", "balanceOf", methodOffset: 0);

            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--deploy-sender-hash", deploySender,
                "--max-paths", "7",
                "--smt-timeout", "1234",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0);
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var meta = root["meta"]!;
            meta["inputs"]!["program_path"]!.GetValue<string>().Should().Be(scriptPath);
            meta["inputs"]!["program_sha256"]!.GetValue<string>().Should().HaveLength(64);
            meta["inputs"]!["manifest_path"]!.GetValue<string>().Should().Be(manifestPath);
            meta["inputs"]!["manifest_sha256"]!.GetValue<string>().Should().HaveLength(64);
            meta["inputs"]!["spec_path"].Should().BeNull();
            meta["smt_solver_version"]!.GetValue<string>().Should().NotBeNullOrWhiteSpace();
            meta["smt_timeout_ms"]!.GetValue<int>().Should().Be(1234);
            meta["smt_bytes_bound"]!.GetValue<int>().Should().Be(64);
            meta["require_external_smt"]!.GetValue<bool>().Should().BeFalse();
            meta["engine_options"]!["max_paths"]!.GetValue<int>().Should().Be(7);
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

