            string manifestPath = Path.Combine(dir, "operand-entry.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, new[]
            {
                (byte)NeoVm.OpCode.PUSHDATA1,
                (byte)0x01,
                (byte)NeoVm.OpCode.RET,
                (byte)NeoVm.OpCode.ABORT,
            });
            WriteMethodManifest(manifestPath, "StaleManifest", "stale", methodOffset: 2, returnType: "Void");

            int exit = InvokeCli(
                "verify",
                scriptPath,
                "--manifest",
                manifestPath,
                "--profile",
                "neo-n3-security",
                "--format",
                "json",
                "--out",
                reportPath);

            exit.Should().Be(3, "profile proofs must execute declared ABI method entries, not JIT-decoded operand bytes");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.coverage.stale")!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("decoded instruction boundary");
            result["method_offset"]!.GetValue<int>().Should().Be(2);
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_WritesStructuredReportForInvalidManifestAbi()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "invalid-manifest.bin");
            string manifestPath = Path.Combine(dir, "invalid-manifest.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(scriptPath, new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllText(manifestPath, """
                {
                  "name": "InvalidManifest",
                  "groups": [],
                  "features": {},
                  "supportedstandards": [],
                  "abi": {
                    "methods": [
                      { "name": "main", "parameters": [], "returntype": "Void", "safe": false }
                    ],
                    "events": []
                  },
                  "permissions": [],
                  "trusts": []
                }
                """);

            int exit = InvokeCli(
                "verify",
                scriptPath,
                "--manifest",
                manifestPath,
                "--profile",
                "neo-n3-security",
                "--format",
                "json",
                "--out",
                reportPath);

            exit.Should().Be(3, "invalid proof-critical manifest ABI fields should fail the verification gate with a machine-readable report");
            File.Exists(reportPath).Should().BeTrue();
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["meta"]!["coverage_incomplete"]!.GetValue<bool>().Should().BeTrue();
            root["meta"]!["coverage_reason"]!.GetValue<string>().Should().Contain("abi.methods[0].offset");
            root["meta"]!["inputs"]!["manifest_path"]!.GetValue<string>().Should().Be(manifestPath);
            root["meta"]!["inputs"]!["manifest_sha256"]!.GetValue<string>().Should().HaveLength(64);
            root["summary"]!["incomplete"]!.GetValue<int>().Should().Be(1);
            root["gate_evaluation"]!["passed"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["violations"]!.AsArray()
                .Select(v => v!.GetValue<string>())
                .Should().Contain(v => v.Contains("manifest", StringComparison.OrdinalIgnoreCase)
                    && v.Contains("abi.methods[0].offset", StringComparison.Ordinal));
            var result = root["results"]!.AsArray().Single()!;
            result["id"]!.GetValue<string>().Should().Be("security.manifest.parse");
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("abi.methods[0].offset");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_ReportMarksNefContractIdentitySenderRequired()
    {
        string dir = CreateTempDirectory();
        try
        {
            string nefPath = Path.Combine(dir, "balance.nef");
            string manifestPath = Path.Combine(dir, "balance.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            File.WriteAllBytes(nefPath, BuildNef("dotnet", "", Array.Empty<MethodToken>(), new[] { (byte)NeoVm.OpCode.RET }));
            WriteMethodManifest(manifestPath, "BalanceContract", "balanceOf", methodOffset: 0);

            int exit = InvokeCli(
                "verify", nefPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "a NEF profile proof is not proof-grade until the deployed Neo N3 contract hash is bound with --deploy-sender-hash");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var identity = root["meta"]!["contract_identity"]!;
            identity["status"]!.GetValue<string>().Should().Be("sender_required");
            identity["source_kind"]!.GetValue<string>().Should().Be("nef");
            identity["manifest_name"]!.GetValue<string>().Should().Be("BalanceContract");
            identity["nef_checksum"]!.GetValue<long>().Should().BeGreaterThan(0);
            identity["nef_checksum_hex"]!.GetValue<string>().Should().StartWith("0x");
            identity["contract_hash"].Should().BeNull();
            identity["reason"]!.GetValue<string>().Should().Contain("--deploy-sender-hash");
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == "security.contract_identity.*")!;
            result["status"]!.GetValue<string>().Should().Be("incomplete");
            result["reason"]!.GetValue<string>().Should().Contain("--deploy-sender-hash");
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_ReportIncludesNefContractHashWhenDeploySenderProvided()
    {
        string dir = CreateTempDirectory();
        try
        {
            string nefPath = Path.Combine(dir, "balance.nef");
            string manifestPath = Path.Combine(dir, "balance.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");
            const string sender = "0102030405060708090a0b0c0d0e0f1011121314";

            byte[] nefBytes = BuildNef("dotnet", "", Array.Empty<MethodToken>(), new[] { (byte)NeoVm.OpCode.RET });
            File.WriteAllBytes(nefPath, nefBytes);
            WriteMethodManifest(manifestPath, "BalanceContract", "balanceOf", methodOffset: 0);
            var manifest = ContractManifest.FromFile(manifestPath);
            var nef = NefFile.Parse(nefBytes, verifyChecksum: true);
            string expectedHash = ContractIdentity.ComputeContractHashHex(
                nef,
                manifest,
                ContractIdentity.ParseUInt160LittleEndianHex(sender));

            int exit = InvokeCli(
                "verify", nefPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--deploy-sender-hash", "0x" + sender,
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(0);
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            var identity = root["meta"]!["contract_identity"]!;
            identity["status"]!.GetValue<string>().Should().Be("computed");
            identity["deploy_sender_hash"]!.GetValue<string>().Should().Be(sender);
            identity["contract_hash"]!.GetValue<string>().Should().Be(expectedHash);
            identity["contract_hash"]!.GetValue<string>().Should().HaveLength(40);
            identity["reason"].Should().BeNull();
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliVerify_RequireExternalSmtFailsOnPortableFallback()
    {
        string dir = CreateTempDirectory();
        try
        {
            string scriptPath = Path.Combine(dir, "balance.nef");
            string manifestPath = Path.Combine(dir, "balance.manifest.json");
            string reportPath = Path.Combine(dir, "verify.json");

            WriteNefScript(scriptPath, new[] { (byte)NeoVm.OpCode.RET });
            WriteMethodManifest(manifestPath, "BalanceContract", "balanceOf", methodOffset: 0);

            using var restore = WithEnvironmentVariable(
                "NEO_SYMBOLIC_EXECUTOR_Z3",
                Path.Combine(dir, "missing-z3"));
            int exit = InvokeCli(
                "verify", scriptPath,
                "--manifest", manifestPath,
                "--profile", "neo-n3-security",
                "--deploy-sender-hash", ProofDeploySenderHash,
                "--require-external-smt",
                "--format", "json",
                "--out", reportPath);

            exit.Should().Be(3, "proof-grade CI can require an external SMT solver instead of the portable fallback");
            var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
            root["summary"]!["all_proved"]!.GetValue<bool>().Should().BeTrue();
            root["meta"]!["smt_available"]!.GetValue<bool>().Should().BeFalse();
            root["meta"]!["require_external_smt"]!.GetValue<bool>().Should().BeTrue();
            root["meta"]!["smt_solver_version"]!.GetValue<string>().Should().Contain("portable fallback");
            root["gate_evaluation"]!["passed"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["policies"]!["require_external_smt"]!.GetValue<bool>().Should().BeTrue();
            root["gate_evaluation"]!["policies"]!["fail_on_unproved"]!.GetValue<bool>().Should().BeTrue();
            root["gate_evaluation"]!["policies"]!["unproved_allowed"]!.GetValue<bool>().Should().BeFalse();
            root["gate_evaluation"]!["violations"]!.AsArray()
                .Select(v => v!.GetValue<string>())
                .Should().Contain(v => v.Contains("external SMT", StringComparison.Ordinal));
        }
        finally
        {
            Directory.Delete(dir, recursive: true);
        }
    }

    [Fact]
    public void CliHelp_DocumentsFormalVerifyCommand()
    {
        var cliProgram = Assembly.LoadFrom(Path.Combine(AppContext.BaseDirectory, "neo-sym.dll"))
            .GetType("Neo.SymbolicExecutor.Cli.Program", throwOnError: true)!;
        var printUsage = cliProgram.GetMethod("PrintUsage", BindingFlags.NonPublic | BindingFlags.Static)!;

        using var output = new StringWriter();
        var originalOut = Console.Out;
        try
        {
            Console.SetOut(output);
            printUsage.Invoke(null, null);
        }
        finally
        {
            Console.SetOut(originalOut);
        }

        string help = output.ToString();
        help.Should().Contain("neo-sym verify");
        help.Should().Contain("--spec <path.neo-sym.json>");
        help.Should().Contain("--profile neo-n3-security");
        help.Should().Contain("--dependency-proof-summary <path.json>");
        help.Should().Contain("--dependency-proof-artifact <hash=program,manifest>");
        help.Should().Contain("--trust-dependency-proof-summaries");
        help.Should().Contain("--allow-unbound-dependency-proof-summaries");
        help.Should().Contain("--emit-dependency-proof-summary <path>");
        help.Should().Contain("--deploy-sender-hash");
        help.Should().Contain("--require-external-smt");
        help.Should().Contain("--require-unqualified-proofs");
        help.Should().Contain("--allow-assumption-backed-proofs");
        help.Should().Contain("--fail-on-unproved");
    }

    private static int InvokeCli(params string[] args)
    {
        var cliProgram = Assembly.LoadFrom(Path.Combine(AppContext.BaseDirectory, "neo-sym.dll"))
            .GetType("Neo.SymbolicExecutor.Cli.Program", throwOnError: true)!;
        var main = cliProgram.GetMethod("Main", BindingFlags.Public | BindingFlags.Static)!;
        return (int)main.Invoke(null, new object[] { args })!;
    }

    private static string DependencyProofMetadataJson(string contractHash, params string[] dependencySummaryHashes)
    {
        string dependencySummariesJson = dependencySummaryHashes.Length == 0
            ? ""
            : """
              ,
                        "dependency_proof_summaries": [
              """ + string.Join(
                    ",",
                    dependencySummaryHashes.Select(hash => $$"""

                          { "sha256": "{{hash}}" }
                    """)) + """

                        ]
              """;

        return $$"""
        {
          "tool": "Neo.SymbolicExecutor.Verify",
          "tool_version": "0.0.0-test",
          "source_profile": "neo-n3-security",
          "gate_passed": true,
          "require_external_smt": false,
          "require_unqualified_proofs": true,
          "assumption_backed_proofs": 0,
          "program_sha256": "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa",
          "manifest_sha256": "bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb",
          "contract_hash": "{{contractHash}}",
          "deploy_sender_hash": "0102030405060708090a0b0c0d0e0f1011121314",
          "nef_checksum_hex": "0x00000000",
          "smt_solver_version": "test"
          {{dependencySummariesJson}}
        }
        """;
    }

    private static byte[] PushBool(bool value) =>
        new[] { (byte)(value ? NeoVm.OpCode.PUSHT : NeoVm.OpCode.PUSHF) };

    private static byte[] ReturnBool(bool value) =>
        new[] { (byte)(value ? NeoVm.OpCode.PUSHT : NeoVm.OpCode.PUSHF), (byte)NeoVm.OpCode.RET };

