                (byte)NeoVm.OpCode.PACK,
                (byte)NeoVm.OpCode.RET,
            });

    private static byte[] RoyaltyInfoSalePriceMaxEntryArrayBody() =>
        Concat(
            new[]
            {
                (byte)NeoVm.OpCode.INITSLOT,
                (byte)0x00,
                (byte)0x03,
                (byte)NeoVm.OpCode.LDARG2,
                (byte)NeoVm.OpCode.PUSH0,
                (byte)NeoVm.OpCode.MAX,
            },
            Pushdata1(Enumerable.Range(0, 20).Select(i => (byte)(0x70 + i)).ToArray()),
            new[]
            {
                (byte)NeoVm.OpCode.PUSH2,
                (byte)NeoVm.OpCode.PACK,
                (byte)NeoVm.OpCode.PUSH1,
                (byte)NeoVm.OpCode.PACK,
