            });

    private static byte[] Nep24RoyaltySettlementNotificationBody(bool correctPayload) =>
        Concat(
            new[]
            {
                (byte)NeoVm.OpCode.INITSLOT,
                (byte)0x00,
                (byte)0x05,
            },
            Pushdata1("RoyaltiesTransferred"u8.ToArray()),
            correctPayload
                ? new[]
                {
                    (byte)NeoVm.OpCode.LDARG4,
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.LDARG3,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LDARG1,
                    (byte)NeoVm.OpCode.PUSH5,
                    (byte)NeoVm.OpCode.PACK,
                }
                : new[]
                {
                    (byte)NeoVm.OpCode.LDARG4,
                    (byte)NeoVm.OpCode.LDARG3,
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LDARG1,
                    (byte)NeoVm.OpCode.PUSH5,
                    (byte)NeoVm.OpCode.PACK,
                },
            Syscall("System.Runtime.Notify"),
            new[] { (byte)NeoVm.OpCode.RET });

    private static byte[] NormalizeBooleanReturnInstructions(byte[] body)
    {
        byte[] normalized = body.ToArray();
        for (int i = 0; i + 1 < normalized.Length; i++)
        {
            if (normalized[i + 1] != (byte)NeoVm.OpCode.RET)
            {
                continue;
            }

            if (normalized[i] == (byte)NeoVm.OpCode.PUSH0)
            {
                normalized[i] = (byte)NeoVm.OpCode.PUSHF;
            }
            else if (normalized[i] == (byte)NeoVm.OpCode.PUSH1)
            {
                normalized[i] = (byte)NeoVm.OpCode.PUSHT;
            }
        }

        return normalized;
    }

    private static JsonNode AssertReceiverCallbackIncomplete(JsonNode root, string resultId, string callbackName)
    {
        var result = root["results"]!.AsArray()
            .Single(r => r!["id"]!.GetValue<string>() == resultId)!;
        result["status"]!.GetValue<string>().Should().Be("incomplete");
        result["reason"]!.GetValue<string>().Should().Contain(callbackName);
        result["reason"]!.GetValue<string>().Should().Contain("receiver");
        result["reason"]!.GetValue<string>().Should().Contain("contract");
        return result;
    }

    private static void AssertExternalReceiverSurfaceIncomplete(JsonNode root, string callbackName)
    {
        foreach (string resultId in new[] { "security.vm_fault_free.transfer", "security.vm_surface.transfer" })
        {
            var result = root["results"]!.AsArray()
                .Single(r => r!["id"]!.GetValue<string>() == resultId)!;
            result["status"]!.GetValue<string>().Should().Be("incomplete", result.ToJsonString());
            result["reason"]!.GetValue<string>().Should().Contain(callbackName);
            result["reason"]!.GetValue<string>().Should().Contain("target contract existence and ABI are not modeled");
        }
    }

    private static JsonNode AssertDependencyProofInputFailureReport(string reportPath, string expectedReasonFragment)
    {
        File.Exists(reportPath).Should().BeTrue();
        var root = JsonNode.Parse(File.ReadAllText(reportPath))!;
        root["meta"]!["coverage_incomplete"]!.GetValue<bool>().Should().BeTrue();
        root["meta"]!["coverage_reason"]!.GetValue<string>().Should().Contain(expectedReasonFragment);
        root["gate_evaluation"]!["passed"]!.GetValue<bool>().Should().BeFalse();
        root["gate_evaluation"]!["violations"]!.AsArray()
            .Select(v => v!.GetValue<string>())
            .Should().Contain(v => v.Contains(expectedReasonFragment, StringComparison.Ordinal));
        var result = root["results"]!.AsArray().Single()!;
        result["id"]!.GetValue<string>().Should().Be("security.dependency_proof.input");
        result["status"]!.GetValue<string>().Should().Be("incomplete");
        result["reason"]!.GetValue<string>().Should().Contain(expectedReasonFragment);
        return root;
    }

