    private static void WriteTransferManifest(string path, int methodOffset)
    {
        File.WriteAllText(path, $$"""
            {
              "name": "TransferContract",
              "groups": [],
              "features": {},
              "supportedstandards": ["NEP-17"],
              "abi": {
                "methods": [
                  {
                    "name": "transfer",
                    "parameters": [
                      { "name": "amount", "type": "Integer" }
                    ],
                    "returntype": "Boolean",
                    "offset": {{methodOffset}},
                    "safe": false
                  }
                ],
                "events": []
              },
              "permissions": [],
              "trusts": []
            }
            """);
    }

