    private static void WriteCompleteNep11Manifest(
        string path,
        int transferOffset,
        int symbolOffset,
        int decimalsOffset,
        int totalSupplyOffset,
        int balanceOfOffset,
        int ownerOfOffset,
        int tokensOfOffset,
        string permissionsJson = "[]",
        string tokenIdType = "ByteString")
    {
        WriteNep11ManifestWithOptionalAbi(
            path,
            transferOffset,
            symbolOffset,
            decimalsOffset,
            totalSupplyOffset,
            balanceOfOffset,
            ownerOfOffset,
            tokensOfOffset,
            includeProperties: true,
            includeTokens: true,
            permissionsJson,
            tokenIdType: tokenIdType);
    }

    private static void WriteCompleteNep24Nep11Manifest(
        string path,
        int transferOffset,
        int symbolOffset,
        int decimalsOffset,
        int totalSupplyOffset,
        int balanceOfOffset,
        int ownerOfOffset,
        int tokensOfOffset,
        int royaltyInfoOffset,
        string permissionsJson = "[]",
        string tokenIdType = "ByteString")
    {
        WriteCompleteNep11Manifest(
            path,
            transferOffset,
            symbolOffset,
            decimalsOffset,
            totalSupplyOffset,
            balanceOfOffset,
            ownerOfOffset,
            tokensOfOffset,
            permissionsJson,
            tokenIdType);

        var manifest = JsonNode.Parse(File.ReadAllText(path))!.AsObject();
        manifest["name"] = "RoyaltyNftContract";
        manifest["supportedstandards"]!.AsArray().Add("NEP-24");

        var abi = manifest["abi"]!.AsObject();
        abi["methods"]!.AsArray().Add(new JsonObject
        {
            ["name"] = "royaltyInfo",
            ["parameters"] = new JsonArray
            {
                new JsonObject { ["name"] = "tokenId", ["type"] = tokenIdType },
                new JsonObject { ["name"] = "royaltyToken", ["type"] = "Hash160" },
                new JsonObject { ["name"] = "salePrice", ["type"] = "Integer" },
            },
            ["returntype"] = "Array",
            ["offset"] = royaltyInfoOffset,
            ["safe"] = true,
        });
        abi["events"]!.AsArray().Add(new JsonObject
        {
            ["name"] = "RoyaltiesTransferred",
            ["parameters"] = new JsonArray
            {
                new JsonObject { ["name"] = "royaltyToken", ["type"] = "Hash160" },
                new JsonObject { ["name"] = "royaltyRecipient", ["type"] = "Hash160" },
                new JsonObject { ["name"] = "buyer", ["type"] = "Hash160" },
                new JsonObject { ["name"] = "tokenId", ["type"] = tokenIdType },
                new JsonObject { ["name"] = "amount", ["type"] = "Integer" },
            },
        });

        File.WriteAllText(path, manifest.ToJsonString());
    }

    private static void AddNep24SettlementMethod(string path, int offset)
    {
        var manifest = JsonNode.Parse(File.ReadAllText(path))!.AsObject();
        manifest["abi"]!["methods"]!.AsArray().Add(new JsonObject
        {
            ["name"] = "settleRoyalty",
            ["parameters"] = new JsonArray
            {
                new JsonObject { ["name"] = "tokenId", ["type"] = "ByteString" },
                new JsonObject { ["name"] = "royaltyToken", ["type"] = "Hash160" },
                new JsonObject { ["name"] = "royaltyRecipient", ["type"] = "Hash160" },
                new JsonObject { ["name"] = "buyer", ["type"] = "Hash160" },
                new JsonObject { ["name"] = "amount", ["type"] = "Integer" },
            },
            ["returntype"] = "Void",
            ["offset"] = offset,
            ["safe"] = false,
        });
        File.WriteAllText(path, manifest.ToJsonString());
    }

