    private static void WriteNep11ManifestWithOptionalAbi(
        string path,
        int transferOffset,
        int symbolOffset,
        int decimalsOffset,
        int totalSupplyOffset,
        int balanceOfOffset,
        int ownerOfOffset,
        int tokensOfOffset,
        bool includeProperties,
        bool includeTokens,
        string permissionsJson = "[]",
        string extraMethodsJson = "",
        string tokenIdType = "ByteString")
    {
        int propertiesOffset = tokensOfOffset + Nep11TokensOfStubLength;
        int tokensOffset = propertiesOffset + Nep11PropertiesStubLength;
        string propertiesMethod = includeProperties
            ? $$"""
                  {
                    "name": "properties",
                    "parameters": [
                      { "name": "tokenId", "type": "{{tokenIdType}}" }
                    ],
                    "returntype": "Map",
                    "offset": {{propertiesOffset}},
                    "safe": true
                  },
            """
            : "";
        string tokensMethod = includeTokens
            ? $$"""
                  {
                    "name": "tokens",
                    "parameters": [],
                    "returntype": "InteropInterface",
                    "offset": {{tokensOffset}},
                    "safe": true
                  },
            """
            : "";

        File.WriteAllText(path, $$"""
            {
              "name": "Nep11Contract",
              "groups": [],
              "features": {},
              "supportedstandards": ["NEP-11"],
              "abi": {
                "methods": [
                  {
                    "name": "symbol",
                    "parameters": [],
                    "returntype": "String",
                    "offset": {{symbolOffset}},
                    "safe": true
                  },
                  {
                    "name": "decimals",
                    "parameters": [],
                    "returntype": "Integer",
                    "offset": {{decimalsOffset}},
                    "safe": true
                  },
                  {
                    "name": "totalSupply",
                    "parameters": [],
                    "returntype": "Integer",
                    "offset": {{totalSupplyOffset}},
                    "safe": true
                  },
                  {
                    "name": "balanceOf",
                    "parameters": [
                      { "name": "owner", "type": "Hash160" }
                    ],
                    "returntype": "Integer",
                    "offset": {{balanceOfOffset}},
                    "safe": true
                  },
                  {
                    "name": "ownerOf",
                    "parameters": [
                      { "name": "tokenId", "type": "{{tokenIdType}}" }
                    ],
                    "returntype": "Hash160",
                    "offset": {{ownerOfOffset}},
                    "safe": true
                  },
                  {
                    "name": "tokensOf",
                    "parameters": [
                      { "name": "owner", "type": "Hash160" }
                    ],
                    "returntype": "InteropInterface",
                    "offset": {{tokensOfOffset}},
                    "safe": true
                  },
            {{propertiesMethod}}
            {{tokensMethod}}
            {{extraMethodsJson}}
                  {
                    "name": "transfer",
                    "parameters": [
                      { "name": "to", "type": "Hash160" },
                      { "name": "tokenId", "type": "{{tokenIdType}}" },
                      { "name": "data", "type": "Any" }
                    ],
                    "returntype": "Boolean",
                    "offset": {{transferOffset}},
                    "safe": false
                  }
                ],
                "events": [
                  {
                    "name": "Transfer",
                    "parameters": [
                      { "name": "from", "type": "Hash160" },
                      { "name": "to", "type": "Hash160" },
                      { "name": "amount", "type": "Integer" },
                      { "name": "tokenId", "type": "{{tokenIdType}}" }
                    ]
                  }
                ]
              },
              "permissions": {{permissionsJson}},
              "trusts": []
            }
            """);
    }

