    private static void WriteSpec(string path)
    {
        File.WriteAllText(path, """
            {
              "version": 1,
              "properties": [
                {
                  "id": "amount_non_negative",
                  "description": "Successful transfer paths must have constrained amount to non-negative.",
                  "method": "transfer",
                  "ensures": [
                    { "arg": "amount", "op": ">=", "value": 0 }
                  ]
                }
              ]
            }
            """);
    }

    private static void WriteIntegerAbiRangeSpec(string path)
    {
        File.WriteAllText(path, $$"""
            {
              "version": 1,
              "properties": [
                {
                  "id": "amount_inside_neovm_integer_range",
                  "description": "Manifest Integer parameters are bounded by NeoVM's StackItem integer range.",
                  "method": "transfer",
                  "ensures": [
                    { "arg": "amount", "op": ">=", "value": "{{Expr.NeoVmIntegerMin}}" },
                    { "arg": "amount", "op": "<=", "value": "{{Expr.NeoVmIntegerMax}}" }
                  ]
                }
              ]
            }
            """);
    }

    private static void WriteVariableByteAbiSizeSpec(string path)
    {
        File.WriteAllText(path, $$"""
            {
              "version": 1,
              "properties": [
                {
                  "id": "variable_bytes_inside_neovm_item_size",
                  "description": "Manifest ByteString-like parameters stay inside NeoVM's stack item size domain.",
                  "method": "accept",
                  "ensures": [
                    { "arg": "data", "metric": "size", "op": ">=", "value": 0 },
                    { "arg": "data", "metric": "size", "op": "<=", "value": {{ExecutionOptions.Default.MaxItemSize}} },
                    { "arg": "payload", "metric": "size", "op": ">=", "value": 0 },
                    { "arg": "payload", "metric": "size", "op": "<=", "value": {{ExecutionOptions.Default.MaxItemSize}} },
                    { "arg": "label", "metric": "size", "op": ">=", "value": 0 },
                    { "arg": "label", "metric": "size", "op": "<=", "value": {{ExecutionOptions.Default.MaxItemSize}} }
                  ]
                }
              ]
            }
            """);
    }

    private static void WriteReturnScopedAmountSpec(string path)
    {
        File.WriteAllText(path, """
            {
              "version": 1,
              "properties": [
                {
                  "id": "true_return_amount_non_negative",
                  "description": "Only true-return transfer paths are required to prove non-negative amount.",
                  "method": "transfer",
                  "requires": [
                    { "return": true, "op": "==", "value": true }
                  ],
                  "ensures": [
                    { "arg": "amount", "op": ">=", "value": 0 }
                  ]
                }
              ]
            }
            """);
