    private static void WriteForbidFaultsSpec(string path, bool requireNonNegative)
    {
        string requires = requireNonNegative
            ? """
                  "requires": [
                    { "arg": "amount", "op": ">=", "value": 0 }
                  ],
            """
            : "";
        File.WriteAllText(path, $$"""
            {
              "version": 1,
              "properties": [
                {
                  "id": "amount_no_fault",
                  "description": "Transfer must not fault for inputs allowed by requires.",
                  "method": "transfer",
                  "forbid_faults": true,
            {{requires}}      "ensures": []
                }
              ]
            }
            """);
    }

