    private static void WriteForbidFaultsAmountEqualsSpec(string path, int value)
    {
        File.WriteAllText(path, $$"""
            {
              "version": 1,
              "properties": [
                {
                  "id": "amount_no_fault",
                  "description": "Transfer must not fault when amount is exactly the allowed value.",
                  "method": "transfer",
