    private static byte[] SymbolicAddOverflowScript() =>
        Concat(
            new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x00, (byte)0x01 },
            PushInt256((BigInteger.One << 255) - BigInteger.One),
            new[]
            {
                (byte)NeoVm.OpCode.LDARG0,
                (byte)NeoVm.OpCode.ADD,
                (byte)NeoVm.OpCode.RET,
            });

    private static byte[] PushInt256(BigInteger value)
    {
        byte[] payload = new byte[32];
        byte[] encoded = value.ToByteArray(isUnsigned: false, isBigEndian: false);
        encoded.CopyTo(payload, 0);
        return Concat(new[] { (byte)NeoVm.OpCode.PUSHINT256 }, payload);
    }

