    private static byte[] ByteStringPickItemScript(bool guardIndex)
    {
        byte[] prefix = { (byte)NeoVm.OpCode.INITSLOT, 0x00, 0x02 };
        byte[] guard = guardIndex
            ? new[]
            {
                (byte)NeoVm.OpCode.LDARG1,
                (byte)NeoVm.OpCode.PUSH0,
                (byte)NeoVm.OpCode.GE,
                (byte)NeoVm.OpCode.JMPIF,
                (byte)0x04,
                (byte)NeoVm.OpCode.PUSH0,
                (byte)NeoVm.OpCode.RET,
                (byte)NeoVm.OpCode.LDARG1,
                (byte)NeoVm.OpCode.LDARG0,
                (byte)NeoVm.OpCode.SIZE,
                (byte)NeoVm.OpCode.LT,
                (byte)NeoVm.OpCode.JMPIF,
                (byte)0x04,
                (byte)NeoVm.OpCode.PUSH0,
                (byte)NeoVm.OpCode.RET,
            }
            : Array.Empty<byte>();
        return Concat(
            prefix,
            guard,
            new[]
            {
                (byte)NeoVm.OpCode.LDARG0,
                (byte)NeoVm.OpCode.LDARG1,
                (byte)NeoVm.OpCode.PICKITEM,
                (byte)NeoVm.OpCode.RET,
            });
    }

