    private static byte[] GasBalanceOfNativeCall(byte[] accountScript) =>
        Concat(
            Pushdata1(GasTokenHashBytes()),
            Pushdata1("balanceOf"u8.ToArray()),
            new[] { (byte)NeoVm.OpCode.PUSH1 },
            accountScript,
            new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.PACK },
            Syscall("System.Contract.Call"));

    private static byte[] NativeCalltArguments(string nativeContract, string nativeMethod)
    {
        if (nativeContract == "GASToken" && nativeMethod == "balanceOf")
            return Pushdata1(new byte[20]);
        if (nativeContract == "LedgerContract" && nativeMethod == "getBlock")
            return PushInt32(17);
        if (nativeContract == "PolicyContract" && nativeMethod == "getFeePerByte")
            return Array.Empty<byte>();

        throw new ArgumentOutOfRangeException($"{nativeContract}.{nativeMethod}");
    }

