    private static byte[] Nep17MixedInsufficientBalanceFalseAndTrueReturn() =>
        Concat(
            new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x02, (byte)0x04 },
            new[] { (byte)NeoVm.OpCode.LDARG0 },
            Syscall("System.Runtime.CheckWitness"),
            new[] { (byte)NeoVm.OpCode.ASSERT },
            new[] { (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.GE, (byte)NeoVm.OpCode.ASSERT },
            Nep17ZeroAddressAssertions(),
            new[] { (byte)NeoVm.OpCode.LDARG0, (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.EQUAL, (byte)NeoVm.OpCode.NOT, (byte)NeoVm.OpCode.ASSERT },
            Syscall("System.Storage.GetContext"),
            new[] { (byte)NeoVm.OpCode.LDARG0 },
            Syscall("System.Storage.Get"),
            new[] { (byte)NeoVm.OpCode.CONVERT, SymbolicEngine.StackItemTypeCodes.Integer, (byte)NeoVm.OpCode.STLOC0 },
            IfConditionThen(
                new[]
                {
                    (byte)NeoVm.OpCode.LDLOC0,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LT,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.PUSH1,
                    (byte)NeoVm.OpCode.NUMEQUAL,
                    (byte)NeoVm.OpCode.BOOLAND,
                },
                ReturnBool(false)),
            IfConditionThen(
                new[]
                {
                    (byte)NeoVm.OpCode.LDLOC0,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LT,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.PUSH1,
                    (byte)NeoVm.OpCode.NUMEQUAL,
                    (byte)NeoVm.OpCode.NOT,
                    (byte)NeoVm.OpCode.BOOLAND,
                },
                ReturnBool(true)),
            ReturnBool(true));

    private static byte[] Nep17BalanceDeltaStorageMutationBody(
        bool wrongToDelta = false,
        bool requireSufficientBalance = true,
        bool allowSelfTransfer = true,
        bool returnFalseOnInsufficientBalance = true)
    {
        byte[] nonSelfMutation = Concat(
            Syscall("System.Storage.GetContext"),
            new[] { (byte)NeoVm.OpCode.LDARG0 },
            Syscall("System.Storage.Get"),
            new[] { (byte)NeoVm.OpCode.CONVERT, SymbolicEngine.StackItemTypeCodes.Integer, (byte)NeoVm.OpCode.STLOC0 },
            requireSufficientBalance
                ? returnFalseOnInsufficientBalance
                    ? new[] { (byte)NeoVm.OpCode.LDLOC0, (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.GE, (byte)NeoVm.OpCode.JMPIF, (byte)0x04, (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.RET }
                    : new[] { (byte)NeoVm.OpCode.LDLOC0, (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.GE, (byte)NeoVm.OpCode.ASSERT }
                : Array.Empty<byte>(),
            Syscall("System.Storage.GetContext"),
            new[] { (byte)NeoVm.OpCode.LDARG1 },
            Syscall("System.Storage.Get"),
            StorageValueOrZeroToLocal1(),
            Syscall("System.Storage.GetContext"),
            new[] { (byte)NeoVm.OpCode.LDARG0, (byte)NeoVm.OpCode.LDLOC0, (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.SUB },
            Syscall("System.Storage.Put"),
            Syscall("System.Storage.GetContext"),
            new[] { (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.LDLOC1, (byte)NeoVm.OpCode.LDARG2, (byte)(wrongToDelta ? NeoVm.OpCode.SUB : NeoVm.OpCode.ADD) },
            Syscall("System.Storage.Put"));

        return Concat(
            new[] { (byte)NeoVm.OpCode.LDARG0 },
            Syscall("System.Runtime.CheckWitness"),
            new[] { (byte)NeoVm.OpCode.ASSERT },
            new[] { (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.GE, (byte)NeoVm.OpCode.ASSERT },
            Nep17ZeroAddressAssertions(),
            allowSelfTransfer
                ? new[] { (byte)NeoVm.OpCode.LDARG0, (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.EQUAL, (byte)NeoVm.OpCode.JMPIF, checked((byte)(nonSelfMutation.Length + 2)) }
                : new[] { (byte)NeoVm.OpCode.LDARG0, (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.EQUAL, (byte)NeoVm.OpCode.NOT, (byte)NeoVm.OpCode.ASSERT },
            nonSelfMutation);
    }

