    private static byte[] Nep17TransferWithUnknownSyscallBranch()
    {
        byte[] unknownSyscall = new[]
        {
            (byte)NeoVm.OpCode.SYSCALL,
            (byte)0xFF,
            (byte)0xFF,
            (byte)0xFF,
            (byte)0xFF,
        };
        byte[] safeTransfer = Concat(
            Nep17BalanceDeltaStorageMutationBody(),
            Nep17TransferNotification(),
            new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.RET });

        return Concat(
            new[]
            {
                (byte)NeoVm.OpCode.INITSLOT, (byte)0x02, (byte)0x04,
                (byte)NeoVm.OpCode.LDARG2,
                (byte)NeoVm.OpCode.PUSH0,
                (byte)NeoVm.OpCode.NUMEQUAL,
                (byte)NeoVm.OpCode.JMPIF,
                (byte)(unknownSyscall.Length + 2),
            },
            unknownSyscall,
            safeTransfer);
    }

