            Pushdata1(Enumerable.Range(0, 20).Select(i => (byte)(0xC0 + i)).ToArray()),
            Syscall("System.Runtime.CheckWitness"),
            new[] { (byte)NeoVm.OpCode.ASSERT },
            enforceAmountNonNegative
                ? Nep17LifecycleAmountNonNegativeAssertion()
                : Array.Empty<byte>(),
            enforceAccountNonZero
                ? Nep17LifecycleAccountNonZeroAssertion()
                : Array.Empty<byte>(),
            Syscall("System.Storage.GetContext"),
            Pushdata1("totalSupply"u8.ToArray()),
            Syscall("System.Storage.Get"),
            StorageValueOrZeroToLocal(NeoVm.OpCode.STLOC0),
            Syscall("System.Storage.GetContext"),
            new[] { (byte)NeoVm.OpCode.LDARG0 },
