            Pushdata1("totalSupply"u8.ToArray()),
            new[] { (byte)NeoVm.OpCode.LDLOC0, (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.ADD },
            Syscall("System.Storage.Put"),
            updateAccountBalance
                ? Nep17MintAccountBalanceMutation()
                : Array.Empty<byte>(),
            emitTransferEvent
                ? Nep17MintTransferNotification()
                : Array.Empty<byte>(),
            new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.RET });

