    private static byte[] Nep11TransferBody(
        bool ownerWitness,
        bool correctEventPayload,
        bool updateOwnerStorage = true,
        bool mutateTotalSupply = false,
        bool updateOwnerBalances = true,
        bool guardTokenIdLength = true,
        bool updateTokensOfIndex = true,
        bool returnFalseOnMissingOwner = true) =>
        Concat(
            new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x03, (byte)0x03 },
            Nep11TransferBodyAfterInit(
                ownerWitness,
                correctEventPayload,
                updateOwnerStorage,
                mutateTotalSupply,
                updateOwnerBalances,
                guardTokenIdLength,
                updateTokensOfIndex,
                returnFalseOnMissingOwner));

    private static byte[] Nep11TransferBodyAfterInit(
        bool ownerWitness,
        bool correctEventPayload,
        bool updateOwnerStorage = true,
        bool mutateTotalSupply = false,
        bool updateOwnerBalances = true,
        bool guardTokenIdLength = true,
        bool updateTokensOfIndex = true,
        bool returnFalseOnMissingOwner = true) =>
        Concat(
            guardTokenIdLength
                ? Nep11TokenIdLengthGuard(NeoVm.OpCode.LDARG1, maxLength: updateTokensOfIndex ? 35 : 64)
                : Array.Empty<byte>(),
