            new[] { (byte)NeoVm.OpCode.LDARG1 },
            Syscall("System.Storage.Get"),
            new[] { (byte)NeoVm.OpCode.STLOC0 },
            Nep11RejectMissingOwnerLocal0(returnFalseOnMissingOwner),
