                    new[] { (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.LDARG0 },
                    Syscall("System.Storage.Put"))
                : Array.Empty<byte>(),
            updateOwnerBalances
                ? Nep11OwnerBalanceDeltaStorageMutation()
                : Nep11OwnerNonSelfAssertion(),
            updateTokensOfIndex
                ? Nep11TokensOfTransferIndexMutation()
                : Array.Empty<byte>(),
            mutateTotalSupply
                ? Nep11MutateTotalSupplyStorage()
                : Array.Empty<byte>(),
