                    (byte)NeoVm.OpCode.LDARG1,
                    (byte)NeoVm.OpCode.PUSH3,
                    (byte)NeoVm.OpCode.PACK,
                },
            Syscall("System.Contract.Call"),
            checkReturn
                ? new[] { (byte)NeoVm.OpCode.ASSERT }
                : Array.Empty<byte>());

    private static byte[] Nep17TransferConditionalCallbackFromGetContract()
    {
        byte[] callback = Nep17PaymentCallback(correctPayload: true, checkReturn: false);
        return Concat(
            Nep17BalanceDeltaStorageMutation(),
            Nep17TransferNotification(),
            ContractManagementGetContractNativeCall(NeoVm.OpCode.LDARG1),
            new[] { (byte)NeoVm.OpCode.ISNULL, (byte)NeoVm.OpCode.JMPIF, (byte)(callback.Length + 2) },
            callback,
            new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.RET });
    }

