    private static byte[] Nep11DivisibleMintSupplyBalanceMutation(
        bool emitTransferEvent,
        bool updateOwnerIndex = true,
        bool guardAmount = true,
        bool enforceAccountNonZero = true,
        bool updateOwnerBalance = true) =>
        Concat(
            new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x02, (byte)0x03 },
            Pushdata1(Enumerable.Range(0, 20).Select(i => (byte)(0xD0 + i)).ToArray()),
            Syscall("System.Runtime.CheckWitness"),
            new[] { (byte)NeoVm.OpCode.ASSERT },
            enforceAccountNonZero
                ? Nep11LifecycleAccountNonZeroAssertion()
                : Array.Empty<byte>(),
            guardAmount
                ? new[] { (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.GT, (byte)NeoVm.OpCode.ASSERT }
                : Array.Empty<byte>(),
            Nep11TokenIdLengthGuard(NeoVm.OpCode.LDARG2, maxLength: 35),
            Syscall("System.Storage.GetContext"),
            Pushdata1("totalSupply"u8.ToArray()),
            Syscall("System.Storage.Get"),
            StorageValueOrZeroToLocal(NeoVm.OpCode.STLOC0),
            Syscall("System.Storage.GetContext"),
            Nep11DivisibleBalanceKey(NeoVm.OpCode.LDARG0, NeoVm.OpCode.LDARG2),
            Syscall("System.Storage.Get"),
            StorageValueOrZeroToLocal1(),
            new[] { (byte)NeoVm.OpCode.LDLOC1, (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.GE, (byte)NeoVm.OpCode.ASSERT },
            new[] { (byte)NeoVm.OpCode.LDLOC1, (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.NUMEQUAL, (byte)NeoVm.OpCode.ASSERT },
            Syscall("System.Storage.GetContext"),
            Pushdata1("totalSupply"u8.ToArray()),
            new[] { (byte)NeoVm.OpCode.LDLOC0, (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.ADD },
            Syscall("System.Storage.Put"),
            updateOwnerBalance
                ? Concat(
                    Syscall("System.Storage.GetContext"),
                    Nep11DivisibleBalanceKey(NeoVm.OpCode.LDARG0, NeoVm.OpCode.LDARG2),
                    new[] { (byte)NeoVm.OpCode.LDLOC1, (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.ADD },
                    Syscall("System.Storage.Put"))
                : Array.Empty<byte>(),
            Nep11DivisibleMintEnumerationIndexMutation(),
            updateOwnerIndex
                ? Nep11DivisibleMintOwnerOfIndexMutation()
                : Array.Empty<byte>(),
            emitTransferEvent
                ? Nep11DivisibleMintTransferNotification()
                : Array.Empty<byte>(),
            new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.RET });

    private static byte[] Nep11DivisibleMintEnumerationIndexMutation() =>
        Concat(
            Syscall("System.Storage.GetContext"),
            Nep11TokensIndexKey(NeoVm.OpCode.LDARG2),
            new[] { (byte)NeoVm.OpCode.PUSH1 },
            Syscall("System.Storage.Put"),
            Syscall("System.Storage.GetContext"),
            Nep11TokensOfIndexKey(NeoVm.OpCode.LDARG0, NeoVm.OpCode.LDARG2),
            new[] { (byte)NeoVm.OpCode.PUSH1 },
            Syscall("System.Storage.Put"));

    private static byte[] Nep11DivisibleMintOwnerOfIndexMutation() =>
