    private static byte[] Nep11DivisibleBurnTransferNotification() =>
        Concat(
            Pushdata1("Transfer"u8.ToArray()),
            new[]
            {
                (byte)NeoVm.OpCode.LDARG2,
                (byte)NeoVm.OpCode.LDARG1,
                (byte)NeoVm.OpCode.PUSHNULL,
                (byte)NeoVm.OpCode.LDARG0,
                (byte)NeoVm.OpCode.PUSH4,
                (byte)NeoVm.OpCode.PACK,
            },
            Syscall("System.Runtime.Notify"));

    private static byte[] Nep11DivisibleTransferBody(
        bool guardAmount,
        bool updateBalances = false,
        bool assertNonSelf = false,
        bool wrongToDelta = false,
        bool mutateTotalSupply = false,
        bool guardTokenIdLength = true,
        bool guardAmountCap = true,
        bool updateOwnerIndex = true,
        bool returnFalseOnInsufficientBalance = true) =>
        Concat(
            new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x02, (byte)0x05 },
            new[] { (byte)NeoVm.OpCode.LDARG0 },
            Syscall("System.Runtime.CheckWitness"),
            new[] { (byte)NeoVm.OpCode.ASSERT },
            guardAmount
                ? new[] { (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.GE, (byte)NeoVm.OpCode.ASSERT }
                : Array.Empty<byte>(),
            guardAmountCap
                ? Nep11DivisibleAmountCapGuard()
                : Array.Empty<byte>(),
            guardTokenIdLength
                ? Nep11TokenIdLengthGuard(NeoVm.OpCode.LDARG3, maxLength: 35)
                : Array.Empty<byte>(),
            assertNonSelf
                ? new[] { (byte)NeoVm.OpCode.LDARG0, (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.EQUAL, (byte)NeoVm.OpCode.NOT, (byte)NeoVm.OpCode.ASSERT }
                : Array.Empty<byte>(),
            updateBalances
                ? Nep11DivisibleBalanceDeltaStorageMutation(wrongToDelta, returnFalseOnInsufficientBalance)
                : Array.Empty<byte>(),
            updateBalances && updateOwnerIndex
                ? Nep11DivisibleOwnerOfIndexMutation()
                : Array.Empty<byte>(),
            mutateTotalSupply
                ? Nep11MutateTotalSupplyStorage()
                : Array.Empty<byte>(),
            Nep11DivisibleTransferNotification(correctPayload: true),
            Nep11DivisiblePaymentCallback(correctPayload: true),
            new[] { (byte)NeoVm.OpCode.PUSH1, (byte)NeoVm.OpCode.RET });

    private static byte[] Nep11DivisibleAmountCapGuard() =>
        Concat(
            new[] { (byte)NeoVm.OpCode.LDARG2 },
            PushInt32(100_000_000),
            new[] { (byte)NeoVm.OpCode.LE, (byte)NeoVm.OpCode.ASSERT });

    private static byte[] PushInt32(int value) =>
        Concat(
            new[] { (byte)NeoVm.OpCode.PUSHINT32 },
            BitConverter.GetBytes(value));

    private static byte[] Nep11TokenIdLengthGuard(NeoVm.OpCode tokenIdArg, int maxLength = 64) =>
        new[]
        {
            (byte)tokenIdArg,
            (byte)NeoVm.OpCode.SIZE,
            (byte)NeoVm.OpCode.PUSHINT8,
            (byte)maxLength,
            (byte)NeoVm.OpCode.LE,
            (byte)NeoVm.OpCode.ASSERT,
        };

    private static byte[] Nep11DivisibleBalanceDeltaStorageMutation(
        bool wrongToDelta = false,
        bool returnFalseOnInsufficientBalance = true) =>
        Concat(
            Syscall("System.Storage.GetContext"),
            Nep11DivisibleBalanceKey(NeoVm.OpCode.LDARG0, NeoVm.OpCode.LDARG3),
            Syscall("System.Storage.Get"),
            new[] { (byte)NeoVm.OpCode.CONVERT, SymbolicEngine.StackItemTypeCodes.Integer, (byte)NeoVm.OpCode.STLOC0 },
            returnFalseOnInsufficientBalance
                ? new[] { (byte)NeoVm.OpCode.LDLOC0, (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.GE, (byte)NeoVm.OpCode.JMPIF, (byte)0x04, (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.RET }
                : new[] { (byte)NeoVm.OpCode.LDLOC0, (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.GE, (byte)NeoVm.OpCode.ASSERT },
            Syscall("System.Storage.GetContext"),
            Nep11DivisibleBalanceKey(NeoVm.OpCode.LDARG1, NeoVm.OpCode.LDARG3),
            Syscall("System.Storage.Get"),
            StorageValueOrZeroToLocal1(),
            Syscall("System.Storage.GetContext"),
            Nep11DivisibleBalanceKey(NeoVm.OpCode.LDARG0, NeoVm.OpCode.LDARG3),
            new[] { (byte)NeoVm.OpCode.LDLOC0, (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.SUB },
            Syscall("System.Storage.Put"),
            Syscall("System.Storage.GetContext"),
            Nep11DivisibleBalanceKey(NeoVm.OpCode.LDARG1, NeoVm.OpCode.LDARG3),
            new[] { (byte)NeoVm.OpCode.LDLOC1, (byte)NeoVm.OpCode.LDARG2, (byte)(wrongToDelta ? NeoVm.OpCode.SUB : NeoVm.OpCode.ADD) },
            Syscall("System.Storage.Put"));

    private static byte[] Nep11DivisibleMixedInsufficientBalanceFalseAndTrueReturn() =>
        Concat(
            new[] { (byte)NeoVm.OpCode.INITSLOT, (byte)0x02, (byte)0x05 },
            new[] { (byte)NeoVm.OpCode.LDARG0 },
            Syscall("System.Runtime.CheckWitness"),
            new[] { (byte)NeoVm.OpCode.ASSERT },
            new[] { (byte)NeoVm.OpCode.LDARG2, (byte)NeoVm.OpCode.PUSH0, (byte)NeoVm.OpCode.GE, (byte)NeoVm.OpCode.ASSERT },
            Nep11TokenIdLengthGuard(NeoVm.OpCode.LDARG3, maxLength: 35),
            new[] { (byte)NeoVm.OpCode.LDARG0, (byte)NeoVm.OpCode.LDARG1, (byte)NeoVm.OpCode.EQUAL, (byte)NeoVm.OpCode.NOT, (byte)NeoVm.OpCode.ASSERT },
            Syscall("System.Storage.GetContext"),
            Nep11DivisibleBalanceKey(NeoVm.OpCode.LDARG0, NeoVm.OpCode.LDARG3),
            Syscall("System.Storage.Get"),
            new[] { (byte)NeoVm.OpCode.CONVERT, SymbolicEngine.StackItemTypeCodes.Integer, (byte)NeoVm.OpCode.STLOC0 },
            IfConditionThen(
                new[]
                {
                    (byte)NeoVm.OpCode.LDLOC0,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LT,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.PUSH1,
                    (byte)NeoVm.OpCode.NUMEQUAL,
                    (byte)NeoVm.OpCode.BOOLAND,
                },
                ReturnBool(false)),
            IfConditionThen(
                new[]
                {
                    (byte)NeoVm.OpCode.LDLOC0,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LT,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.PUSH1,
                    (byte)NeoVm.OpCode.NUMEQUAL,
                    (byte)NeoVm.OpCode.NOT,
                    (byte)NeoVm.OpCode.BOOLAND,
                },
                ReturnBool(true)),
            ReturnBool(true));

    private static byte[] Nep11DivisibleBalanceKey(NeoVm.OpCode accountArg, NeoVm.OpCode tokenIdArg) =>
        Concat(
            Pushdata1("balance:"u8.ToArray()),
            new[] { (byte)accountArg, (byte)NeoVm.OpCode.CAT },
            Pushdata1(":"u8.ToArray()),
            new[] { (byte)NeoVm.OpCode.CAT, (byte)tokenIdArg, (byte)NeoVm.OpCode.CAT });

    private static byte[] Nep11DivisibleOwnerOfIndexMutation()
    {
        byte[] deleteSenderIndex = Concat(
            Syscall("System.Storage.GetContext"),
            Nep11DivisibleOwnerIndexKey(NeoVm.OpCode.LDARG3, NeoVm.OpCode.LDARG0),
            Syscall("System.Storage.Delete"));
        byte[] putRecipientIndex = Concat(
            Syscall("System.Storage.GetContext"),
            Nep11DivisibleOwnerIndexKey(NeoVm.OpCode.LDARG3, NeoVm.OpCode.LDARG1),
            new[] { (byte)NeoVm.OpCode.PUSH1 },
            Syscall("System.Storage.Put"));

        return Concat(
            IfConditionThen(
                new[]
                {
                    (byte)NeoVm.OpCode.LDLOC0,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.SUB,
                    (byte)NeoVm.OpCode.PUSH0,
                    (byte)NeoVm.OpCode.EQUAL,
                },
                deleteSenderIndex),
            IfConditionThen(
                new[]
                {
                    (byte)NeoVm.OpCode.LDLOC1,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.ADD,
                    (byte)NeoVm.OpCode.PUSH0,
                    (byte)NeoVm.OpCode.GT,
                },
                putRecipientIndex));
    }

    private static byte[] Nep11DivisibleOwnerIndexKey(NeoVm.OpCode tokenIdArg, NeoVm.OpCode ownerArg) =>
        Concat(
            Pushdata1("owners:"u8.ToArray()),
            new[]
            {
                (byte)tokenIdArg,
                (byte)NeoVm.OpCode.CONVERT,
                SymbolicEngine.StackItemTypeCodes.ByteString,
                (byte)NeoVm.OpCode.CAT,
            },
            Pushdata1(":"u8.ToArray()),
            new[] { (byte)NeoVm.OpCode.CAT, (byte)ownerArg, (byte)NeoVm.OpCode.CAT });

    private static byte[] IfConditionThen(byte[] condition, byte[] body)
    {
        if (body.Length + 2 > sbyte.MaxValue)
            throw new InvalidOperationException("short conditional jump body is too large for the test bytecode builder");

        return Concat(
            condition,
            new[]
            {
                (byte)NeoVm.OpCode.NOT,
                (byte)NeoVm.OpCode.JMPIF,
                (byte)(body.Length + 2),
            },
            body);
    }

    private static byte[] Nep11DivisibleTransferNotification(bool correctPayload) =>
        Concat(
            Pushdata1("Transfer"u8.ToArray()),
            correctPayload
                ? new[]
                {
                    (byte)NeoVm.OpCode.LDARG3,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LDARG1,
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.PUSH4,
                    (byte)NeoVm.OpCode.PACK,
                }
                : new[]
                {
                    (byte)NeoVm.OpCode.LDARG3,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.LDARG1,
                    (byte)NeoVm.OpCode.PUSH4,
                    (byte)NeoVm.OpCode.PACK,
                },
            Syscall("System.Runtime.Notify"));

    private static byte[] Nep11DivisiblePaymentCallback(bool correctPayload, bool checkReturn = true) =>
        Concat(
            new[] { (byte)NeoVm.OpCode.LDARG1 },
            Pushdata1("onNEP11Payment"u8.ToArray()),
            new[] { (byte)NeoVm.OpCode.PUSH15 },
            correctPayload
                ? new[]
                {
                    (byte)NeoVm.OpCode.LDARG4,
                    (byte)NeoVm.OpCode.LDARG3,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LDARG0,
                    (byte)NeoVm.OpCode.PUSH4,
                    (byte)NeoVm.OpCode.PACK,
                }
                : new[]
                {
                    (byte)NeoVm.OpCode.LDARG4,
                    (byte)NeoVm.OpCode.LDARG3,
                    (byte)NeoVm.OpCode.LDARG2,
                    (byte)NeoVm.OpCode.LDARG1,
                    (byte)NeoVm.OpCode.PUSH4,
                    (byte)NeoVm.OpCode.PACK,
                },
            Syscall("System.Contract.Call"),
            checkReturn
                ? new[] { (byte)NeoVm.OpCode.ASSERT }
                : Array.Empty<byte>());

    private static byte[] CompleteNep17Script(
        byte[] transferBody,
        out int symbolOffset,
        out int decimalsOffset,
        out int totalSupplyOffset,
        out int balanceOfOffset,
        byte[]? balanceOfBody = null,
        byte[]? totalSupplyBody = null,
        byte[]? decimalsBody = null,
        byte[]? symbolBody = null)
    {
        byte[] symbol = symbolBody ?? Concat(Pushdata1("TKN"u8.ToArray()), new[] { (byte)NeoVm.OpCode.RET });
        byte[] decimals = decimalsBody ?? new[] { (byte)NeoVm.OpCode.PUSH8, (byte)NeoVm.OpCode.RET };
        byte[] totalSupply = totalSupplyBody ?? TotalSupplyStorageRead();
        byte[] balanceOf = balanceOfBody ?? Nep17BalanceOfDirectStorageRead();
        byte[] transfer = NormalizeBooleanReturnInstructions(transferBody);

        symbolOffset = transfer.Length;
        decimalsOffset = symbolOffset + symbol.Length;
        totalSupplyOffset = decimalsOffset + decimals.Length;
        balanceOfOffset = totalSupplyOffset + totalSupply.Length;
        return Concat(transfer, symbol, decimals, totalSupply, balanceOf);
    }

