    private static byte[] ConditionalSymbolReturnScript(string first, string second)
    {
        byte[] firstReturn = Concat(
            Pushdata1(System.Text.Encoding.ASCII.GetBytes(first)),
            new[] { (byte)NeoVm.OpCode.RET });
        byte[] secondReturn = Concat(
            Pushdata1(System.Text.Encoding.ASCII.GetBytes(second)),
            new[] { (byte)NeoVm.OpCode.RET });

        return Concat(
            Syscall("System.Storage.GetContext"),
            Pushdata1("symbolFlag"u8.ToArray()),
            Syscall("System.Storage.Get"),
            new[] { (byte)NeoVm.OpCode.JMPIF, (byte)(firstReturn.Length + 2) },
            firstReturn,
            secondReturn);
    }

