    private static byte[] SyscallBytes(string name)
    {
        uint hash = SyscallRegistry.ComputeHash(name);
        return BitConverter.GetBytes(hash);
    }

    private static byte[] Syscall(string name)
    {
        var hash = SyscallBytes(name);
        return new[] { (byte)NeoVm.OpCode.SYSCALL, hash[0], hash[1], hash[2], hash[3] };
    }

    private static byte[] Pushdata1(byte[] data)
    {
        byte[] result = new byte[data.Length + 2];
        result[0] = (byte)NeoVm.OpCode.PUSHDATA1;
        result[1] = (byte)data.Length;
        Array.Copy(data, 0, result, 2, data.Length);
        return result;
    }

    private static byte[] Pushdata4(byte[] data)
    {
        byte[] result = new byte[data.Length + 5];
        byte[] length = BitConverter.GetBytes(data.Length);
        result[0] = (byte)NeoVm.OpCode.PUSHDATA4;
        Array.Copy(length, 0, result, 1, length.Length);
        Array.Copy(data, 0, result, 5, data.Length);
        return result;
    }

