            },
            Syscall("System.Iterator.Value"),
            afterValue);

    private static byte[] MalformedCompressedPublicKey()
    {
        byte[] bytes = Enumerable.Repeat((byte)0xff, 33).ToArray();
        bytes[0] = 0x02;
        return bytes;
    }

    private static byte[] Concat(params byte[][] parts)
    {
        int len = parts.Sum(p => p.Length);
        byte[] result = new byte[len];
        int o = 0;
        foreach (var part in parts)
        {
            Array.Copy(part, 0, result, o, part.Length);
            o += part.Length;
        }
        return result;
    }

    private static string HashDescriptor(byte[] hash) =>
        "0x" + Convert.ToHexString(hash).ToLowerInvariant();

    private static string Sha256File(string path) =>
        Convert.ToHexString(System.Security.Cryptography.SHA256.HashData(File.ReadAllBytes(path))).ToLowerInvariant();

    private static byte[] ScriptHash(byte[] script)
    {
        byte[] sha256 = System.Security.Cryptography.SHA256.HashData(script);
        var digest = new Org.BouncyCastle.Crypto.Digests.RipeMD160Digest();
        digest.BlockUpdate(sha256, 0, sha256.Length);
        byte[] result = new byte[digest.GetDigestSize()];
        digest.DoFinal(result, 0);
        return result;
    }

