    private static void WriteNefScript(string path, byte[] script) =>
        File.WriteAllBytes(path, BuildNef("dotnet", "", Array.Empty<MethodToken>(), script));

    private static byte[] BuildNef(string compiler, string source, MethodToken[] tokens, byte[] script)
    {
        using var ms = new MemoryStream();
        using (var writer = new BinaryWriter(ms, System.Text.Encoding.ASCII, leaveOpen: true))
        {
            writer.Write(NefFile.MagicValue);
            var compilerBytes = new byte[64];
            byte[] compilerString = System.Text.Encoding.ASCII.GetBytes(compiler);
            Array.Copy(compilerString, compilerBytes, Math.Min(compilerString.Length, compilerBytes.Length));
            writer.Write(compilerBytes);
            WriteVarBytes(writer, System.Text.Encoding.ASCII.GetBytes(source));
            writer.Write((byte)0);
            WriteVarInt(writer, (ulong)tokens.Length);
            foreach (var token in tokens)
                WriteToken(writer, token);
            writer.Write((ushort)0);
            WriteVarBytes(writer, script);
        }

        byte[] prefix = ms.ToArray();
        uint checksum = NefFile.ComputeChecksum(prefix);
        byte[] full = new byte[prefix.Length + 4];
        Array.Copy(prefix, full, prefix.Length);
        System.Buffers.Binary.BinaryPrimitives.WriteUInt32LittleEndian(full.AsSpan(prefix.Length), checksum);
        return full;
    }

    private static byte[] BuildNefWithRawMethodTokenFields(
        string compiler,
        string source,
        byte[] hash,
        string method,
        ushort parametersCount,
        byte hasReturnValue,
        byte callFlags,
        byte[] script)
    {
        using var ms = new MemoryStream();
        using (var writer = new BinaryWriter(ms, System.Text.Encoding.ASCII, leaveOpen: true))
        {
            writer.Write(NefFile.MagicValue);
            var compilerBytes = new byte[64];
            byte[] compilerString = System.Text.Encoding.ASCII.GetBytes(compiler);
            Array.Copy(compilerString, compilerBytes, Math.Min(compilerString.Length, compilerBytes.Length));
            writer.Write(compilerBytes);
            WriteVarBytes(writer, System.Text.Encoding.ASCII.GetBytes(source));
            writer.Write((byte)0);
            WriteVarInt(writer, 1);
            writer.Write(hash);
            byte[] nameBytes = System.Text.Encoding.UTF8.GetBytes(method);
            WriteVarInt(writer, (ulong)nameBytes.Length);
            writer.Write(nameBytes);
            writer.Write(parametersCount);
            writer.Write(hasReturnValue);
            writer.Write(callFlags);
            writer.Write((ushort)0);
            WriteVarBytes(writer, script);
        }

        byte[] prefix = ms.ToArray();
        uint checksum = NefFile.ComputeChecksum(prefix);
        byte[] full = new byte[prefix.Length + 4];
        Array.Copy(prefix, full, prefix.Length);
        System.Buffers.Binary.BinaryPrimitives.WriteUInt32LittleEndian(full.AsSpan(prefix.Length), checksum);
        return full;
    }

    private static (string PublicKeyHex, string SignatureBase64) CreateManifestGroupSignature(byte[] contractHash)
    {
        using var ecdsa = ECDsa.Create(ECCurve.NamedCurves.nistP256);
        ECParameters parameters = ecdsa.ExportParameters(includePrivateParameters: false);
        byte[] x = FixedWidth(parameters.Q.X, 32);
        byte[] y = FixedWidth(parameters.Q.Y, 32);
        byte[] publicKey = new byte[33];
        publicKey[0] = (byte)((y[^1] & 1) == 0 ? 0x02 : 0x03);
        Array.Copy(x, 0, publicKey, 1, x.Length);
        byte[] signature = ecdsa.SignData(
            contractHash,
            HashAlgorithmName.SHA256,
            DSASignatureFormat.IeeeP1363FixedFieldConcatenation);
        return (Convert.ToHexString(publicKey), Convert.ToBase64String(signature));
    }

    private static byte[] FixedWidth(byte[]? bytes, int width)
    {
        bytes.Should().NotBeNull();
        bytes!.Length.Should().BeLessThanOrEqualTo(width);
        if (bytes.Length == width)
            return bytes;

        byte[] padded = new byte[width];
        Array.Copy(bytes, 0, padded, width - bytes.Length, bytes.Length);
        return padded;
    }

    private static void WriteVarBytes(BinaryWriter writer, byte[] bytes)
    {
        WriteVarInt(writer, (ulong)bytes.Length);
        writer.Write(bytes);
    }

    private static void WriteVarInt(BinaryWriter writer, ulong value)
    {
        if (value < 0xFD)
        {
            writer.Write((byte)value);
        }
        else if (value <= 0xFFFF)
        {
            writer.Write((byte)0xFD);
            writer.Write((ushort)value);
        }
        else if (value <= 0xFFFFFFFF)
        {
            writer.Write((byte)0xFE);
            writer.Write((uint)value);
        }
        else
        {
            writer.Write((byte)0xFF);
            writer.Write(value);
        }
    }

    private static void WriteToken(BinaryWriter writer, MethodToken token)
    {
        writer.Write(token.Hash);
        byte[] nameBytes = System.Text.Encoding.UTF8.GetBytes(token.Method);
        WriteVarInt(writer, (ulong)nameBytes.Length);
        writer.Write(nameBytes);
        writer.Write(token.ParametersCount);
        writer.Write((byte)(token.HasReturnValue ? 1 : 0));
        writer.Write(token.CallFlags);
    }

    private static string CreateTempDirectory()
    {
        string dir = Path.Combine(Path.GetTempPath(), "neo-sym-verify-tests", Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(dir);
        return dir;
    }

    private static void CreateHardLink(string targetPath, string linkPath)
    {
        using var process = Process.Start(new ProcessStartInfo("ln")
        {
            RedirectStandardError = true,
            RedirectStandardOutput = true,
            UseShellExecute = false,
            ArgumentList =
            {
                targetPath,
                linkPath,
            },
        });
        process.Should().NotBeNull("the platform should provide ln for non-Windows hard-link tests");
        process!.WaitForExit();
        process.ExitCode.Should().Be(0, process.StandardError.ReadToEnd());
    }

    private static IDisposable WithEnvironmentVariable(string variable, string? value)
    {
        string? previous = Environment.GetEnvironmentVariable(variable);
        Environment.SetEnvironmentVariable(variable, value);
        return new RestoreEnvironmentVariable(variable, previous);
    }

    private sealed class RestoreEnvironmentVariable(string variable, string? previous) : IDisposable
    {
        public void Dispose() => Environment.SetEnvironmentVariable(variable, previous);
    }

    private sealed class FixedSmtBackend : ISmtBackend
    {
        private readonly SmtOutcome _outcome;

        public FixedSmtBackend(SmtOutcome outcome)
        {
            _outcome = outcome;
        }

        public bool IsAvailable => true;
        public string Version => "fixed-test";
        public int TimeoutMs => 1;

        public SmtOutcome IsSatisfiable(IReadOnlyList<Expression> conditions, Expression extra) =>
            _outcome;

        public SmtOutcome IsSatisfiable(IReadOnlyList<Expression> conditions) =>
            _outcome;

        public IReadOnlyDictionary<string, object>? BuildWitness(IReadOnlyList<Expression> conditions) =>
            null;

        public BigInteger? ConcretizeInt(
            IReadOnlyList<Expression> conditions,
            Expression target,
            BigInteger? lo = null,
            BigInteger? hi = null) => null;

        public SmtStats GetStats() => new(
            Queries: 0,
            CacheHits: 0,
            Unknowns: _outcome == SmtOutcome.Unknown ? 1 : 0,
            Timeouts: 0,
            Sat: _outcome == SmtOutcome.Sat ? 1 : 0,
            Unsat: _outcome == SmtOutcome.Unsat ? 1 : 0);
    }
}
